############ prepare GLORI m6A sites as positive for benchmark ############################
dt.GLORI.sample <- fread("/data/m6A_calling_strategy/Benchmark_m6As/GLORI/GLORI_sample_depth_info.txt")
colnames(dt.GLORI.sample) <- colnames(dt.GLORI.sample) %>% str_replace_all(pattern = " ",replacement = "")
dt.GLORI.sample <- dt.GLORI.sample %>% dplyr::select(Run,AssayType,AvgSpotLen,Bases,cell_line,cell_type,genotype,LibraryName,source_name,treatment)
dt.GLORI.sampleID <- fread("/data/m6A_calling_strategy/Benchmark_m6As/GLORI/GLORI_GSE210563_sampleID.txt",header = F)
dt.GLORI.sample <- dt.GLORI.sample %>% left_join(x=.,y=dt.GLORI.sampleID %>% dplyr::rename(SampleName=V2),by=c("LibraryName"="V1"))
#HEK293T
dt.GLORI.HEK293 <- dt.GLORI.sample %>% filter(str_detect(cell_line,pattern="HEK293") & treatment=="GLORI+")
GLORI.HEK293.Tarkara.SmallRNA <- foreach(i = 1:nrow(dt.GLORI.HEK293),.combine='rbind')%do%{
  file.path <- list.files("/data/m6A_calling_strategy/Benchmark_m6As/GLORI/GSE210563_RAW/",pattern=dt.GLORI.HEK293[i,LibraryName],full.names = T)
  dt.sites <- fread(file = file.path) %>% dplyr::select(seqnames=Chr,start=Sites,end=Sites,strand=Strand,score=Ratio) %>% mutate(name=paste(seqnames,start,end,strand,sep="_")) %>%
    dplyr::select(seqnames,start,end,name,score,strand) %>% mutate(Sample=dt.GLORI.HEK293[i,SampleName], Platform="GLORI") %>%
    mutate(Library=ifelse(str_detect(Sample,"Takara"), "Takara", "SmallRNA"))
  dt.sites
}

GLORI.HEK293.eCLIP.sample <- list.files("/data/m6A_calling_strategy/Benchmark_m6As/GLORI/GSE233875_RAW/",pattern = "GLORI") %>%
  strsplit(split="_",fixed=T) %>% sapply("[",2) %>% strsplit(split=".",fixed=T) %>% sapply("[",1)
GLORI.HEK293.eCLIP <- foreach(i = GLORI.HEK293.eCLIP.sample,.combine = 'rbind')%do%{
  file.path <- list.files("/data/m6A_calling_strategy/Benchmark_m6As/GLORI/GSE233875_RAW/",pattern = i,full.names = T)
  dt.sites <- fread(file = file.path) %>% dplyr::select(seqnames=Chr,start=Sites,end=Sites,strand=Strand,score=Ratio) %>% mutate(name=paste(seqnames,start,end,strand,sep="_")) %>%
    dplyr::select(seqnames,start,end,name,score,strand) %>% mutate(Sample=i, Platform="GLORI",Library="eCLIP")
  dt.sites
}
GLORI.HEK293 <- rbind(GLORI.HEK293.Tarkara.SmallRNA,GLORI.HEK293.eCLIP)

GLORI.HEK293 <- GLORI.HEK293 %>% mutate(SampleName=paste0("HEK293_",Platform,"_",Library,"_",ifelse(str_detect(Sample,"IVT"),"IVT","mRNA"),Sample %>% strsplit(split="rep",fixed=T) %>% sapply(tail, 1)))
