ggVennDiagram(GLORI.HEK293.list,force_upset = T,label_size = 2)

dt.GLORI.HEK293.consistent <- GLORI.HEK293 %>% group_by(name) %>% mutate(no.mRNA=n_distinct(SampleName[!str_detect(SampleName,"IVT")]),
                                                                            no.IVT=n_distinct(SampleName[str_detect(SampleName,"IVT")]),
                                                                            no.Total=n_distinct(SampleName)) %>%
  as.data.table() %>% dplyr::select(name,contains("no.")) %>% distinct()
attr(dt.GLORI.HEK293.consistent,"groups") <- NULL
dt.GLORI.HEK293.consistent <- dt.GLORI.HEK293.consistent %>% filter(no.mRNA>=2 & no.IVT==0)
dt.GLORI.HEK293.consistent <- GLORI.HEK293 %>% inner_join(x=.,y=dt.GLORI.HEK293.consistent %>% dplyr::select(-no.Total),by=c("name"))
dt.GLORI.HEK293.consistent <- dt.GLORI.HEK293.consistent %>% group_by(name) %>% mutate(score=mean(score),SampleName.Collapsed=paste(SampleName,collapse = ",")) %>%
  as.data.table() %>% dplyr::select(seqnames,start,end,name,score,strand,no.mRNA,no.IVT,SampleName.Collapsed) %>% distinct()
attr(dt.GLORI.HEK293.consistent,"groups") <- NULL

