  GLORI.HEK293.perturbation[Sample==i,name]
}
names(GLORI.HEK293.perturbation.list) <- unique(GLORI.HEK293.perturbation$Sample)

ggVennDiagram(GLORI.HEK293.perturbation.list,force_upset = T,label_size = 2)

GLORI.HEK293.perturbation <- GLORI.HEK293.perturbation %>% mutate(SampleName=paste0("HEK293_GLORI_",ifelse(str_detect(Sample,"FTO"),"FTO","METTL3i"),
                                                                                  Sample %>% strsplit(split="rep",fixed=T) %>% sapply("[",2))) %>%
  mutate(Perturbation=ifelse(str_detect(SampleName,"FTO"),"FTO","METTL3i"))
dt.GLORI.HEK293.confident <- dt.GLORI.HEK293.consistent %>% dplyr::select(-SampleName.Collapsed) %>%
  inner_join(x=.,y=GLORI.HEK293.perturbation %>% dplyr::select(name,score.perturbation=score,SampleName.perturbation=SampleName,Perturbation),by="name")
dt.GLORI.HEK293.confident <- dt.GLORI.HEK293.confident %>% dplyr::arrange(name,score.perturbation) %>% group_by(name,Perturbation) %>%
  mutate(PerturbEffect=mean(score.perturbation)-score) %>% as.data.table()
dt.GLORI.HEK293.confident <- dt.GLORI.HEK293.confident %>% dplyr::select(seqnames,start,end,name,score,strand,no.mRNA,no.IVT,Perturbation,PerturbEffect) %>% distinct() %>%
  mutate(PerturbEffect=round(PerturbEffect,3)) %>%
  pivot_wider(names_from = "Perturbation",values_from = "PerturbEffect",names_prefix = "PerturbEffect.") %>% as.data.table()
dt.GLORI.HEK293.confident %>% filter(PerturbEffect.FTO <= -0.1 | PerturbEffect.METTL3i <= -0.1)#53k m6As display at least 10% demethylation under FTO+ or METTL3i
dt.GLORI.HEK293.confident %>% filter(PerturbEffect.FTO <= -0.5 | PerturbEffect.METTL3i <= -0.5)#22k m6As display at least 50% demethylation under FTO+ or METTL3i
dt.GLORI.HEK293.confident <- dt.GLORI.HEK293.confident %>% filter(PerturbEffect.FTO <= -0.1 | PerturbEffect.METTL3i <= -0.1) %>%
  mutate(Confidence=case_when(PerturbEffect.FTO <= -0.5 & PerturbEffect.METTL3i <= -0.5 ~ "high",
                              PerturbEffect.FTO <= -0.1 & PerturbEffect.METTL3i <= -0.1 ~ "medium", .default = "low") %>% factor(levels=c("low","medium","high")))
dt.GLORI.HEK293.confident[,.N,keyby=.(Confidence)]
