dt.GLORI.HEK293.confident %>% group_by(Confidence) %>% summarise(quantile=c("q0.25","q0.5","q0.75"),PerturbEffect.FTO=quantile(PerturbEffect.FTO, c(0.25,0.5,0.75),na.rm=T),
