#mESC
eTAM.sample <- data.table(FilePath=list.files("/data/m6A_calling_strategy/Benchmark_m6As/eTAMseq/",full.names = T,pattern="hits.txt")) %>%
  mutate(Sample=list.files("/data/m6A_calling_strategy/Benchmark_m6As/eTAMseq/",full.names = F,pattern="hits.txt") %>% str_replace(pattern=".hits.txt",replacement="") %>% str_replace(pattern="GSE211303_",replacement="")) %>%
  mutate(Control=if_else(str_detect(Sample,"ivt"), "IVT", "FTO"), Cell=dplyr::case_when(str_detect(Sample,"mesc") ~ "mESC", str_detect(Sample,"hela") ~ "HeLa"))
eTAM.sample.mESC <- eTAM.sample %>% filter(Cell=="mESC" & !str_detect(Sample,fixed("m3cko."))) %>%
  mutate(Replicate = paste0(ifelse(str_detect(Sample,"m3cko"),"eTAM_mESC_m3ckoctrl_rep","eTAM_mESC_rep"),Sample %>% strsplit(split="rep",fixed=T) %>% sapply("[",2)))
eTAM.mESC <- foreach(i = 1:nrow(eTAM.sample.mESC),.combine = 'rbind')%do%{
  dt.sites <- fread(file = eTAM.sample.mESC[i,FilePath]) %>% mutate(seqnames=pos %>% strsplit(split="_",fixed=T) %>% sapply("[",1),
                                                                    start=pos %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                                                                    end=pos %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                                                                    score=methylation/100,
                                                                    strand=pos %>% strsplit(split="_",fixed=T) %>% sapply("[",3),
                                                                    Sample=eTAM.sample.mESC[i,Sample]) %>%
    mutate(name=paste(seqnames,start,end,strand,sep="_")) %>% dplyr::select(seqnames,start,end,name,score,strand,Sample)
  dt.sites
}
eTAM.mESC <- eTAM.mESC %>% left_join(x=.,y=eTAM.sample.mESC %>% dplyr::select(-FilePath),by=c("Sample"))
eTAM.mESC[,.N,keyby =.(Replicate,Control)]
