#mESC under writer/eraser perturbation (METTL3 cko)
eTAM.sample.mESC.perturbation <- eTAM.sample %>% filter(Cell=="mESC" & str_detect(Sample,fixed("m3cko."))) %>%
  mutate(Replicate = paste0("eTAM_mESC_Mettl3cko_rep",Sample %>% strsplit(split="rep",fixed=T) %>% sapply("[",2)))
eTAM.mESC.perturbation <- foreach(i = 1:nrow(eTAM.sample.mESC.perturbation),.combine = 'rbind')%do%{
  dt.sites <- fread(file = eTAM.sample.mESC[i,FilePath]) %>% mutate(seqnames=pos %>% strsplit(split="_",fixed=T) %>% sapply("[",1),
                                                                    start=pos %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                                                                    end=pos %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                                                                    score=methylation/100,
                                                                    strand=pos %>% strsplit(split="_",fixed=T) %>% sapply("[",3),
                                                                    Sample=eTAM.sample.mESC.perturbation[i,Sample]) %>%
    mutate(name=paste(seqnames,start,end,strand,sep="_")) %>% dplyr::select(seqnames,start,end,name,score,strand,Sample)
  dt.sites
}
eTAM.mESC.perturbation <- eTAM.mESC.perturbation %>% left_join(x=.,y=eTAM.sample %>% dplyr::select(-FilePath),by=c("Sample"))
dt.eTAM.mESC.confident <- dt.eTAM.mESC.consistent %>% left_join(x=.,y=eTAM.mESC.perturbation %>% dplyr::select(name,score.Mettl3cko=score),by=c("name")) %>%
  mutate(PerturbEffect=score.Mettl3cko-score) %>% filter(nRep>1 | PerturbEffect <= -0.1) %>%
  mutate(confidence =  dplyr::case_when(nRep>1 & PerturbEffect <= -0.5 ~ "high",
                                        nRep >1 & PerturbEffect <= -0.1 ~ "medium", .default = "low") %>% factor(levels=c("low","medium","high"))) %>%
  dplyr::arrange(name)
dt.eTAM.mESC.confident[,.N,keyby=.(confidence)]
