#lifover from mm10 to mm39
#liftover mm10 to mm39
m6A_liftover <- function(
    chainfile="~/genome_db/LiftOverChain/mm10ToMm39.over.chain",
    input.bed=m6A.site.list$mESC_GLORI1
){
  chain <- rtracklayer::import.chain(chainfile)
  input.GR <- GenomicRanges::makeGRangesFromDataFrame(input.bed,keep.extra.columns = T)
  as.data.table(unlist(rtracklayer::liftOver(input.GR, chain))) %>% dplyr::select(seqnames,start,end,name,score,strand)
}
#lift over mESC m6A sites
dt.eTAM.mESC.consistent <- m6A_liftover(chainfile="~/genome_db/LiftOverChain/mm10ToMm39.over.chain", input.bed=dt.eTAM.mESC.consistent) %>%
  mutate(Platform="eTAM") %>% inner_join(x=.,y=dt.eTAM.mESC.consistent %>% dplyr::select(name,Cell,nRep),by=c("name")) %>%  mutate(name=paste(seqnames,start,end,strand))
dt.eTAM.mESC.confident <- m6A_liftover(chainfile="~/genome_db/LiftOverChain/mm10ToMm39.over.chain", input.bed=dt.eTAM.mESC.confident) %>%
  mutate(Platform="eTAM") %>% inner_join(x=.,y=dt.eTAM.mESC.confident %>% dplyr::select(name,Cell,nRep,PerturbEffect,confidence),by=c("name")) %>%  mutate(name=paste(seqnames,start,end,strand))

saveRDS(dt.eTAM.mESC.consistent,file="/data/m6A_calling_strategy/Benchmark_m6As/eTAMseq/dt.eTAMseq.mESC.consistent.m6As.RDS")
saveRDS(dt.eTAM.mESC.confident,file="/data/m6A_calling_strategy/Benchmark_m6As/eTAMseq/dt.eTAMseq.mESC.confident.m6As.RDS")

