#obtain the benchmark m6a modified genes
dt.HEK293.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.HEK293.benchmark.m6As.RDS")
dt.HEK293.benchmark.m6As.withoverlapped.gene <- foreach(b = unique(dt.HEK293.benchmark.m6As$Sample), .combine='rbind')%do%{
  dt.overlap <- bt.intersect(a=dt.HEK293.benchmark.m6As %>% dplyr::filter(Sample==b),
               b=fread("/data/m6A_calling_strategy/RIPPeakS_resource/hg38_gencode.gene.bed"),
               s=T, f=0.5, F=0.8, e = T, wo=T) %>% as.data.table()
  dt.benchmark.m6a <- dt.overlap %>% group_by(name=V4) %>% mutate(nGene=n_distinct(V12), Gene.list=paste0(V12,collapse = "|")) %>% as.data.table() %>%
    distinct(name,nGene,Gene.list) %>%
    right_join(x=.,y=dt.HEK293.benchmark.m6As %>% dplyr::filter(Sample==b),by=c("name")) %>% mutate(nGene=case_when(is.na(nGene) ~ 0, .default = nGene))
  dt.benchmark.m6a %>% dplyr::filter(nGene<=2) %>% dplyr::select(seqnames,start,end,name,score,strand,Sample,everything())
}
saveRDS(dt.HEK293.benchmark.m6As.withoverlapped.gene, file="/data/m6A_calling_strategy/Benchmark_m6As/dt.HEK293.benchmark.m6As.overlapped.gene.RDS")
for(b in unique(dt.HEK293.benchmark.m6As.withoverlapped.gene$Sample)){
  fwrite(dt.HEK293.benchmark.m6As.withoverlapped.gene %>% dplyr::filter(Sample==b),
         file=paste0("/data/m6A_calling_strategy/RIPPeakS_resource/dt.benchmark.",b,".m6As.bed"),row.names=F,col.names = F,sep="\t")
}

