############### prepare m6As from MACS2 with alternative parameters ############
dt.parameter.combo.MACS2 <- foreach(pvalue=c(NA,1,0.05,0.01,0.001),.combine='rbind')%do%{#default is NA
  foreach(qvalue=c(1,0.05,0.01,0.001), .combine='rbind')%do%{#default is 5e-2
    foreach(nomodel=c(TRUE,FALSE), .combine='rbind')%do%{#default is FALSE
      foreach(nolambda=c(TRUE,FALSE),.combine='rbind')%do%{#default is FALSE
        foreach(mfold=c("-m 5 50", "-m 2 50"), .combine='rbind')%do%{#default is -m 5 50
          data.table(pvalue_cutoff=pvalue, qvalue_cutoff=qvalue, nomodel=nomodel, nolambda=nolambda, mfold=mfold)
        }
      }
    }
  }
} %>% filter(!(!is.na(pvalue_cutoff) & qvalue_cutoff != 1)) %>% mutate(ComboName=paste0("Combo",1:nrow(.)), Method="MACS2")

dt.MACS2.m6As <- foreach(pc = 1:nrow(dt.parameter.combo.MACS2),.combine = 'rbind')%do%{
  message(paste0("start load ", dt.parameter.combo.MACS2$ComboName[pc]))
  Samples <- list.files(path=paste0("/data/m6A_calling_strategy/MACS2/",dt.parameter.combo.MACS2$ComboName[pc]), pattern="peaks.xls",full.names = F) %>%
    str_replace(pattern="_peaks.xls",replacement = "")
  m6As <- list.files(path=paste0("/data/m6A_calling_strategy/MACS2/",dt.parameter.combo.MACS2$ComboName[pc]), pattern="peaks.xls",full.names = T)
  names(m6As) <- Samples
  foreach(i = 1:length(m6As),.combine='rbind')%do%{
    fread(file = m6As[i]) %>% dplyr::select(seqnames=chr,start,end,name,score=fold_enrichment) %>% mutate(strand="*") %>%
      mutate(name=paste(names(m6As)[i],"MACS2", seqnames, start, end, strand,sep="_")) %>%
      dplyr::select(seqnames,start,end,name,score,strand) %>% mutate(Sample=Samples[i],ComboName=dt.parameter.combo.MACS2$ComboName[pc])
  }
}
dt.MACS2.m6As <- dt.MACS2.m6As %>% dplyr::arrange(ComboName,Sample,seqnames,start) %>% filter(str_detect(seqnames,"chr"))
saveRDS(dt.MACS2.m6As, file="/data/m6A_calling_strategy/MACS2/dt.MACS2.m6As.from.alternative.parameters.RDS")

dt.MACS2.m6As %>% filter(Sample == "mESC_WT1") %>% dplyr::arrange(seqnames,start,end) %>% View()
dt.MACS2.m6As %>% filter(Sample == "mESC_WT1") %>% dplyr::arrange(seqnames,start,end) %>%
  group_by(name) %>% mutate(nCombo=n_distinct(ComboName)) %>% as.data.table() %>%  distinct(name,nCombo) %>%  View()

