#the statistics (count,width) of MACS2 m6a
dt.statistic.MACS2 <- dt.MACS2.m6As %>% filter(!str_detect(Sample,"IVT")) %>%
  group_by(ComboName) %>% mutate(Score95=quantile(score,0.95)) %>% #calculate top score for each combo
  group_by(ComboName,Sample) %>% mutate(nPeak=n(), MeanWidth=mean(end-start), MedianWidth=median(end-start),
                                        MeanScore=mean(score),MedianScore=median(score)) %>%
  mutate(RatioWidth150=n_distinct(name[end-start>=150])/nPeak,RatioScore2=n_distinct(name[score>=2])/nPeak) %>%
  as.data.table() %>% distinct(ComboName,Score95,Sample,nPeak,MeanWidth,MedianWidth,RatioWidth150,MeanScore,MedianScore,RatioScore2)
attr(dt.statistic.MACS2,"groups") <- NULL
saveRDS(dt.statistic.MACS2, file="dt.statistic.of.MACS2.m6A.RDS")
dt.statistic.MACS2 <- readRDS("dt.statistic.of.MACS2.m6A.RDS")
AllComboName <- dt.statistic.MACS2[MedianWidth<=10000,unique(ComboName)]
AllSample <- unique(dt.MACS2.m6As$Sample) %>% grep(pattern="IVT",invert = T,value=T)
dt.peakcount.MACS2 <- foreach(c=AllComboName,.combine='rbind')%do%{
  message(paste0("start ", c))
  foreach(s=AllSample,.combine='rbind')%do%{
    dt.m6a <- dt.MACS2.m6As[ComboName==c & Sample==s,]
    registerDoParallel(cl=10)
    fc.cutoffs <- c(0,unlist(quantile(dt.MACS2.m6As[ComboName==c,score],seq(0,0.99,0.01))))
    dt.count <- foreach(fc=fc.cutoffs,.combine='rbind')%dopar%{
      data.table(ComboName=c,Sample=s,foldchange.cutoff=fc,nPeak=nrow(dt.m6a[score>=fc,]))
    }
    stopImplicitCluster()
    dt.count
  }
}
saveRDS(dt.peakcount.MACS2, file="dt.peakcount.MACS2.m6A.RDS")
dt.peakcount.MACS2 <- readRDS("dt.peakcount.MACS2.m6A.RDS")
#overlap of MACS2 and benchmark m6a
MACS2.BenchmarkOverlap <- function(Inputm6A=dt.MACS2.m6As %>% filter(!str_detect(Sample,"IVT") & ComboName=="Combo41"),
                             Benchmark.list=m6A.site.list,
                             bedfile.dir="/data/m6A_calling_strategy/Analysis/BedFiles",
                             out.tmp="/data/m6A_calling_strategy/Analysis/Benchmark_tmp",
                             ncores=20){
  if(!dir.exists(out.tmp)){dir.create(out.tmp)}
  if(!dir.exists(bedfile.dir)){dir.create(bedfile.dir)}
  #write input m6As as bed file
  dt.null <- foreach(c = unique(Inputm6A$ComboName))%do%{
    foreach(s = unique(Inputm6A$Sample))%do%{
      if(!file.exists(paste0(bedfile.dir,"/MACS2_",c,"_",s,".m6a.bed"))){
        out <- Inputm6A %>% filter(Sample==s & ComboName == c)
        fwrite(out[,1:6],sep="\t",row.names=F,col.names=F,file = paste0(bedfile.dir,"/MACS2_",c,"_",s,".m6a.bed"))
      }
    }
  }
  #write benchmark m6a as bed file
  dt.null <- foreach(b = names(Benchmark.list))%do%{
    if(!file.exists(paste0(bedfile.dir,"/Benchmark_",b,".m6a.bed"))){
      out <- Benchmark.list[[b]]
      fwrite(out[,1:6],sep="\t",row.names=F,col.names=F,file=paste0(bedfile.dir,"/Benchmark_",b,".m6a.bed"))
    }
  }
  #prepare parameter data table for parallel
  dt.parameter.table <- foreach(c = unique(Inputm6A$ComboName),.combine='rbind')%do%{
    foreach(s = unique(Inputm6A$Sample),.combine='rbind')%do%{
      if(str_detect(s,"HEK")){Benchmarks <- names(Benchmark.list) %>% grep(pattern="HEK",value=T)}else{
        Benchmarks <- names(Benchmark.list) %>% grep(pattern="mESC",value=T)
      }
      foreach(b=Benchmarks,.combine='rbind')%do%{
        #bedtoolsr::bt.intersect(a=InputBed,b=SamplePositiveBed.list[[k]],F=1,wo=T,s=F,S=F)
        data.table(a=paste0(bedfile.dir,"/MACS2_",c,"_",s,".m6a.bed"),
                   b=paste0(bedfile.dir,"/Benchmark_",b,".m6a.bed"),
                   #option="-wo -F 1 ",
                   outfile=paste0(out.tmp,"/MACS2__",c,"__",s,"__",b,".overlap.txt"))
      }
    }
  }
  fwrite(dt.parameter.table, file=paste0(out.tmp,"/parallel_bedtools_parameter_table.txt"),sep="\t",row.names = F,col.names=F)
  #parallel command
  message("start bedtools intersect command")
  parallel_cmd<- paste0("parallel -j ", ncores," --will-cite -a ", out.tmp, "/parallel_bedtools_parameter_table.txt --colsep '\t' '",
                        "~/anaconda3/envs/m6A_seq/bin/bedtools intersect -wo -F 1 -a {1} -b {2} 1>{3} 2>/dev/null'")
  system(command = parallel_cmd, wait = T)
   message("Finished bedtools intersect")
  # #read and output overlap
  # dt.overlap <- foreach(f=list.files(out.tmp,pattern=".overlap.txt",full.names = F),.combine='rbind')%do%{
  #   fread(file = paste0(out.tmp,"/",f),sep="\t",header=F) %>% mutate(FileName=f %>% str_replace(pattern=".overlap.txt",replacement = "")) %>%
  #     mutate(ComboName=FileName %>% strsplit(split="__",fixed=T) %>% sapply("[",2),
  #            Sample=FileName %>% strsplit(split="__",fixed=T) %>% sapply("[",3),
  #            Benchmark=FileName %>% strsplit(split="__",fixed=T) %>% sapply("[",4)) %>% dplyr::select(-FileName)
  # }
  # #delete tmp
  # system(command = paste0("rm -rf ",out.tmp), wait = T)
  # return(dt.overlap)
}
