dt.MACS2.performance <- foreach(c=AllComboName,.combine='rbind')%do%{
  dt.res.combo <- foreach(s=AllSample %>% grep(pattern="IVT",invert=T,value=T),.combine='rbind')%do%{
      message(paste0("start ",c, " for ", s))
    if(str_detect(s, "HEK")){
      SamplePositiveBed.list <- m6A.site.list[str_detect(names(m6A.site.list),"HEK")]}else{
        SamplePositiveBed.list <- m6A.site.list[str_detect(names(m6A.site.list),"mESC")]
      }
    foreach(b=names(SamplePositiveBed.list),.combine='rbind')%do%{
      #load overlap files
      if(file.exists(paste0("/data/m6A_calling_strategy/Analysis/Benchmark_tmp","/MACS2__",c,"__",s,"__",b,".overlap.txt"))){
        dt.m6a.benchmark.overlap <- fread(paste0("/data/m6A_calling_strategy/Analysis/Benchmark_tmp","/MACS2__",c,"__",s,"__",b,".overlap.txt"))
        fc.cutoffs <- dt.peakcount.MACS2[ComboName==c,unique(foldchange.cutoff)]
        #filter overlap according to foldchange cutoff
        registerDoParallel(cl=4)
          dt.res <- foreach(fc = fc.cutoffs, .combine='rbind')%dopar%{
          dt.m6a.benchmark.overlap <- dt.m6a.benchmark.overlap %>% filter(V5 >= fc)
          if(nrow(dt.m6a.benchmark.overlap)>0){
            TP.peak <- dt.m6a.benchmark.overlap$V4 %>% unique() %>% length()
            TP.site <- dt.m6a.benchmark.overlap[,V10] %>% unique() %>% length()
            data.table(Sample=s,ComboName=c,foldchange.cutoff=fc,Benchmark=b,TP.peak,TP.site,TPR=TP.site/nrow(SamplePositiveBed.list[[b]]))
          }
        }
        stopImplicitCluster()
        dt.res %>% inner_join(x=.,y=dt.peakcount.MACS2 %>% filter(ComboName==c & Sample==s),by=c("ComboName","Sample","foldchange.cutoff"))
      }
    }
  }
  dt.res.combo <- dt.res.combo %>% mutate(FPR=TP.peak/nPeak)
  dt.res.combo
}
saveRDS(dt.MACS2.performance, file="/data/m6A_calling_strategy/Analysis/dt.MACS2.performance.based_on_benchmark_m6As_HEK293_mESC.RDS")


#IVT benchmark of MACS2
source("/data/m6A_calling_strategy/Script/Wrapper_function_for_m6A_calling_using_MACS2SMePeak.R")
dt.MACS2.m6As <- readRDS("/data/m6A_calling_strategy/MACS2/dt.MACS2.m6As.from.alternative.parameters.RDS")
fc.max <- ceiling(quantile(dt.MACS2.m6As$score,0.99))

#benchmark with IVT false positive
dt.MACS2.IVT <- foreach(i = paste0("Combo",1:length(unique(dt.MACS2.m6As$ComboName))),.combine='rbind')%do%{
  message(paste0("Start IVT-based performance estimate  under MACS2 parameter ", i))
  foreach(j = unique(dt.MACS2.m6As[ComboName==i,Sample]) %>% grep(pattern="IVT",invert = T,value=T),.combine='rbind')%do%{
    SampleInputBed <- dt.MACS2.m6As %>% filter(Sample== j & ComboName== i & (end-start)<=5000) ##remove extreme long peaks
    SampleInputBed <- SampleInputBed[,1:6]
    IVT_samples <- unique(dt.MACS2.m6As[ComboName==i,Sample]) %>% grep(pattern="IVT",invert = F,value=T)
    if(str_detect(j, "HEK")){
      genome_file="~/genome_db/STAR_index/STAR_hg38/chrNameLength.txt"
      antibody <- j %>% strsplit(split="_",fixed=T) %>% sapply("[",2)
      IVT_samples <- IVT_samples %>% grep(pattern="HEK",value=T) %>% grep(pattern=antibody,value=T)
    }else{
      genome_file="~/genome_db/STAR_index/STAR_mm39/chrNameLength.txt"
      IVT_samples <- IVT_samples %>% grep(pattern="mESC",value = T)
    }
    if(nrow(SampleInputBed)>0){
      foreach(k = IVT_samples,.combine = 'rbind')%do%{
        SampleNegativeBed <- dt.MACS2.m6As %>% filter(Sample== k & ComboName== i & (end-start)<=5000)
        SampleNegativeBed <- SampleNegativeBed[,1:6]
        dt.TPR.FPR <- EstimatePerformanceIVT(InputBed=SampleInputBed,#standard bed file input with six cols
                                             NegativeBed=SampleNegativeBed,
                                             genome_file=genome_file,
                                             strandness=c("s","S","nonstranded")[3],
                                             OverlapThreshold=0.5,#minimum fraction be satisfied for A OR B
                                             foldchange.step=0.1,
                                             foldchange.range=c(1,fc.max))
        dt.TPR.FPR[is.na(FalsePositiveRate),FalsePositiveRate := 0]
        dt.TPR.FPR[is.na(TruePositivePeak),TruePositivePeak := 0]
        index <- which(dt.TPR.FPR$TruePositivePeak==0)
        if(length(index)>=1){dt.TPR.FPR <- dt.TPR.FPR[1:index[1],]}
        dt.TPR.FPR %>% mutate(ComboName=i,Sample=j,IVTSample=k)
      }
    }
  }
}
saveRDS(dt.MACS2.IVT, file="/data/m6A_calling_strategy/Analysis/dt.MACS2.performance.based_on_IVT.RDS")

################# prepare m6As from MeTPeak with alternative parameters ############
dt.parameter.combo <- foreach(pvalue=c(NA,1,1e-2,1e-5,1e-8),.combine = 'rbind')%do%{#default is NA
  foreach(fdr=c(NA,1,5e-2,1e-3,1e-5),.combine='rbind')%do%{#default is 5e-2
    foreach(window.size=c(50,100),.combine='rbind')%do%{#default is 50
      foreach(sliding.step=c(30,50),.combine='rbind')%do%{#default is 50
        data.table(pvalue_cutoff=pvalue, fdr_cutoff=fdr, window.size=window.size,sliding.step=sliding.step)
      }
    }
  }
} %>% filter((is.na(pvalue_cutoff) & !is.na(fdr_cutoff)) | (is.na(fdr_cutoff) & !is.na(pvalue_cutoff))) %>%  mutate(ComboName=paste0("Combo",1:nrow(.))) %>%
  mutate(pvalue_cutoff=as.character(signif(pvalue_cutoff,1)),fdr_cutoff=as.character(signif(fdr_cutoff,1))) %>%
  mutate(ComboID=case_when(is.na(pvalue_cutoff) ~ paste0("q",fdr_cutoff,"_w",window.size,"_s",sliding.step),
                           !is.na(pvalue_cutoff) ~ paste0("p",pvalue_cutoff,"_w",window.size,"_s",sliding.step))) %>%
  mutate(IsDefaultCombo=ComboID=="q0.05_w50_s50",Method="MeTPeak") %>% dplyr::select(Method,ComboID,IsDefaultCombo,ComboName)

dt.MeTPeak.m6As <- foreach(pc = 1:nrow(dt.parameter.combo),.combine = 'rbind')%do%{
  message(paste0("start loading ", dt.parameter.combo$ComboName[pc]))
  Samples <- list.files(path=paste0("/data/m6A_calling_strategy/MeTPeak_new/",dt.parameter.combo$ComboName[pc]), pattern="peak.xls",full.names = T,recursive = T) %>%
    strsplit(split="/") %>% sapply(tail,2,simplify = F) %>% sapply(head,1)
  m6As <- list.files(path=paste0("/data/m6A_calling_strategy/MeTPeak_new/",dt.parameter.combo$ComboName[pc]), pattern="peak.xls",full.names = T,recursive = T)
  names(m6As) <- Samples
  foreach(i = 1:length(m6As),.combine='rbind')%do%{
    fread(file = m6As[i],header = T) %>% dplyr::mutate(seqnames=chr, start=chromStart, end=chromEnd, score=fold_enrchment) %>%
      mutate(name=paste(names(m6As)[i],"MeTPeak", seqnames, start, end, strand,sep="_")) %>%
      dplyr::select(seqnames,start,end,name,score,strand) %>% mutate(Sample=Samples[i],ComboName=dt.parameter.combo$ComboName[pc])
  }
}
dt.MeTPeak.m6As <- dt.MeTPeak.m6As %>% dplyr::arrange(ComboName,Sample,seqnames,start) %>% filter(str_detect(seqnames,"chr"))
saveRDS(dt.MeTPeak.m6As, file="/data/m6A_calling_strategy/MeTPeak/dt.MeTPeak.m6As.from.alternative.parameters.RDS")

