dt.statistic.MeTPeak <- dt.MeTPeak.m6As %>% filter(!str_detect(Sample,"IVT")) %>%
  group_by(ComboName) %>% mutate(Score95=quantile(score,0.95)) %>% #calculate top score for each combo
  group_by(ComboName,Sample) %>% mutate(nPeak=n(), MeanWidth=mean(end-start), MedianWidth=median(end-start),
                                        MeanScore=mean(score),MedianScore=median(score)) %>%
  mutate(RatioWidth150=n_distinct(name[end-start>=150])/nPeak, RatioWidth5k=n_distinct(name[end-start>=5000])/nPeak,
         RatioScore2=n_distinct(name[score>=2])/nPeak) %>%
  as.data.table() %>% distinct(ComboName,Score95,Sample,nPeak,MeanWidth,MedianWidth,RatioWidth150,RatioWidth5k,MeanScore,MedianScore,RatioScore2)
