         Antibody=case_when(str_detect(Sample, "mESC") ~ "NEB", str_detect(Sample, "NEB") ~ "NEB", str_detect(Sample,"SYSY") ~ "SYSY", str_detect(Sample,"Abcam") ~ "Abcam")) %>%
