################# prepare m6As from exomePeak with alternative parameters ############
dt.parameter.combo <- foreach(pvalue=c(NA,1,1e-2,1e-5,1e-8),.combine = 'rbind')%do%{#default is NA
  foreach(fdr=c(NA,1,5e-2,1e-3,1e-5),.combine='rbind')%do%{#default is 5e-2
    foreach(window.size=c(50,100,200),.combine='rbind')%do%{#default is 200
      foreach(sliding.step=c(30,50),.combine='rbind')%do%{#default is 30
        data.table(pvalue_cutoff=pvalue, fdr_cutoff=fdr, window.size=window.size,sliding.step=sliding.step)
      }
    }
  }
} %>% filter((is.na(pvalue_cutoff) & !is.na(fdr_cutoff)) | (is.na(fdr_cutoff) & !is.na(pvalue_cutoff))) %>%  mutate(ComboName=paste0("Combo",1:nrow(.))) %>%
  mutate(pvalue_cutoff=as.character(signif(pvalue_cutoff,1)),fdr_cutoff=as.character(signif(fdr_cutoff,1))) %>%
  mutate(ComboID=case_when(is.na(pvalue_cutoff) ~ paste0("q",fdr_cutoff,"_w",window.size,"_s",sliding.step),
                           !is.na(pvalue_cutoff) ~ paste0("p",pvalue_cutoff,"_w",window.size,"_s",sliding.step))) %>%
  mutate(IsDefaultCombo=ComboID=="q0.05_w200_s30",Method="exomePeak") %>% dplyr::select(Method,ComboID,IsDefaultCombo,ComboName)

dt.exomePeak.m6As <- foreach(pc = 1:nrow(dt.parameter.combo),.combine = 'rbind')%do%{
  message(paste0("start loading ", dt.parameter.combo$ComboName[pc]))
  Samples <- list.files(path=paste0("/data/m6A_calling_strategy/exomePeak_new/",dt.parameter.combo$ComboName[pc]), pattern="peak.xls",full.names = T,recursive = T) %>%
    strsplit(split="/") %>% sapply(tail,2,simplify = F) %>% sapply(head,1)
  m6As <- list.files(path=paste0("/data/m6A_calling_strategy/exomePeak_new/",dt.parameter.combo$ComboName[pc]), pattern="peak.xls",full.names = T,recursive = T)
  names(m6As) <- Samples
  foreach(i = 1:length(m6As),.combine='rbind')%do%{
    fread(file = m6As[i],header = T) %>% dplyr::mutate(seqnames=chr, start=chromStart, end=chromEnd, score=fold_enrchment) %>%
      mutate(name=paste(names(m6As)[i],"exomePeak", seqnames, start, end, strand,sep="_")) %>%
      dplyr::select(seqnames,start,end,name,score,strand) %>% mutate(Sample=Samples[i],ComboName=dt.parameter.combo$ComboName[pc])
  }
}
dt.exomePeak.m6As <- dt.exomePeak.m6As %>% dplyr::arrange(ComboName,Sample,seqnames,start) %>% filter(str_detect(seqnames,"chr"))
saveRDS(dt.exomePeak.m6As, file="/data/m6A_calling_strategy/exomePeak/dt.exomePeak.m6As.from.alternative.parameters.RDS")


#benchmark based on reference m6As
source("/data/m6A_calling_strategy/Script/Wrapper_function_for_m6A_calling_using_MACS2SMePeak.R")
dt.exomePeak.m6As <- readRDS("/data/m6A_calling_strategy/exomePeak/dt.exomePeak.m6As.from.alternative.parameters.RDS")
dt.exomePeak.m6As <- dt.exomePeak.m6As %>% filter(!str_detect(Sample, "IVT"))
dt.exomePeak.m6As[,.N,by=.(ComboName,Sample)]
dt.HEK293.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.HEK293.benchmark.m6As.RDS")
dt.mESC.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.mESC.benchmark.m6As.RDS")
dt.benchmark.m6As <- rbind(dt.HEK293.benchmark.m6As,dt.mESC.benchmark.m6As)
m6A.site.list <- foreach(i=unique(dt.benchmark.m6As$Sample))%do%{
  dt.benchmark.m6As[Sample==i,1:6]
}
names(m6A.site.list) <- unique(dt.benchmark.m6As$Sample)
fc.max <- ceiling(quantile(dt.exomePeak.m6As$score,0.99))[[1]]

dt.exomePeak.performance <- foreach(i = paste0("Combo",1:length(unique(dt.exomePeak.m6As$ComboName))),.combine='rbind')%do%{
  message(paste0("Start performance estimate for  under exomePeak parameter ", i))
  foreach(j = unique(dt.exomePeak.m6As[ComboName==i,Sample]),.combine='rbind')%do%{
    SampleInputBed <- dt.exomePeak.m6As %>% filter(Sample== j & ComboName== i & (end - start) <= 5000)#remove extreme long peaks
    SampleInputBed <- SampleInputBed[,1:6]
    if(str_detect(j, "HEK")){
      SamplePositiveBed.list <- m6A.site.list[str_detect(names(m6A.site.list),"HEK")]}else{
        SamplePositiveBed.list <- m6A.site.list[str_detect(names(m6A.site.list),"mESC")]
      }
    if(nrow(SampleInputBed)>0){
      foreach(k = 1:length(SamplePositiveBed.list),.combine = 'rbind')%do%{
        dt.TPR.FPR <- EstimatePerformance(InputBed=SampleInputBed,
                                          PositiveBed=SamplePositiveBed.list[[k]],
                                          strandness=c("s","S","nonstranded")[1],
                                          OverlapThreshold=0.5,#minimum fraction be satisfied for A OR B
                                          foldchange.step=0.1,
                                          foldchange.range=c(1,fc.max))
        if(nrow(dt.TPR.FPR)>0){
          dt.TPR.FPR[is.na(FalsePositiveRate),FalsePositiveRate := 0]
          dt.TPR.FPR[is.na(TruePositiveRate),TruePositiveRate := 0]
          index <- which(dt.TPR.FPR$TruePositiveRate==0)
          if(length(index)>=1){dt.TPR.FPR <- dt.TPR.FPR[1:index[1],]}
          dt.TPR.FPR %>% mutate(ComboName=i,Sample=j,PositiveBed=names(SamplePositiveBed.list)[k])
        }
      }
    }
  }
}
saveRDS(dt.exomePeak.performance, file="/data/m6A_calling_strategy/Analysis/dt.exomePeak.performance.based_on_benchmark_m6As_HEK293_mESC.RDS")


#benchmark based on IVT
source("/data/m6A_calling_strategy/Script/Wrapper_function_for_m6A_calling_using_MACS2SMePeak.R")
dt.exomePeak.m6As <- readRDS("/data/m6A_calling_strategy/exomePeak/dt.exomePeak.m6As.from.alternative.parameters.RDS")
fc.max <- ceiling(quantile(dt.exomePeak.m6As$score,0.99))[[1]]

#benchmark with IVT false positive
dt.exomePeak.IVT <- foreach(i = paste0("Combo",1:length(unique(dt.exomePeak.m6As$ComboName))),.combine='rbind')%do%{
  message(paste0("Start IVT-based performance estimate  under exomePeak parameter ", i))
  foreach(j = unique(dt.exomePeak.m6As[ComboName==i,Sample]) %>% grep(pattern="IVT",invert = T,value=T),.combine='rbind')%do%{
    #message(paste0("Start IVT-based performance estimate ", j, " under exomePeak parameter ", i))
    SampleInputBed <- dt.exomePeak.m6As %>% filter(Sample== j & ComboName== i & (end-start)<=5000) ##remove extreme long peaks
    SampleInputBed <- SampleInputBed[,1:6]
    IVT_samples <- unique(dt.exomePeak.m6As[ComboName==i,Sample]) %>% grep(pattern="IVT",invert = F,value=T)
    if(str_detect(j, "HEK")){
      genome_file="~/genome_db/STAR_index/STAR_hg38/chrNameLength.txt"
      antibody <- j %>% strsplit(split="_",fixed=T) %>% sapply("[",2)
      IVT_samples <- IVT_samples %>% grep(pattern="HEK",value=T) %>% grep(pattern=antibody,value=T)
    }else{
      genome_file="~/genome_db/STAR_index/STAR_mm39/chrNameLength.txt"
      IVT_samples <- IVT_samples %>% grep(pattern="mESC",value = T)
    }
    if(nrow(SampleInputBed)>0){
      foreach(k = IVT_samples,.combine = 'rbind')%do%{
        SampleNegativeBed <- dt.exomePeak.m6As %>% filter(Sample== k & ComboName== i & (end-start)<=5000)##remove extreme long peaks
        SampleNegativeBed <- SampleNegativeBed[,1:6]
        dt.TPR.FPR <- EstimatePerformanceIVT(InputBed=SampleInputBed,#standard bed file input with six cols
                                             NegativeBed=SampleNegativeBed,
                                             genome_file=genome_file,
                                             strandness=c("s","S","nonstranded")[1],
                                             OverlapThreshold=0.5,#minimum fraction be satisfied for A OR B
                                             foldchange.step=0.1,
                                             foldchange.range=c(1,fc.max))
        dt.TPR.FPR[is.na(FalsePositiveRate),FalsePositiveRate := 0]
        dt.TPR.FPR[is.na(TruePositivePeak),TruePositivePeak := 0]
        index <- which(dt.TPR.FPR$TruePositivePeak==0)
        if(length(index)>=1){dt.TPR.FPR <- dt.TPR.FPR[1:index[1],]}
        dt.TPR.FPR %>% mutate(ComboName=i,Sample=j,IVTSample=k)
      }
    }
  }
}
saveRDS(dt.exomePeak.IVT, file="/data/m6A_calling_strategy/Analysis/dt.exomePeak.performance.based_on_IVT.RDS")

