dt.parameter.combo <- foreach(mode=c("exon","full_transcript"),.combine='rbind')%do%{#default is exon
  foreach(bin.size=c(25,50,100),.combine='rbind')%do%{#default is 25
    foreach(step.size=c(25,50),.combine='rbind')%do%{#default is 25
      foreach(pvalue=c(1,1e-3,1e-10,1e-12),.combine='rbind')%do%{#default is 1e-10
        data.table(mode=mode,bin.size,step.size,pvalue_cutoff=pvalue)
      }
    }
  }
} %>% filter(bin.size>=step.size) %>%
  dplyr::arrange(mode,bin.size,step.size,pvalue_cutoff) %>% mutate(ComboName=paste0("Combo",1:nrow(.)),pvalue_cutoff=as.character(signif(pvalue_cutoff,1))) %>%
  mutate(ComboID=paste0(ifelse(mode=="exon","ExMode_","TxMode_"),"p",pvalue_cutoff,"_w",bin.size,"_s",step.size)) %>%
  mutate(IsDefaultCombo=ComboID=="ExMode_p1e-10_w25_s25",Method="exomePeak2") %>% dplyr::select(Method,ComboID,IsDefaultCombo,ComboName)

dt.exomePeak2.m6As <- foreach(pc = 1:nrow(dt.parameter.combo),.combine = 'rbind')%do%{
  message(paste0("start loading ", dt.parameter.combo$ComboName[pc]))
  Samples <- list.files(path=paste0("/data/m6A_calling_strategy/exomePeak2_new/",dt.parameter.combo$ComboName[pc]), pattern="peaks.csv",full.names = T,recursive = T) %>%
    strsplit(split="/") %>% sapply(tail,2,simplify = F) %>% sapply(head,1) %>% strsplit(split="__",fixed=T) %>% sapply("[",1)
  m6As <- list.files(path=paste0("/data/m6A_calling_strategy/exomePeak2_new/",dt.parameter.combo$ComboName[pc]), pattern="peaks.csv",full.names = T,recursive = T)
  names(m6As) <- Samples
  foreach(i = 1:length(m6As),.combine='rbind')%do%{
    fread(file = m6As[i],header = T) %>% dplyr::mutate(seqnames=chr, start=chromStart, end=chromEnd, score=(RPM.IP+0)/(RPM.input+0)) %>%#add pseudocount 0.1
      filter(RPM.IP>RPM.input) %>%
      mutate(name=paste(names(m6As)[i],"exomePeak2", seqnames, start, end, strand,sep="_")) %>%
      dplyr::select(seqnames,start,end,name,score,strand,contains("RPM")) %>% mutate(Sample=Samples[i],ComboName=dt.parameter.combo$ComboName[pc])
  }
}
