dt.exomePeak2.performance <- foreach(i = paste0("Combo",1:length(unique(dt.exomePeak2.m6As$ComboName))),.combine='rbind')%do%{
  message(paste0("Start performance estimate for  under exomePeak2 parameter ", i))
  foreach(j = unique(dt.exomePeak2.m6As[ComboName==i,Sample]),.combine='rbind')%do%{
    SampleInputBed <- dt.exomePeak2.m6As %>% filter(Sample== j & ComboName== i & (end - start) <= 5000)#remove extreme long peaks
    SampleInputBed <- SampleInputBed[,1:6]
    if(str_detect(j, "HEK")){
      SamplePositiveBed.list <- m6A.site.list[str_detect(names(m6A.site.list),"HEK")]}else{
        SamplePositiveBed.list <- m6A.site.list[str_detect(names(m6A.site.list),"mESC")]
      }
    if(nrow(SampleInputBed)>0){
      foreach(k = 1:length(SamplePositiveBed.list),.combine = 'rbind')%do%{
        dt.TPR.FPR <- EstimatePerformance(InputBed=SampleInputBed,
                                          PositiveBed=SamplePositiveBed.list[[k]],
                                          strandness=c("s","S","nonstranded")[1],
                                          OverlapThreshold=0.5,#minimum fraction be satisfied for A OR B
                                          foldchange.step=0.1,
                                          foldchange.range=c(1,fc.max))
        if(nrow(dt.TPR.FPR)>0){
          dt.TPR.FPR[is.na(FalsePositiveRate),FalsePositiveRate := 0]
          dt.TPR.FPR[is.na(TruePositiveRate),TruePositiveRate := 0]
          index <- which(dt.TPR.FPR$TruePositiveRate==0)
          if(length(index)>=1){dt.TPR.FPR <- dt.TPR.FPR[1:index[1],]}
          dt.TPR.FPR %>% mutate(ComboName=i,Sample=j,PositiveBed=names(SamplePositiveBed.list)[k])
        }
      }
    }
  }
}
saveRDS(dt.exomePeak2.performance, file="/data/m6A_calling_strategy/Analysis/dt.exomePeak2.performance.based_on_benchmark_m6As_HEK293_mESC.RDS")

