dt.exomePeak2.m6As[RPM.input==0,score:=(RPM.IP+0.5)/(RPM.input+0.5)]
fc.max <- ceiling(quantile(dt.exomePeak2.m6As$score,0.99))[[1]]

#benchmark with IVT false positive
dt.exomePeak2.IVT <- foreach(i = paste0("Combo",1:length(unique(dt.exomePeak2.m6As$ComboName))),.combine='rbind')%do%{
  message(paste0("Start IVT-based performance estimate  under exomePeak2 parameter ", i))
  foreach(j = unique(dt.exomePeak2.m6As[ComboName==i,Sample]) %>% grep(pattern="IVT",invert = T,value=T),.combine='rbind')%do%{
    #message(paste0("Start IVT-based performance estimate ", j, " under exomePeak2 parameter ", i))
    SampleInputBed <- dt.exomePeak2.m6As %>% filter(Sample== j & ComboName== i & (end-start)<=5000) ##remove extreme long peaks
    SampleInputBed <- SampleInputBed[,1:6]
    IVT_samples <- unique(dt.exomePeak2.m6As[ComboName==i,Sample]) %>% grep(pattern="IVT",invert = F,value=T)
    if(str_detect(j, "HEK")){
      genome_file="~/genome_db/STAR_index/STAR_hg38/chrNameLength.txt"
      antibody <- j %>% strsplit(split="_",fixed=T) %>% sapply("[",2)
      IVT_samples <- IVT_samples %>% grep(pattern="HEK",value=T) %>% grep(pattern=antibody,value=T)
    }else{
      genome_file="~/genome_db/STAR_index/STAR_mm39/chrNameLength.txt"
      IVT_samples <- IVT_samples %>% grep(pattern="mESC",value = T)
    }
    if(nrow(SampleInputBed)>0){
      foreach(k = IVT_samples,.combine = 'rbind')%do%{
        SampleNegativeBed <- dt.exomePeak2.m6As %>% filter(Sample== k & ComboName== i & (end-start)<=5000)##remove extreme long peaks
        SampleNegativeBed <- SampleNegativeBed[,1:6]
        dt.TPR.FPR <- EstimatePerformanceIVT(InputBed=SampleInputBed,#standard bed file input with six cols
                                             NegativeBed=SampleNegativeBed,
                                             genome_file=genome_file,
                                             strandness=c("s","S","nonstranded")[1],
                                             OverlapThreshold=0.5,#minimum fraction be satisfied for A OR B
                                             foldchange.step=0.1,
                                             foldchange.range=c(1,fc.max))
        dt.TPR.FPR[is.na(FalsePositiveRate),FalsePositiveRate := 0]
        dt.TPR.FPR[is.na(TruePositivePeak),TruePositivePeak := 0]
        index <- which(dt.TPR.FPR$TruePositivePeak==0)
        if(length(index)>=1){dt.TPR.FPR <- dt.TPR.FPR[1:index[1],]}
        dt.TPR.FPR %>% mutate(ComboName=i,Sample=j,IVTSample=k)
      }
    }
  }
}
saveRDS(dt.exomePeak2.IVT, file="/data/m6A_calling_strategy/Analysis/dt.exomePeak2.performance.based_on_IVT.RDS")

