    strsplit(split="/") %>% sapply(tail,1) %>% str_replace(pattern="_peaks.xls",replacement="")
  m6As <- list.files(path=paste0("/data/m6A_calling_strategy/TRESS_new/",dt.parameter.combo$ComboName[pc]), pattern="peaks.xls",full.names = T,recursive = T)
  names(m6As) <- Samples
  foreach(i = 1:length(m6As),.combine='rbind')%do%{
    fread(file = m6As[i],header = T) %>% dplyr::mutate(seqnames=chr, score=2^(as.numeric(lg.fc))) %>%
      mutate(name=paste(names(m6As)[i],"TRESS", seqnames, start, end, strand,sep="_")) %>%
      dplyr::select(seqnames,start,end,name,score,strand,pvalue=pvals,fdr=p.adj) %>% mutate(Sample=Samples[i],ComboName=dt.parameter.combo$ComboName[pc])
  }
}
