################# prepare m6As from MeRIPtools with alternative parameters ############
dt.parameter.combo <-  foreach(binSize=c(50),.combine = 'rbind')%do%{#default is 50
  foreach(test.method=c("Fisher","Binomial"),.combine='rbind')%do%{#default is unknown
    foreach(min_counts=c(5,15),.combine='rbind')%do%{#default is 15
      foreach(fdr_cutoff=c(0.1,0.05,1e-2),.combine='rbind')%do%{#default is 0.05
        foreach(oddratio_cutoff=c(0,1),.combine='rbind')%do%{#default is 1
          data.table(binSize=binSize, test.method=test.method, min_counts=min_counts, fdr_cutoff=fdr_cutoff, oddratio_cutoff=oddratio_cutoff)
        }
      }
    }
  }
} %>% mutate(ComboName=paste0("Combo",1:nrow(.))) %>% mutate(IsDefaultCombo = binSize==50 & min_counts==15 & fdr_cutoff==0.05 & oddratio_cutoff==1, Method="MeRIPtools") %>%
  dplyr::arrange(desc(IsDefaultCombo))

dt.MeRIPtools.m6As <- foreach(pc = 1:nrow(dt.parameter.combo),.combine = 'rbind')%do%{
  message(paste0("start loading ", dt.parameter.combo$ComboName[pc]))
  Samples <- list.files(path=paste0("/data/m6A_calling_strategy/MeRIPtools/",dt.parameter.combo$ComboName[pc]), pattern="peak.tsv",full.names = T,recursive = T) %>%
    strsplit(split="/") %>% sapply(tail,1) %>% str_replace(pattern="_peak.tsv",replacement="")
  m6As <- list.files(path=paste0("/data/m6A_calling_strategy/MeRIPtools/",dt.parameter.combo$ComboName[pc]), pattern="peak.tsv",full.names = T,recursive = T)
  names(m6As) <- Samples
  foreach(i = 1:length(m6As),.combine='rbind')%do%{
    fread(file = m6As[i],header = T) %>% dplyr::mutate(seqnames=chr) %>%
      mutate(name=paste(names(m6As)[i],"MeRIPtools", seqnames, start, end, strand,sep="_")) %>%
      dplyr::select(seqnames,start,end,name,score,strand,contains("Cov.norm")) %>% mutate(Sample=Samples[i],ComboName=dt.parameter.combo$ComboName[pc])
  }
}
