dt.Method.TPR.FPR.pruned.IVTControled  <- foreach(m = unique(dt.Method.TPR.FPR$Method),.combine='rbind')%do%{
    dt.method <- foreach(combo = dt.Method.TPR.FPR[Method==m,unique(ComboName)],.combine='rbind')%do%{
      registerDoParallel(cl=2)
      message(paste0("start FPR/TPR prune for ", m, " under parameter ", combo))
      dt.combo <- foreach(a = dt.Method.TPR.FPR[Method==m & ComboName==combo,unique(Antibody)],.combine='rbind')%do%{
        foreach(cell = dt.Method.TPR.FPR[Method==m & ComboName==combo & Antibody==a,unique(Cell)],.combine='rbind')%do%{
          foreach(b = dt.Method.TPR.FPR[Method==m & ComboName==combo & Antibody==a & Cell==cell,unique(BenchmarkType)],.combine='rbind')%do%{
            TPR.FPR.pruned(dt.TPR.FPR.fc = dt.Method.TPR.FPR[Method==m & ComboName==combo & Antibody==a & Cell==cell & BenchmarkType==b,.(FPR=FalsePositiveRate.avg, TPR=TruePositiveRate.avg, cutoff=foldchange.cutoff)],step=0.01) %>%
              mutate(Method=m, ComboName=combo, Antibody=a, Cell=cell, BenchmarkType=b)
          }
        }
      }
      stopImplicitCluster()
      dt.combo
    }
    dt.method
}

