#obtain the distribution of longest tx width of hg38 and mm39
if(!file.exists("dt.tx.length.distribution.hg38.mm39.RDS")){
  txdb.hg38 <- GenomicFeatures::makeTxDbFromGFF("~/genome_db/gencode.v44.annotation.gtf")
  txdb.mm39 <- GenomicFeatures::makeTxDbFromGFF("~/genome_db/gencode.vM33.annotation.gtf")
  dt.tx.length.hg38 <- GenomicFeatures::transcriptLengths(txdb.hg38,with.cds_len=F, with.utr5_len=F,with.utr3_len=F) %>% as.data.table()
  dt.tx.length.hg38  <- dt.tx.length.hg38 %>% dplyr::arrange(gene_id,desc(tx_len))
  dt.tx.length.hg38.distribution <- dt.tx.length.hg38 %>% group_by(gene_id) %>% slice_max(tx_len) %>% as.data.table() %>%
    mutate(txlength.q25=quantile(tx_len,0.25),txlength.q50=quantile(tx_len,0.50),txlength.q75=quantile(tx_len,0.75),txlength.q95=quantile(tx_len,0.95)) %>%
    dplyr::select(contains("txlength")) %>% distinct() %>% mutate(genome="hg38")
  dt.tx.length.mm39 <- GenomicFeatures::transcriptLengths(txdb.mm39,with.cds_len=F, with.utr5_len=F,with.utr3_len=F) %>% as.data.table()
  dt.tx.length.mm39  <- dt.tx.length.mm39 %>% dplyr::arrange(gene_id,desc(tx_len))
  dt.tx.length.mm39.distribution <- dt.tx.length.mm39 %>% group_by(gene_id) %>% slice_max(tx_len) %>% as.data.table() %>%
    mutate(txlength.q25=quantile(tx_len,0.25),txlength.q50=quantile(tx_len,0.50),txlength.q75=quantile(tx_len,0.75),txlength.q95=quantile(tx_len,0.95)) %>%
    dplyr::select(contains("txlength")) %>% distinct() %>% mutate(genome="mm39")
  dt.tx.length.distribution <- rbind(dt.tx.length.mm39.distribution,dt.tx.length.hg38.distribution)
  saveRDS(dt.tx.length.distribution , file="dt.tx.length.distribution.hg38.mm39.RDS")
}else{
  dt.tx.length.distribution <- readRDS("dt.tx.length.distribution.hg38.mm39.RDS")
}
dt.peak.width.statistic <- foreach(M = c("exomePeak","exomePeak2","MACS2","MeRIPtools","MeTPeak","TRESS"),.combine='rbind')%do%{
  dt.statistic <- readRDS(paste0("dt.peak.width.statistic.of.",M,".m6As.RDS")) %>% dplyr::select(Method,ComboName,everything())
  dt.statistic
} %>% dplyr::arrange(desc(SumWidth.q50))
dt.peak.width.statistic <- dt.peak.width.statistic %>% mutate(Combo=paste0(Method,"|",ComboName)) %>% group_by(Combo) %>% mutate(avg.SumWidth.q50=mean(SumWidth.q50)) %>% as.data.table()

p.peak.width.q50 <- dt.peak.width.statistic %>% distinct(Combo,avg.SumWidth.q50,Method) %>%
  ggplot(data=.)+
  geom_bar(aes(x=Combo,y=avg.SumWidth.q50/1000,fill=Method),width=0.5,stat = "identity")+
  geom_hline(yintercept = dt.tx.length.distribution[genome=="hg38",txlength.q25/1000],linewidth=0.5,linetype=2,color="red")+
  geom_hline(yintercept = dt.tx.length.distribution[genome=="hg38",txlength.q50/1000],linewidth=0.5,linetype=1,color="red")+
  geom_hline(yintercept = dt.tx.length.distribution[genome=="hg38",txlength.q75/1000],linewidth=0.5,linetype=2,color="red")+
  scale_y_continuous(limits = c(0,5),na.value = 5)+
  scale_fill_manual(breaks = c("MACS2","TRESS","exomePeak","exomePeak2","MeRIPtools","MeTPeak"),
                    values = c("#003a7d","#008dff","#ff73b6","#c701ff","#4ecb8d","#ff9d3a"))+
  labs(x="Combos of all methods", y="Median of intron-removed width of peak (kB)")+
  theme_pubr(base_size = 7,base_family = "Times")+
  theme(plot.title = element_text(size=7,face = "bold",hjust=0.5),
        plot.subtitle = element_text(size=7,hjust=0.5,face="bold"),
        legend.position = "top",legend.key.height = unit(6,"point"),legend.key.width=unit(6,"point"),
        legend.text = element_text(size=7),legend.title = element_text(size=7),legend.spacing = unit(1,"point"),
        strip.background = element_rect(fill="white"), axis.text.x = element_blank())

dt.method.combo.filtered <- dt.peak.width.statistic %>% dplyr::filter(avg.SumWidth.q50<=dt.tx.length.distribution[genome=="hg38",txlength.q50]) %>% distinct(Method,ComboName,Combo,avg.SumWidth.q50)
