    scale_linewidth_manual(values = c(2,0.5),breaks = c(TRUE,FALSE),guide="none")+
    scale_y_continuous(n.breaks = 10)+
    scale_x_continuous(limits = c(0,1),n.breaks = 6)+
    scale_color_manual(values = dt.Method.IVTControled.Combo.color$Color,
                       breaks = dt.Method.IVTControled.Combo.color$ComboName, guide="none")+
    labs(x="False positive rate", y="True positive rate",title=ifelse(IVTcutoff==1, paste0(METHOD," performance (Abcam antibody)"), paste0(METHOD," performance with IVT controled (Abcam antibody)")),
         subtitle =  "GLORI sites as benchmark m6As")+
    facet_wrap(~Cell,scales = "fixed")+
    theme_pubr(base_size=7,base_family = "Times")+
    theme(plot.title = element_text(size=7,face = "bold",hjust=0.5),
          plot.subtitle = element_text(size=7,hjust=0.5,face="bold"),
          legend.position = "top",legend.key.height = unit(6,"point"),legend.key.width=unit(6,"point"),
          legend.text = element_text(size=7),legend.title = element_text(size=7),legend.spacing = unit(1,"point"),
          strip.background = element_rect(fill="white"))
  p.Method.IVTControled.TPR.FPR.Abcam.GLORI

  #plot7 the the pruned TPR and FPR of Abcam anti-m6A and SACseq
  require(ggpubr)
  require(ggsci)
  dt.Method.IVTControled.Combo.color <- data.table(Method =METHOD, ComboName=unique(dt.Method.IVTControled.TPR.FPR[Method==METHOD,ComboName]),
                                                   Color=colorRampPalette(c("black", "white"))(length(unique(dt.Method.IVTControled.TPR.FPR[Method==METHOD,ComboName]))),
                                                   Highlight=FALSE)
  dt.Method.IVTControled.Combo.color[ComboName %in% dt.Method.IVTControled.TPR.FPR[IsDefaultCombo==TRUE & Method==METHOD,unique(ComboName)], `:=`(Color = "#1a80bb", Highlight=TRUE)]
  dt.Method.IVTControled.Combo.color[ComboName %in% dt.Method.IVTControled.AUC.top[Method == METHOD  & Antibody=="Abcam" & str_detect(BenchmarkType,"GLORI"), unique(ComboName)], `:=`(Color = "#a00000", Highlight=TRUE)]

  dt.highlight.combo.auc <- dt.Method.IVTControled.AUC %>% filter(Method== METHOD & Antibody=="Abcam" & str_detect(BenchmarkType,"SACseq")) %>%
    filter(IsDefaultCombo | ComboName %in% dt.Method.IVTControled.AUC.top[Method == METHOD  & Antibody=="Abcam" & str_detect(BenchmarkType,"GLORI"), unique(ComboName)]) %>%
    dplyr::select(Method,Antibody,BenchmarkType,ComboName,IsDefaultCombo,ComboID,Cell,contains("AUC")) %>%
    left_join(x=.,y=dt.Method.IVTControled.Combo.color %>% dplyr::select(Method,ComboName,Color)) %>%
    mutate(ypos=ifelse(IsDefaultCombo==TRUE, 0.7, 0.8),xpos=0.5, label=ifelse(IsDefaultCombo==TRUE,paste0("Default:",ComboName,":",ComboID,":ScaledAUC=",AUC.scaled),
                                                                              paste0("Best:",ComboName,":",ComboID,":ScaledAUC=",AUC.scaled))) %>%
    mutate(ypos=dplyr::case_when(str_detect(label,"Fisher") ~ 0.6, .default = ypos)) %>% mutate(ypos=dplyr::case_when(METHOD == "MACS2" ~ ypos+0.2, .default = ypos))

  p.Method.IVTControled.TPR.FPR.Abcam.SACseq <- dt.Method.IVTControled.TPR.FPR %>% filter(Method== METHOD & Antibody=="Abcam" & str_detect(BenchmarkType,"SACseq")) %>%
    left_join(x=.,y=dt.Method.IVTControled.Combo.color,by="ComboName") %>%
    ggplot(data=.,aes(x=FPR, y=TPR,color=ComboName))+
    geom_text(data=dt.highlight.combo.auc,aes(x=xpos,y=ypos,color=ComboName,label=label),size=2.5)+
    #geom_smooth(linewidth=0.5,se = F,aes(linetype=Highlight,linewidth=Highlight))+
    geom_step(linewidth=0.5,aes(linetype=Highlight,linewidth=Highlight))+
    scale_linetype_manual(values = c(1,2),breaks = c(TRUE,FALSE),guide="none")+
    scale_linewidth_manual(values = c(2,0.5),breaks = c(TRUE,FALSE),guide="none")+
    scale_y_continuous(n.breaks = 10)+
    scale_x_continuous(limits = c(0,1),n.breaks = 6)+
    scale_color_manual(values = dt.Method.IVTControled.Combo.color$Color,
                       breaks = dt.Method.IVTControled.Combo.color$ComboName, guide="none")+
    labs(x="False positive rate", y="True positive rate",title=ifelse(IVTcutoff==1, paste0(METHOD," performance (Abcam antibody)"), paste0(METHOD," performance with IVT controled (Abcam antibody)")),
         subtitle =  "SACseq sites as benchmark m6As")+
    facet_wrap(~Cell,scales = "fixed")+
    theme_pubr(base_size=7,base_family = "Times")+
    theme(plot.title = element_text(size=7,face = "bold",hjust=0.5),
          plot.subtitle = element_text(size=7,hjust=0.5,face="bold"),
          legend.position = "top",legend.key.height = unit(6,"point"),legend.key.width=unit(6,"point"),
          legend.text = element_text(size=7),legend.title = element_text(size=7),legend.spacing = unit(1,"point"),
          strip.background = element_rect(fill="white"))
  p.Method.IVTControled.TPR.FPR.Abcam.SACseq

  require(plotgardener)
  pdf(ifelse(IVTcutoff==1,paste0("plot.",METHOD,".best.combo.pdf"),paste0("plot.",METHOD,".best.combo.IVTcontroled.pdf")),width = 18, height = 11.693)
  pageCreate(width=37,height = 20,default.units = "cm",showGuides = F)
  plotGG(p.Method.IVTControled.TPR.FPR.NEB.GLORI, x = 0.05, y=0.05, default.units = "cm",width = 18, height = 7)
  plotGG(p.Method.IVTControled.TPR.FPR.NEB.eTAMseq, x = 18.2, y=0.05, default.units = "cm",width = 9, height = 7)
  plotGG(p.Method.IVTControled.TPR.FPR.NEB.SACseq, x = 27.3, y=0.05, default.units = "cm",width = 9, height = 7)
  plotGG(p.Method.IVTControled.TPR.FPR.SYSY.GLORI, x = 0.05, y=7.2, default.units = "cm",width = 9, height = 7)
  plotGG(p.Method.IVTControled.TPR.FPR.SYSY.SACseq, x = 9.2, y=7.2, default.units = "cm",width = 9, height = 7)
  plotGG(p.Method.IVTControled.TPR.FPR.Abcam.GLORI, x = 18.2, y=7.2, default.units = "cm",width = 9, height = 7)
  plotGG(p.Method.IVTControled.TPR.FPR.Abcam.SACseq, x = 27.3, y=7.2, default.units = "cm",width = 9, height = 7)
  dev.off()
}

