#load m6As MACS2 best combo (Combo41) under NEB
dt.MACS2.m6As <- readRDS("/data/m6A_calling_strategy/MACS2/dt.MACS2.m6As.from.alternative.parameters.RDS")
fc.max <- ceiling(quantile(dt.MACS2.m6As$score,0.99))[[1]]
dt.MACS2.m6As <- dt.MACS2.m6As %>% filter(ComboName=="Combo41" & (str_detect(Sample,"NEB") | str_detect(Sample,"mESC")))
dt.MACS2.m6As[,.N,by=.(ComboName,Sample)]
