# 8:   Combo41      mESC_WT2 102725
#load TPR/FPR to determine the fold change cutoff under FPR
dt.MACS2.TPR.FPR.pruned <- readRDS("dt.Method.TPR.FPR.pruned.RDS")%>% filter(Method=="MACS2" & ComboName=="Combo41" & Antibody=="NEB")
dt.MACS2.TPR.FPR.pruned %>% filter(TruePositiveRate==0.6)
#    Method ComboName Antibody Cell BenchmarkType FalsePositiveRate TruePositiveRate foldchange.cutoff TruePositivePeak.avg IVTRemovedPeaks   IVTRate
# 1:  MACS2   Combo41      NEB  HEK        SACseq               0.5        0.4683528              42.9               7040.0         6352.75 0.5491957
# 2:  MACS2   Combo41      NEB  HEK         GLORI               0.5        0.6843378              13.5              17560.0        11614.50 0.6692913
# 3:  MACS2   Combo41      NEB mESC         GLORI               0.5        0.6693074              27.2               9708.5         7390.00 0.6190752
# 4:  MACS2   Combo41      NEB mESC       eTAMseq               0.5        0.7471147              32.5               8341.5         6763.25 0.5942831
dt.MACS2.TPR.FPR <- readRDS("dt.Method.TPR.FPR.RDS") %>% filter(Method=="MACS2" & ComboName=="Combo41" & Antibody=="NEB")
#fc.max <- ceiling(quantile(dt.MACS2.m6As$score,0.99))[[1]]
dt.HEK293.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.HEK293.benchmark.m6As.RDS")
dt.mESC.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.mESC.benchmark.m6As.RDS")
dt.benchmark.m6As <- rbind(dt.HEK293.benchmark.m6As,dt.mESC.benchmark.m6As)
m6A.site.list <- foreach(i=unique(dt.benchmark.m6As$Sample))%do%{dt.benchmark.m6As[Sample==i,1:6]}
names(m6A.site.list) <- unique(dt.benchmark.m6As$Sample)
registerDoParallel(cl=10)
dt.MACS2.TPR.FPR.IVT.divided <- foreach(s=unique(dt.MACS2.m6As$Sample) %>% grep(pattern="IVT",invert=T,value=T),.combine='rbind')%do%{
  ivt_sample <- dplyr::case_when(str_detect(s,"HEK") ~ c("HEK_NEB_IVT1","HEK_NEB_IVT2"), str_detect(s,"mESC") ~ c("mESC_IVT1","mESC_IVT2"))
  foreach(ivt = ivt_sample,.combine='rbind')%do%{
    message(paste0("calculate IVT divided TPR/FPR for ",s," based IVT ", ivt))
    dt.sample.m6a <- dt.MACS2.m6As %>% filter(Sample==s) %>%  filter((end-start<=5000))
    dt.ivt.m6a <- dt.MACS2.m6As %>% filter(Sample==ivt) %>% filter((end-start<=5000))
    #overlap with IVT
    genome_file=ifelse(str_detect(s,"HEK"),"~/genome_db/STAR_index/STAR_hg38/chrNameLength.txt","~/genome_db/STAR_index/STAR_mm39/chrNameLength.txt")
    InputBed <- bedtoolsr::bt.sort(dt.sample.m6a[,1:6],g = genome_file) %>% as.data.table()
    NegativeBed <- bedtoolsr::bt.sort(dt.ivt.m6a[,1:6],g=genome_file) %>% as.data.table()
    dt.m6As.IVT.overlap <- bedtoolsr::bt.intersect(a=InputBed,b=NegativeBed,s=FALSE,g=genome_file,sorted=T,f=0.5,wo=T) %>% as.data.table()
    #overlap of m6a with benchmark
    if(str_detect(s, "HEK")){
      SamplePositiveBed.list <- m6A.site.list[str_detect(names(m6A.site.list),"HEK")]}else{
        SamplePositiveBed.list <- m6A.site.list[str_detect(names(m6A.site.list),"mESC")]
      }
    dt.m6a.benchmark.overlap <- foreach(k = 1:length(SamplePositiveBed.list),.combine = 'rbind')%do%{
        bedtoolsr::bt.intersect(a=InputBed,b=SamplePositiveBed.list[[k]],F=1,wo=T,s=F,S=F) %>% as.data.table() %>% mutate(Benchmark=names(SamplePositiveBed.list)[k])
    }
    dt.TPR.FPR.IVT.divided <- foreach(fc=c(seq(0,fc.max,by=0.5)),.combine='rbind')%dopar%{
      #divide m6As into IVT+ and IVT- m6As
      dt.m6a.ivtplus <- dt.m6As.IVT.overlap %>% filter(V5>=fc & V11>=fc) %>% dplyr::select(V1:V6) %>% distinct()
      dt.m6a.ivtnega <- InputBed %>% filter(V5>=fc) %>% filter(!(V4 %in% dt.m6a.ivtplus$V4))
      #calculate TPR and FPR for IVT+ and IVT- m6As
      #TPR and FPR for all m6a
      dt.m6a.all <- rbind(dt.m6a.ivtnega,dt.m6a.ivtplus)
      if(nrow(dt.m6a.all)>0){
        dt.TPR.FPR.all <- foreach(b = unique(dt.m6a.benchmark.overlap$Benchmark),.combine='rbind')%do%{
          dt.m6a.all.benchmark.overlap <- dt.m6a.benchmark.overlap %>% filter(Benchmark==b & (V4 %in% dt.m6a.all$V4))
          TP <- dt.m6a.all.benchmark.overlap$V4 %>% unique() %>% length()
          FP <- nrow(dt.m6a.all) - TP
          TPR <- (dt.m6a.all.benchmark.overlap[,V10] %>% unique() %>% length())/nrow(SamplePositiveBed.list[[b]])#recall, or sensitivity
          FPR <- FP/(FP+TP)
          data.table(Sample=s,foldchange.cutoff=fc,IVTSample=ivt,Group="all",nPeak=nrow(dt.m6a.all),
                     Benchmark=b,TruePositiveRate=TPR, FalsePositiveRate=FPR,TruePositivePeak=TP)
        }
      }
      #TPR and FPR for IVT- m6a
      if(nrow(dt.m6a.ivtnega)>0){
        dt.TPR.FPR.ivtnega <- foreach(b = unique(dt.m6a.benchmark.overlap$Benchmark),.combine='rbind')%do%{
          dt.m6a.ivtnega.benchmark.overlap <- dt.m6a.benchmark.overlap %>% filter(Benchmark==b & (V4 %in% dt.m6a.ivtnega$V4))
          TP <- dt.m6a.ivtnega.benchmark.overlap$V4 %>% unique() %>% length()
          FP <- nrow(dt.m6a.ivtnega) - TP
          TPR <- (dt.m6a.ivtnega.benchmark.overlap[,V10] %>% unique() %>% length())/nrow(SamplePositiveBed.list[[b]])#recall, or sensitivity
          FPR <- FP/(FP+TP)
          data.table(Sample=s,foldchange.cutoff=fc,IVTSample=ivt,Group="IVT-",nPeak=nrow(dt.m6a.ivtnega),
                     Benchmark=b,TruePositiveRate=TPR, FalsePositiveRate=FPR,TruePositivePeak=TP)
        }
      }
      #TPR and FPR for IVT+ m6a
      if(nrow(dt.m6a.ivtplus)>0){
        dt.TPR.FPR.ivtplus <- foreach(b = unique(dt.m6a.benchmark.overlap$Benchmark),.combine='rbind')%do%{
          dt.m6a.ivtplus.benchmark.overlap <- dt.m6a.benchmark.overlap %>% filter(Benchmark==b & (V4 %in% dt.m6a.ivtplus$V4))
          TP <- dt.m6a.ivtplus.benchmark.overlap$V4 %>% unique() %>% length()
          FP <- nrow(dt.m6a.ivtplus) - TP
          TPR <- (dt.m6a.ivtplus.benchmark.overlap[,V10] %>% unique() %>% length())/nrow(SamplePositiveBed.list[[b]])#recall, or sensitivity
          FPR <- FP/(FP+TP)
          data.table(Sample=s,foldchange.cutoff=fc,IVTSample=ivt,Group="IVT+",nPeak=nrow(dt.m6a.ivtplus),
                     Benchmark=b,TruePositiveRate=TPR, FalsePositiveRate=FPR,TruePositivePeak=TP)
        }
      }
      rbind(dt.TPR.FPR.all, dt.TPR.FPR.ivtnega,dt.TPR.FPR.ivtplus) %>% dplyr::arrange(Sample,IVTSample,Benchmark)
    }
    dt.TPR.FPR.IVT.divided
  }
}
