dt.Method.intensity <- foreach(cell=c("HEK","mESC"),.combine='rbind')%do%{
  input.m6a <- dt.Method.BestCombo.m6A %>% filter(str_detect(Sample, cell) & str_detect(Sample,pattern="IVT",negate = T))
  #input.m6a <- input.m6a %>% filter(Method=="MACS2" & ComboName=="Combo41")
  foreach(a=unique(input.m6a$Antibody),.combine = 'rbind')%do%{
    input.m6a.sample = input.m6a %>% filter(Antibody==a)
    dt.intensity.sample <- foreach(intronremoved = c(TRUE,FALSE),.combine='rbind')%do%{
      dt.m6a.with.new.intensity <- NewIntensity(input.m6a.sample = input.m6a.sample,
                                                bamFolder = "/data/m6A_calling_strategy/7_MACS2SPeak/BAM/R1_bam/",#use R1, which is reverse to mRNA
                                                dt.BAM.Depth = dt.BAM.Depth.HEK.mESC,
                                                dir.tmp=paste0("/data/m6A_calling_strategy/Analysis/tmp_",cell,"_",a,"_",intronremoved),
                                                threads = 12,
                                                genome_file=paste0("~/genome_db/STAR_index/STAR_", ifelse(cell=="HEK", "hg38", "mm39"),"/chrNameLength.txt"),
                                                intronremoved = intronremoved,
                                                Pseudocount = c(2),
                                                SummaryMethod = c("max"),
                                                org = ifelse(cell=="HEK","hg38","mm39"))
      dt.m6a.with.new.intensity
    }
    saveRDS(dt.intensity.sample,file=paste0("dt.",cell,".",a,".Method.BestCombo.new.intensity.RDS"))
  }
}

