dt.TPR.FPR.new.intensity <- foreach(a=unique(dt.m6a.with.new.intensity$Antibody),combine='rbind')%do%{
  dt.TPR.FPR.antibody <- foreach(cell = dt.m6a.with.new.intensity[Antibody==a,unique(Cell)],.combine='rbind')%do%{
    if(str_detect(cell, "mESC")){benchmarks <- names(m6A.site.list) %>% grep(pattern="mESC",value=T)}else{benchmarks <- names(m6A.site.list) %>% grep(pattern="HEK",value=T)}
    dt.peak.cell <- dt.m6a.with.new.intensity %>% filter(Antibody==a & Cell==cell) %>% mutate(name=paste0(Sample,"|",name))
    dt.TPR.FPR.cell <- foreach(b=benchmarks,.combine = 'rbind')%do%{
      foreach(P=unique(dt.peak.cell$pseudocount),.combine='rbind')%do%{
        foreach(S=unique(dt.peak.cell$SummaryMethod),.combine='rbind')%do%{
          message(paste("start ", a, cell, b, P, S,sep=" "))
          # t1 <- Sys.time()
          dt.peak.new <-  dt.peak.cell %>% filter(pseudocount == P & SummaryMethod == S)
          # #add peak with enrichment >1.2x at both strand
          dt.miss.peak <-  dt.peak.new %>% filter(pos>=1.2 & neg>=1.2) %>% dplyr::arrange(name) %>% mutate(score.new = case_when(strand.new=="+" ~ neg, strand.new=="-" ~ pos)) %>%
            mutate(strand.new = case_when(strand.new=="+" ~ "-", strand.new=="-" ~ "+")) %>% mutate(name=paste0(name,"_",strand.new))
          dt.peak.new <- rbind(dt.peak.new, dt.miss.peak)
          dt.peak.new <- dt.peak.new %>% mutate(seqnames=name %>% strsplit(split="|",fixed = T) %>% sapply("[",4) %>% strsplit(split="_",fixed=T) %>% sapply("[",1),
                                                start=name %>% strsplit(split="|",fixed=T) %>% sapply("[",4) %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                                                end=name %>% strsplit(split="|",fixed=T) %>% sapply("[",4) %>% strsplit(split="_",fixed=T) %>% sapply("[",3),
                                                strand=strand.new,
                                                score=score.new) %>% dplyr::select(seqnames,start,end,name,score,strand,Sample,Method,ComboName)
          #obtain the overlap of benchmark and m6a
          dt.peak.benchmark.overlap <- bedtoolsr::bt.intersect(a=dt.peak.new, b=m6A.site.list[[b]][,1:6], s=T, S=F, wo=T) %>% as.data.table() %>% distinct()
          fc.cutoffs <- unlist(quantile(dt.peak.cell$score.new,seq(0,1,length.out=100)[1:99])) %>% unique()
          #obtain TPR and FPR use foldchange quantile as cutoffs
          registerDoParallel(cl=4)
          dt.TPR.FPR.new <- foreach(fc = fc.cutoffs,.combine='rbind')%dopar%{
            dt.overlap.filtered <- dt.peak.benchmark.overlap %>% filter(V5>=fc)
            dt.peakcount <- dt.peak.new[score>=fc,.(nPeak=n_distinct(name,score,strand)),by=.(Sample,Method,ComboName)]
            #benchmark for Sample x Method x Combo
            dt.TPR.FPR <- dt.overlap.filtered[,.(TP=n_distinct(V4,V5,V6), TP.sites=n_distinct(V13,V14,V15)),by=.(Sample=V7,Method=V8,ComboName=V9)] %>%
              left_join(x=.,y=dt.peakcount,by=c("Sample","Method","ComboName")) %>%
              mutate(foldchange.cutoff = fc,FPR=1-TP/nPeak, TPR=TP.sites/nrow(m6A.site.list[[b]]))
            dt.TPR.FPR
          }
          stopImplicitCluster()
          #Sys.time()-t1
          dt.TPR.FPR.new %>% mutate(Antibody=a, Cell=cell, Benchmark=b, Pseudocount=P, SummaryMethod=S)
        }
      }
    }
    dt.TPR.FPR.cell
  }
  saveRDS(dt.TPR.FPR.antibody, file=paste0("dt.",a,"Method.BestCombo.peak.intensity.FRR.TPR.RDS"))
  dt.TPR.FPR.antibody
}
saveRDS(dt.TPR.FPR.new.intensity,file="dt.Method.BestCombo.peak.intensity.FRR.TPR.RDS")

