  dt.Method.pruned.TPR.FPR.new.intensity  <- dt.pruned.TPR.FPR.new.intensity %>% filter(Method==M) %>% mutate(Combo=paste0(Method,"|",ComboName,"_","P",Pseudocount,"_",SummaryMethod))
