    inner_join(x=.,y=dt.Method.pruned.TPR.FPR.new.intensity %>% distinct(Method,ComboName,Antibody)) %>% mutate(Combo=paste0(Method,"|",ComboName))
  #combine new TPR/FPR and old TPR/FPR together
  dt.Method.pruned.TPR.FPR.combined <- list(dt.Method.pruned.TPR.FPR.new.intensity %>% dplyr::select(Method,ComboName,Combo,Antibody,Cell,Benchmark,AUC0.5,TPR_FPR50, maxTPR,maxTPRmFPR,cutoff,FPR,TPR,TPRmFPR),
                                            dt.Method.pruned.TPR.FPR.old %>% dplyr::select(Method,ComboName,Combo,Antibody,Cell,Benchmark,AUC0.5,TPR_FPR50, maxTPR,maxTPRmFPR,cutoff,FPR,TPR,TPRmFPR)) %>% Reduce(x=.,rbind)
  dt.Method.pruned.TPR.FPR.combined <- dt.Method.pruned.TPR.FPR.combined %>% mutate(Cell=case_when(str_detect(Cell,"HEK") ~ "HEK293", str_detect(Cell,"mESC") ~ "mESC"))
