                                  Highlight=FALSE)
  old.best.combo.NEB <- readRDS("dt.Method.BestCombo.TPR.FPR.AUC.RDS") %>% dplyr::select(Method,Antibody,ComboName) %>% distinct() %>%
    filter(Method==M & Antibody=="NEB") %>% distinct(ComboName,Antibody) %>% filter(Antibody=="NEB")
  dt.Method.Combo.color[Combo %in% paste0(M,"|",old.best.combo.NEB$ComboName), `:=`(Color = "#1a80bb", Highlight=TRUE)] #original best combo
  dt.Method.Combo.color[Combo %in% dt.pruned.TPR.FPR.topAUC.new.intensity[Antibody=="NEB" & Method==M,unique(Combo)], `:=`(Color = "#a00000", Highlight=TRUE)]#new best combo

  dt.highlight.combo.auc <- dt.Method.pruned.TPR.FPR.combined %>% filter(Method== M & Antibody=="NEB" & str_detect(Benchmark,"GLORI")) %>%
