    dplyr::select(Method,Antibody,Benchmark,Combo,ComboName,Cell,contains("AUC")) %>% mutate(AUC.scaled=round(AUC0.5/0.5,2)) %>% distinct() %>%
    inner_join(x=.,y=dt.Method.Combo.color %>% dplyr::select(Method,Combo,Color)) %>% mutate(Cell=case_when(str_detect(Cell,"HEK") ~ "HEK293", str_detect(Cell,"mESC") ~ "mESC")) %>%
    group_by(Cell) %>% dplyr::arrange(desc(AUC.scaled)) %>% mutate(ypos=seq(0.9,0.7,-0.1)[1:n()],xpos=0.5, label=ifelse(str_detect(Combo,"_"),paste0("NewBest:",Combo,":ScaledAUC=",AUC.scaled),
                                                                                                               paste0("OldBest:",Combo,":ScaledAUC=",AUC.scaled))) %>% as.data.table() %>%
    dplyr::arrange(Cell,desc(AUC.scaled))

