dt.TPR.FPR.new.intensity <- readRDS("dt.Method.BestCombo.peak.intensity.FRR.TPR.RDS")
dt.pruned.TPR.FPR.topAUC.new.intensity <- readRDS("dt.BestCombo.pruned.TPR.FPR.AUC.new.intensity.RDS")


#load new intensity of best combo
dt.m6a.with.new.intensity <- readRDS("dt.Method.BestCombo.new.intensity.RDS")
dt.BestCombo.m6a.new.intensity <- dt.m6a.with.new.intensity %>% mutate(Combo=paste0(Method,"|",ComboName,"_P",pseudocount,"_",SummaryMethod)) %>%
                                inner_join(x=.,y=dt.pruned.TPR.FPR.topAUC.new.intensity %>% distinct(Antibody,Method,ComboName,Combo))

#the optimal new intensity cutoff for each combo according to AUC curve under GLORI_HEK293(which might be most close to true positive)
dt.pruned.TPR.FPR.topAUC.new.intensity %>% group_by(Antibody,Cell,Benchmark,Method,Combo) %>% filter(TPRmFPR==maxTPRmFPR) %>% slice_max(TPR) %>% as.data.table() %>%
  filter(Benchmark=="GLORI_HEK293")
dt.pruned.TPR.FPR.topAUC.new.intensity %>% group_by(Antibody,Cell,Benchmark,Method,Combo) %>% slice_min(abs(FPR-0.15))  %>% as.data.table() %>%
  filter(Benchmark=="GLORI_HEK293")

#compare the peak statistic of each combo under best optimal cutoff
dt.BestCombo.m6a.foldchange.cutoff <- dt.pruned.TPR.FPR.topAUC.new.intensity %>% group_by(Antibody,Cell,Benchmark,Method,Combo) %>%
  filter(TPRmFPR==maxTPRmFPR) %>% slice_max(TPR) %>% as.data.table() %>% filter(Benchmark=="GLORI_HEK293")
# dt.BestCombo.m6a.foldchange.cutoff.mean <- dt.BestCombo.m6a.foldchange.cutoff %>% filter(TPRmFPR>=0.03) %>% group_by(Antibody) %>% mutate(cutoff.avg=round(mean(cutoff),2)) %>%
#   as.data.table() %>% distinct(Antibody,cutoff.avg)
# dt.BestCombo.m6a.foldchange.cutoff %>% filter(TPRmFPR<0.03) %>% dplyr::select(Antibody,Cell,Benchmark,Method,ComboName,Combo) %>% inner_join(x=.,y=dt.BestCombo.m6a.foldchange.cutoff.mean) %>%
#   inner_join(x=.,y=dt.pruned.TPR.FPR.topAUC.new.intensity) %>% group_by(Antibody,Cell,Benchmark,Method,Combo) %>% slice_min(abs(cutoff-cutoff.avg))

dt.BestCombo.m6a.foldchange.cutoff %>% distinct(Antibody,cutoff,Combo)
dt.BestCombo.m6a.optimalcutoff <- dt.BestCombo.m6a.foldchange.cutoff %>% filter(TPRmFPR>=0.03) %>% dplyr::select(Antibody,Method,Combo,cutoff,FPR,TPR,TPRmFPR,maxTPRmFPR,maxTPR) %>%
  inner_join(x=.,y=dt.BestCombo.m6a.new.intensity) %>% filter(score.new > cutoff)
dt.BestCombo.m6a.optimalcutoff[,list(nPeak=.N,FPR,TPR),by=.(Sample,Antibody,Method,Combo)] %>% dplyr::arrange(Antibody,Sample,Method,Combo) %>% distinct()

#check the peak width of top Combo of each method
dt.BestCombo.m6a.optimalcutoff.peak.width <- foreach(a = unique(dt.BestCombo.m6a.optimalcutoff$Antibody),.combine='rbind')%do%{
  foreach(cell = dt.BestCombo.m6a.optimalcutoff[Antibody==a,unique(Cell)],.combine = 'rbind')%do%{
    dt.m6a <- dt.BestCombo.m6a.optimalcutoff[Antibody==a & Cell==cell,.(name,strand.new,score.new,Sample,Combo,Method,Antibody,Cell)] %>% mutate(name.inter=strsplit(name,"|",fixed=T) %>% sapply("[",3))
    dt.m6a <- dt.m6a %>% mutate(seqnames=name.inter %>% strsplit(split="_",fixed=T) %>% sapply("[",1), start=name.inter %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                                  end=name.inter %>% strsplit(split="_",fixed=T) %>% sapply("[",3),score=score.new, strand=strand.new) %>%
      dplyr::select(seqnames,start,end,name,score,strand,Sample,Antibody,Cell,Combo,Method) %>% mutate(name=paste0(Sample,"|",name))
    if(str_detect(cell,"mESC")){
      dt.m6a.with.width <- LongPeakRemoveIntron(dt.peak=dt.m6a[,1:6],genome_file = "~/genome_db/STAR_index/STAR_mm39/chrNameLength.txt",
                                                 dt.intron = readRDS("dt.intron.mm39.RDS"))
    }else{
      dt.m6a.with.width <- LongPeakRemoveIntron(dt.peak=dt.m6a[,1:6],genome_file = "~/genome_db/STAR_index/STAR_hg38/chrNameLength.txt",
                                                dt.intron = readRDS("dt.intron.hg38.RDS"))
    }
    dt.m6a <- dt.m6a %>% left_join(x=.,y=dt.m6a.with.width %>% dplyr::select(name,strand,SumWidth) %>% distinct())
    dt.m6a[is.na(SumWidth),SumWidth := 0]
    dt.m6a <- dt.m6a %>% mutate(Width=as.integer(end)-as.integer(start))
    dt.m6a
  }
}

dt.BestCombo.m6a.optimalcutoff.peak.width %>% distinct(Cell,Sample,Combo)
