source("/data/m6A_calling_strategy/Script/Wrapper_function_for_m6A_calling_using_MACS2SMePeak.R")

#load best combo: exomePeak2_Combo35 and others
dt.Method.BestCombo.m6A <- readRDS("dt.Method.BestCombo.m6A.RDS")
dt.pruned.TPR.FPR.topAUC.new.intensity <- readRDS("dt.BestCombo.pruned.TPR.FPR.AUC.new.intensity.RDS")
dt.pruned.TPR.FPR.topAUC.new.intensity %>% distinct(Antibody,Method,ComboName,Combo) %>% dplyr::arrange(Method,Antibody)
dt.Method.BestCombo.m6A %>% distinct(Antibody,Method,ComboName)
dt.Method.BestCombo.m6A <- dt.Method.BestCombo.m6A %>% inner_join(x=.,y=dt.pruned.TPR.FPR.topAUC.new.intensity %>% distinct(Antibody,Method,ComboName))
dt.Method.BestCombo.m6A %>% distinct(Antibody,Method,ComboName)
dt.Method.BestCombo.m6A <- dt.Method.BestCombo.m6A %>% mutate(Cell = dplyr::case_when(str_detect(Sample,"mESC") ~ "mESC", str_detect(Sample,"HEK") ~ "HEK293"))
#depth for all sample
dt.BAM.Depth.HEK.mESC <- {
  BAMs <- list.files(path="/data/m6A_calling_strategy/7_MACS2SPeak/BAM/R1_bam/",pattern = '(bam)$',full.names = T)
  names(BAMs) <- list.files(path="/data/m6A_calling_strategy/7_MACS2SPeak/BAM/R1_bam/",pattern = '(bam)$',full.names = F) %>% strsplit(split=".",fixed=T) %>% sapply("[",1)
  names(BAMs) <- names(BAMs) %>% str_replace(pattern="_Input",replacement = "") %>% str_replace(pattern="_RIP",replacement = "")
  BAMs <- BAMs[names(BAMs) %in% (unique(dt.Method.BestCombo.m6A$Sample) %>% grep(pattern="IVT",value=T,invert=T))]
  CalculateMappedReadParallel(n.cores = 20,
                              BAMs = BAMs,
                              samtools_path="~/anaconda3/envs/m6A_seq/bin/"
  )
} %>% mutate(Replicate=Sample %>% str_replace(pattern="_Input",replacement="") %>% str_replace(pattern="_RIP",replacement=""))

# input.m6a = dt.Method.BestCombo.m6A %>% filter(Method=="exomePeak2" & ComboName=="Combo35" & str_detect(Sample,pattern="IVT",negate = T)) %>%
#             group_by(Sample) %>% slice_sample(prop=0.1) %>% as.data.table()
input.m6a = dt.Method.BestCombo.m6A %>% filter(str_detect(Sample,pattern="IVT",negate = T))
t1 <- Sys.time()
dt.BestCombo.m6a.new.intensity <- foreach(cell = unique(dt.Method.BestCombo.m6A$Cell),.combine = 'rbind')%do%{
  input.m6a.cell <- input.m6a %>% filter(Cell==cell)
  foreach(i = c(TRUE,FALSE),.combine='rbind')%do%{ #intron remove
    dt.intensity.cell <- foreach(o = c(" -split -counts ", " -split -mean "), .combine='rbind')%do%{ #coverage mode
      foreach(b = c(0,500,100), .combine='rbind')%do%{ #bin size
        message(paste0("start new intensity base on intronremoved", i, " coverageOption", o, " bin", b, " of ", cell))

        if(cell=="mESC"){
          dt.new.intensity <- BedtoolsIntensity(input.m6a.sample = input.m6a.cell,
                            dt.BAM.Depth = dt.BAM.Depth.HEK.mESC,
                            bamFolder = "/data/m6A_calling_strategy/7_MACS2SPeak/BAM/R1_bam/",#use R1, which is reverse to mRNA
                            dir.tmp=paste0("/data/m6A_calling_strategy/Analysis/tmp","_",cell,"_",i),
                            threads = 12,
                            genome_file=paste0("~/genome_db/STAR_index/STAR_", c("hg38","mm39"),"/chrNameLength.txt")[2],
                            intronremoved = i,
                            bedtools_option= o,
                            binsize=b,
                            Pseudocount=c(1,2),
                            SummaryMethod="max",
                            org = c("hg38","mm39")[2]
                            )
        }else{
         dt.new.intensity <-  BedtoolsIntensity(input.m6a.sample = input.m6a.cell,
                            dt.BAM.Depth = dt.BAM.Depth.HEK.mESC,
                            bamFolder = "/data/m6A_calling_strategy/7_MACS2SPeak/BAM/R1_bam/",#use R1, which is reverse to mRNA
                            dir.tmp=paste0("/data/m6A_calling_strategy/Analysis/tmp","_",cell,"_",i),
                            threads = 12,
                            genome_file=paste0("~/genome_db/STAR_index/STAR_", c("hg38","mm39"),"/chrNameLength.txt")[1],
                            intronremoved = i,
                            bedtools_option= o,
                            binsize=b,
                            Pseudocount=c(1,2),
                            SummaryMethod="max",
                            org = c("hg38","mm39")[1]
                            )
        }
        dt.new.intensity %>% mutate(intronremove =i, coverageOption=o, binsize=b,Cell=cell)
      }
    }
    dt.intensity.cell
  }
}
