#benchmark with new intensity
dt.HEK293.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.HEK293.benchmark.m6As.RDS")
dt.mESC.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.mESC.benchmark.m6As.RDS")
dt.benchmark.m6As <- rbind(dt.HEK293.benchmark.m6As,dt.mESC.benchmark.m6As)
m6A.site.list <- foreach(i=unique(dt.benchmark.m6As$Sample))%do%{dt.benchmark.m6As[Sample==i,1:6]}
names(m6A.site.list) <- unique(dt.benchmark.m6As$Sample)
dt.BestCombo.m6a.new.intensity <- readRDS("dt.BestCombo.m6a.new.intensity.alternative.bedtools.option.RDS")
dt.option.ID <- dt.BestCombo.m6a.new.intensity %>% distinct(coverageOption, Intronremoved, binsize, SummaryMethod,pseudocount)
dt.option.ID <- dt.option.ID %>% mutate(OptionID = paste0(strsplit(coverageOption,split="-",fixed=T) %>% sapply(tail,1), "IntronRemove ", Intronremoved, " bin ",binsize, " P ",pseudocount))
dt.TPR.FPR.BestCombo.new.intensity <- foreach(a=unique(dt.BestCombo.m6a.new.intensity$Antibody),.combine='rbind')%do%{
  cells <- dt.BestCombo.m6a.new.intensity[Antibody==a,unique(Cell)]
  dt.TPR.FPR.antibody <- foreach(cell = cells,.combine='rbind')%do%{
    if(str_detect(cell, "mESC")){benchmarks <- names(m6A.site.list) %>% grep(pattern="mESC",value=T)}else{benchmarks <- names(m6A.site.list) %>% grep(pattern="HEK",value=T)}
    dt.peak.cell <- dt.BestCombo.m6a.new.intensity %>% dplyr::filter(Antibody==a & Cell==cell) %>% mutate(name=paste0(Sample,"|",name))
    #dt.peak.cell <- dt.peak.cell %>% group_by(Sample) %>% slice_sample(prop = 0.01) %>% as.data.table()
    dt.peak.cell <- dt.peak.cell %>% left_join(x=.,y=dt.option.ID,by=c("pseudocount", "SummaryMethod", "Intronremoved", "coverageOption", "binsize"))
    dt.TPR.FPR.cell <- foreach(b=benchmarks,.combine = 'rbind')%do%{
      foreach(Option=unique(dt.peak.cell$OptionID),.combine='rbind')%do%{
          message(paste("start ", b, "based benchmark", a, cell, "at bedtools coverage option:",Option,sep=" "))
          # t1 <- Sys.time()
          dt.peak.new <-  dt.peak.cell %>% dplyr::filter(OptionID==Option)
          # #add peak with enrichment >1.2x at both strand
          dt.miss.peak <-  dt.peak.new %>% dplyr::filter(pos>=1.2 & neg>=1.2) %>% dplyr::arrange(name) %>% mutate(score.new = case_when(strand.new=="+" ~ neg, strand.new=="-" ~ pos)) %>%
            mutate(strand.new = case_when(strand.new=="+" ~ "-", strand.new=="-" ~ "+")) %>% mutate(name=paste0(name,"_",strand.new))
          dt.peak.new <- rbind(dt.peak.new, dt.miss.peak)
          dt.peak.new <- dt.peak.new %>% mutate(seqnames=name %>% strsplit(split="|",fixed = T) %>% sapply("[",5) %>% strsplit(split="_",fixed=T) %>% sapply("[",1),
                                                start=name %>% strsplit(split="|",fixed=T) %>% sapply("[",5) %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                                                end=name %>% strsplit(split="|",fixed=T) %>% sapply("[",5) %>% strsplit(split="_",fixed=T) %>% sapply("[",3),
                                                strand=strand.new,
                                                score=score.new) %>% dplyr::select(seqnames,start,end,name,score,strand,Sample)
          dt.peak.new <- dt.peak.new %>% mutate(Method=name %>% strsplit(split="|",fixed=T) %>% sapply("[",3),
                                                ComboName=name %>% strsplit(split="|",fixed=T) %>% sapply("[",4))
          #obtain the overlap of benchmark and m6a
          dt.peak.benchmark.overlap <- bedtoolsr::bt.intersect(a=dt.peak.new, b=m6A.site.list[[b]][,1:6], s=T, S=F, wo=T) %>% as.data.table() %>% distinct()
          fc.cutoffs <- unlist(quantile(dt.peak.cell$score.new,seq(0,1,length.out=100)[1:99])) %>% unique()
          #obtain TPR and FPR use foldchange quantile as cutoffs
          registerDoParallel(cl=4)
          dt.TPR.FPR.new <- foreach(fc = fc.cutoffs,.combine='rbind')%dopar%{
            dt.overlap.filtered <- dt.peak.benchmark.overlap %>% dplyr::filter(V5>=fc)
            dt.peakcount <- dt.peak.new[score>=fc,.(nPeak=n_distinct(name,score,strand)),by=.(Sample,Method,ComboName)]
            #benchmark for Sample x Method x Combo
            dt.TPR.FPR <- dt.overlap.filtered[,.(TP=n_distinct(V4,V5,V6), TP.sites=n_distinct(V13,V14,V15)),by=.(Sample=V7,Method=V8,ComboName=V9)] %>%
              left_join(x=.,y=dt.peakcount,by=c("Sample","Method","ComboName")) %>%
              mutate(foldchange.cutoff = fc,FPR=1-TP/nPeak, TPR=TP.sites/nrow(m6A.site.list[[b]]))
            dt.TPR.FPR
          }
          stopImplicitCluster()
          #Sys.time()-t1
          dt.TPR.FPR.new %>% mutate(Antibody=a, Cell=cell, Benchmark=b, OptionID=Option)
      }
    }
    dt.TPR.FPR.cell
    # dt.TPR.FPR.cell %>% group_by(OptionID,Method,ComboName,Sample) %>% mutate(maxTPRmFPR=max(TPR-FPR)) %>% dplyr::filter(TPR-FPR==maxTPRmFPR) %>% as.data.table() %>%
    #                 dplyr::arrange(desc(maxTPRmFPR))
  }
  #saveRDS(dt.TPR.FPR.antibody, file=paste0("dt.",a,"Method.BestCombo.peak.intensity.FRR.TPR.RDS"))
  dt.TPR.FPR.antibody
}

