dt.pruned.TPR.FPR.new.intensity <- foreach(a = unique(dt.TPR.FPR.new.intensity$Antibody),.combine='rbind')%do%{
  foreach(c=dt.TPR.FPR.new.intensity[Antibody==a,unique(Cell)],.combine='rbind')%do%{
    dt.TPR.FPR.sample <- dt.TPR.FPR.new.intensity[Antibody==a & Cell==c,]
    foreach(M = unique(dt.TPR.FPR.sample$Method),.combine = 'rbind')%do%{
      foreach(combo = dt.TPR.FPR.sample[Method == M,unique(ComboName)], .combine='rbind')%do%{
        message(paste0("start FPR/TPR prune for ", a, " ", c, " for ", M, " ", combo))
        dt.pruned.TPR.FPR.sample <- foreach(O=unique(dt.TPR.FPR.sample$OptionID),.combine='rbind')%do%{
            foreach(b=unique(dt.TPR.FPR.sample$Benchmark),.combine='rbind')%do%{
              TPR.FPR.pruned(dt.TPR.FPR.fc = dt.TPR.FPR.sample[Method == M & ComboName == combo & OptionID==O & Benchmark==b,.(FPR=FPR.avg, TPR=TPR.avg, cutoff=foldchange.cutoff)],step=0.01) %>%
                mutate(Antibody=a,Cell=c, Method = M, ComboName = combo, OptionID=O, Benchmark=b)
            }
        }
        dt.pruned.TPR.FPR.sample
      }
    }
  }
}

