source("/data/m6A_calling_strategy/Script/Wrapper_function_for_m6A_calling_using_MACS2SMePeak.R")
dt.BestOption.m6a <- readRDS("dt.Method.BestOption.m6As.RDS")
dt.BestOption.pruned.TPR.FPR <- readRDS(file="dt.Method.BestOption.AUC.pruned.TPR.FPR.RDS")
dt.HEK293.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.HEK293.benchmark.m6As.RDS")
dt.mESC.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.mESC.benchmark.m6As.RDS")
dt.benchmark.m6As <- rbind(dt.HEK293.benchmark.m6As,dt.mESC.benchmark.m6As)
m6A.site.list <- foreach(i=unique(dt.benchmark.m6As$Sample))%do%{dt.benchmark.m6As[Sample==i,1:6]}
names(m6A.site.list) <- unique(dt.benchmark.m6As$Sample)
FPR.ranges <- c(seq(0.01,0.6,by=0.01),seq(0.6,1,by=0.05)) %>% unique()
#obtain peak intensity cutoff for target FPR (GLORI_HEK293 as benchmark) under Antibody x Combo
dt.fc.cutoff.all <- foreach(f=FPR.ranges,.combine='rbind')%do%{
  dt.BestOption.pruned.TPR.FPR %>% dplyr::filter(FPR <= f & Benchmark == "GLORI_HEK293") %>% group_by(Antibody,Combo) %>%
    slice_max(TPR,n = 1) %>% slice_min(FPR,n=1) %>% as.data.table() %>% dplyr::select(Antibody, Combo,cutoff) %>%
    dplyr::filter(!is.na(cutoff)) %>% dplyr::arrange(Antibody,Combo) %>% mutate(TargetedFPR=f)
}

t1 <- Sys.time()
dt.TPR.FPR.Merged.BestOption <- foreach(f = FPR.ranges,.combine='rbind')%do%{
  foreach(cell = c("mESC","HEK293"), .combine='rbind')%do%{
      message(paste0("start method integration under FPR", f,  " for ", cell))
      #determine the corresponding cutoff for each combo
      dt.fc.cutoff <- dt.BestOption.pruned.TPR.FPR %>% dplyr::filter(FPR <= f & Benchmark == "GLORI_HEK293") %>% group_by(Antibody,Combo) %>%
        slice_max(TPR,n = 1) %>% slice_min(FPR,n=1) %>% as.data.table() %>% dplyr::select(Antibody, Combo,cutoff) %>%
        dplyr::filter(!is.na(cutoff)) %>% dplyr::arrange(Antibody,Combo) %>% mutate(TargetedFPR=f)
      if(nrow(dt.fc.cutoff)>0){
        #pull out best option m6as
        dt.m6a.fc.cutoff <- dt.BestOption.m6a %>% dplyr::filter(Cell==cell) %>% left_join(x=.,y=dt.fc.cutoff %>% dplyr::select(Antibody,Combo,cutoff))
        dt.m6a.fc.cutoff <- dt.m6a.fc.cutoff %>% dplyr::filter(pos >= cutoff | neg >= cutoff)
        dt.m6a.missed <- dt.m6a.fc.cutoff %>% dplyr::filter(pos >= cutoff & neg >= cutoff) %>% dplyr::arrange(name) %>%
          mutate(score.new = case_when(strand.new=="+" ~ neg, strand.new=="-" ~ pos)) %>%
          mutate(strand.new = case_when(strand.new=="+" ~ "-", strand.new=="-" ~ "+")) %>% mutate(name=paste0(name,"_",strand.new))
        dt.m6a.fc.cutoff <- rbind(dt.m6a.fc.cutoff, dt.m6a.missed)
        dt.m6a.fc.cutoff <- dt.m6a.fc.cutoff %>% mutate(seqnames=name %>% strsplit(split="|",fixed = T) %>% sapply("[",4) %>% strsplit(split="_",fixed=T) %>% sapply("[",1),
                                                        start=name %>% strsplit(split="|",fixed=T) %>% sapply("[",4) %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                                                        end=name %>% strsplit(split="|",fixed=T) %>% sapply("[",4) %>% strsplit(split="_",fixed=T) %>% sapply("[",3),
                                                        strand=strand.new,
                                                        score=score.new) %>% dplyr::select(seqnames,start,end,name,score,strand,Sample,Combo)
        #merge peaks to obtain new peaks; alternative get the intersect (n>=2, 3, 4)
        dt.m6a.sorted <- bt.sort(dt.m6a.fc.cutoff)
        colnames(dt.m6a.sorted) <- colnames(dt.m6a.fc.cutoff)

        #calculate the intron removed width of m6a before merged
        dt.sorted.m6a.intronremove <- LongPeakRemoveIntron(dt.peak = dt.m6a.sorted,
                                                           dt.intron = readRDS(file = ifelse(str_detect(cell,"mESC"),"dt.intron.mm39.RDS","dt.intron.hg38.RDS")),
                                                           genome_file = ifelse(str_detect(cell,"mESC"),"~/genome_db/STAR_index/STAR_mm39/chrNameLength.txt","~/genome_db/STAR_index/STAR_hg38/chrNameLength.txt")
        )
        dt.m6a.sorted <- dt.m6a.sorted %>% left_join(x=.,y=dt.sorted.m6a.intronremove %>% distinct(name,Combo,Sample,SumWidth))
        #remove extreme long peaks during benchmark
        foreach(ExtremeLong = c(6000),.combine='rbind')%do%{
          #remove extremelong peaks (exonic sumwidth >= 2 * q95 of tx length= 12k)
          dt.m6a.unmerged <- dt.m6a.sorted %>% dplyr::filter(SumWidth <= ExtremeLong)
          dt.sorted.m6a.exonic.width <- dt.sorted.m6a.intronremove %>% distinct(name,Combo,Sample,SumWidth) %>% dplyr::filter(SumWidth<=ExtremeLong) %>% group_by(Combo) %>%
            summarise(quantile=paste0("q",seq(0,1,0.1)),SumWidth.quantile=quantile(SumWidth,probs=seq(0,1,0.1))) %>%
            pivot_wider(id_cols = c("Combo"),values_from = c("SumWidth.quantile"),names_from = c("quantile")) %>% as.data.table()
          #merge method m6as together
          dt.merged.m6a <- foreach(sam=unique(dt.m6a.unmerged$Sample),.combine='rbind')%do%{
            foreach(s = c("+","-"), .combine='rbind')%do%{
              bt.merge(dt.m6a.unmerged %>% dplyr::filter(Sample==sam & strand==s), s = T, d = 10) %>% as.data.table() %>% mutate(Sample=sam, strand = s)
            }
          }
          dt.merged.m6a <- dt.merged.m6a %>% mutate(seqnames=V1, start=V2,end=V3,score=1000) %>% mutate(name=paste0("FPR",f,"|",Sample,"|",paste(seqnames,start,end,strand,sep="_"))) %>%
            dplyr::select(seqnames,start,end,name,score,strand,Sample)
          #intron-remove merge m6a
          dt.merged.m6a.intronremove <- LongPeakRemoveIntron(dt.peak = dt.merged.m6a,
                                                             dt.intron = readRDS(file = ifelse(str_detect(cell,"mESC"),"dt.intron.mm39.RDS","dt.intron.hg38.RDS")),
                                                             genome_file = ifelse(str_detect(cell,"mESC"),"~/genome_db/STAR_index/STAR_mm39/chrNameLength.txt","~/genome_db/STAR_index/STAR_hg38/chrNameLength.txt"))
          dt.merged.m6a.exonic.width <- dt.merged.m6a.intronremove %>% distinct(name,Sample,SumWidth) %>% dplyr::filter(SumWidth<=ExtremeLong) %>%
            summarise(quantile=paste0("q",seq(0,1,0.1)),SumWidth.quantile=quantile(SumWidth,probs=seq(0,1,0.1))) %>% mutate(Combo="Merged") %>%
            pivot_wider(id_cols = c("Combo"),values_from = c("SumWidth.quantile"),names_from = c("quantile")) %>% as.data.table()
          dt.merged.m6a <- dt.merged.m6a %>% left_join(x=.,y=dt.merged.m6a.intronremove %>% distinct(name,Sample,SumWidth)) %>% dplyr::filter(SumWidth<=ExtremeLong)
          # benchmark of merged m6a
          foreach(b=unique(dt.BestOption.pruned.TPR.FPR[Cell==cell,Benchmark]), .combine='rbind')%do%{
            dt.merged.peak.benchmark.overlap <- bedtoolsr::bt.intersect(a=dt.merged.m6a, b=m6A.site.list[[b]][,1:6], s=T, wo=T) %>% as.data.table() %>% distinct()
            dt.merged.peakcount <- dt.merged.m6a[,.(nPeak=n_distinct(name,score,strand)),by=.(Sample)]
            dt.merged.TPR.FPR <- dt.merged.peak.benchmark.overlap[,.(TP=n_distinct(V4,V5,V6), TP.sites=n_distinct(V11,V12,V13)),by=.(Sample=V7)] %>%
              left_join(x=.,y=dt.merged.peakcount,by=c("Sample")) %>% mutate(FPR=1-TP/nPeak, TPR=TP.sites/nrow(m6A.site.list[[b]]))
            #benchmark of method m6a
            dt.unmerged.peak.benchmark.overlap <- bedtoolsr::bt.intersect(a=dt.m6a.unmerged, b=m6A.site.list[[b]][,1:6], s=T, wo=T) %>% as.data.table() %>% distinct()
            dt.unmerged.peakcount <- dt.m6a.unmerged %>% group_by(Sample,Combo) %>% mutate(nPeak=n()) %>% distinct(Sample,Combo,nPeak) %>% as.data.table()
            dt.unmerged.TPR.FPR <- dt.unmerged.peak.benchmark.overlap[,.(TP=n_distinct(V4,V5,V6), TP.sites=n_distinct(V13,V14,V15)),by=.(Sample=V7,Combo=V8)] %>%
              left_join(x=.,y=dt.unmerged.peakcount,by=c("Sample","Combo")) %>% mutate(FPR=1-TP/nPeak, TPR=TP.sites/nrow(m6A.site.list[[b]]))
            #merged the performance together
            rbind(dt.unmerged.TPR.FPR, dt.merged.TPR.FPR %>% mutate(Combo=paste0("Merged_FPR",f))) %>% dplyr::arrange(Sample,desc(TPR)) %>%
              mutate( Benchmark=b, TargetedFPR=f, ExtremeLongPeak=ExtremeLong)
          }
        }
    }
  }
}
Sys.time()-t1
saveRDS(dt.TPR.FPR.Merged.BestOption, file="dt.TPR.FPR.Merged.BestOption.RDS")

