  distinct(Antibody,Cell,Combo,cutoff,TargetedFPR,Benchmark,TPR.avg,FPR.avg) %>% as.data.table()
dt.TPR.FPR.Merged.BestOption <- dt.TPR.FPR.Merged.BestOption %>% mutate(Combo = strsplit(Combo,split="_FPR",fixed=T) %>% sapply("[",1)) %>%
  mutate(Combo=case_when(Combo=="Merged" ~ "BestOption_Merged", .default = Combo))
attr(dt.TPR.FPR.Merged.BestOption,"groups") <- NULL
attr(dt.TPR.FPR.Merged.BestOption,"index") <- NULL
dt.TPR.FPR.Merged.BestOption <- dt.TPR.FPR.Merged.BestOption %>% mutate(cutoff=case_when(is.na(cutoff) & Combo == "BestOption_Merged" ~ TargetedFPR, .default = cutoff))
#prune TPR and FPR
dt.pruned.TPR.FPR.Merged.BestOption <- foreach(a = unique(dt.TPR.FPR.Merged.BestOption$Antibody),.combine='rbind')%do%{
  foreach(cell=unique(dt.TPR.FPR.Merged.BestOption[Antibody==a,Cell]), .combine='rbind')%do%{
    foreach(c = unique(dt.TPR.FPR.Merged.BestOption[Antibody == a & Cell == cell, Combo]), .combine='rbind')%do%{
      foreach(b = unique(dt.TPR.FPR.Merged.BestOption[Cell == cell, Benchmark]), .combine='rbind')%do%{
        message(paste0("start prune TPR/FPR for ", a, " ", cell, " ", c, " based on ", b))
        TPR.FPR.pruned(dt.TPR.FPR.fc = dt.TPR.FPR.Merged.BestOption[Antibody==a & Cell==cell & Combo==c & Benchmark==b,.(FPR=FPR.avg, TPR=TPR.avg, cutoff)],step=0.01) %>%
          mutate(Antibody=a,Cell=cell, Combo=c, Benchmark=b)
      }
    }
  }
}
