#obtain the best cutoff
dt.TPRmFPR.RIPPeakS <- dt.pruned.TPR.FPR.Merged.BestOption %>% dplyr::filter(Combo=="BestOption_Merged" & Benchmark == "GLORI_HEK293") %>% mutate(TPRmFPR=TPR-FPR) %>%
  group_by(Antibody) %>% mutate(maxTPRmFPR=max(TPRmFPR)) %>% mutate(near.maxTPRmFPR=TPRmFPR>=maxTPRmFPR-0.02) %>% as.data.table()
dt.highlight.cutoff.RIPPeaks <- list(dt.TPRmFPR.RIPPeakS %>% dplyr::filter(near.maxTPRmFPR) %>% group_by(Antibody) %>% slice_max(TPR) %>% as.data.table() %>% mutate(Mode="Sensitive"),
                            dt.TPRmFPR.RIPPeakS %>% dplyr::filter(near.maxTPRmFPR) %>% group_by(Antibody) %>% slice_min(FPR) %>% as.data.table() %>% mutate(Mode="Strict")) %>% Reduce(x=.,rbind) %>%
  mutate(Label=paste0("FPR:",FPR,",FPR",TPR))
dt.cutoff.RIPPeaks <- dt.highlight.cutoff.RIPPeaks %>% distinct(Combo,Antibody,Mode,cutoff)
dt.TPR.FPR.RIPPeakS <- dt.TPR.FPR.Merged.BestOption %>% dplyr::filter(Combo=="BestOption_Merged") %>% mutate(cutoff=round(cutoff,2)) %>%
  left_join(x=.,y=dt.cutoff.RIPPeaks %>% mutate(cutoff=round(cutoff,2)), by=c("Antibody","Combo","cutoff")) %>%
  mutate(TPRmFPR=TPR.avg-FPR.avg) %>% group_by(Antibody,Cell,Benchmark) %>% mutate(near.maxTPRmFPR = TPRmFPR>=max(TPRmFPR)-0.02) %>% as.data.table()
attr(dt.TPR.FPR.RIPPeakS,"groups") <- NULL
dt.TPR.FPR.RIPPeaks.at.two.mode <- dt.TPR.FPR.RIPPeakS %>% filter(!is.na(Mode)) %>%
  group_by(Mode,Benchmark,Cell,Antibody) %>% slice_max(TPR.avg-FPR.avg, n=1) %>%
  as.data.table() %>% dplyr::arrange(Antibody,Cell,Mode,Benchmark) %>%
  mutate(Label=paste0("FPR:",round(FPR.avg,2), ", FPR:",round(TPR.avg,2))) %>% dplyr::filter(str_detect(Benchmark,"GLORI_HEK293"))

p.dumbbell.optimal.cutoff.RIPPeakS <- dt.TPR.FPR.RIPPeakS %>% dplyr::filter(str_detect(Benchmark,"GLORI_HEK293")) %>%
  ggplot(data=.)+
  geom_segment(aes(x = cutoff, y=FPR.avg, yend=TPR.avg, color=near.maxTPRmFPR))+
  geom_point(aes(x=cutoff,y=FPR.avg),shape=16,size=1)+
  geom_point(aes(x=cutoff,y=TPR.avg),shape=21,size=1)+
  geom_step(aes(x=cutoff,y=TPRmFPR),linewidth=0.5)+
  geom_label(data=dt.TPR.FPR.RIPPeaks.at.two.mode[Mode=="Sensitive",], aes(x=cutoff, y=TPR.avg, label=Label),color=c("#1874CD", "#FF3030")[2],size=2.5,nudge_y = 0.01,nudge_x = 0)+
  geom_label(data=dt.TPR.FPR.RIPPeaks.at.two.mode[Mode=="Strict",], aes(x=cutoff, y=TPR.avg, label=Label),color=c("#1874CD", "#FF3030")[2],size=2.5,nudge_y = 0.01,nudge_x = 0)+
  scale_color_manual(breaks=c(FALSE,TRUE),values=c("grey50", "#e31a1c"),guide="none")+
  scale_y_continuous(breaks = seq(0,1,by=0.1))+
  scale_x_continuous(breaks = seq(0,1,by=0.1))+
  facet_wrap(~Antibody+Cell+Benchmark,scales = "free_y")+
  labs(x="Cutoff of RIPPeakS", y="TPR (up) and FPR (down)", title="Optimal cutoff for RIPPeaks")+
  theme_pubr(base_size=7,base_family = "Times")+
  theme(plot.title = element_text(size=7,face = "bold",hjust=0.5),
        plot.subtitle = element_text(size=7,hjust=0.5,face="bold"),
        legend.position = "top",legend.key.height = unit(6,"point"),legend.key.width=unit(6,"point"),
        legend.text = element_text(size=7),legend.title = element_text(size=7),legend.spacing = unit(1,"point"),
        strip.background = element_rect(fill="white"))

#Mode:Sensitive and Mode Strict of RIPPeaks
dt.BestOption.pruned.TPR.FPR <- readRDS(file="dt.Method.BestOption.AUC.pruned.TPR.FPR.RDS")
dt.fc.cutoff.all <- foreach(f=FPR.ranges,.combine='rbind')%do%{
  dt.BestOption.pruned.TPR.FPR %>% dplyr::filter(FPR <= f & Benchmark == "GLORI_HEK293") %>% group_by(Antibody,Combo) %>%
    slice_max(TPR,n = 1) %>% slice_min(FPR,n=1) %>% as.data.table() %>% dplyr::select(Antibody, Combo,cutoff) %>%
    dplyr::filter(!is.na(cutoff)) %>% dplyr::arrange(Antibody,Combo) %>% mutate(TargetedFPR=f)
}
dt.cutoff.parameter.RIPPeaks <- dt.fc.cutoff.all %>% mutate(TargetedFPR=round(TargetedFPR,2)) %>%
