  dt.FPR.TPR.Abcam.HEK <- foreach(M=unique(dt.method.combo$Method),.combine='rbind')%do%{
    message(paste0("load result for  ", M))
    foreach(combo=dt.method.combo[Method==M,unique(ComboName)], .combine='rbind')%do%{
      res.file  <- paste0("/data/m6A_calling_strategy/RIPPeakS_Abcam/Benchmark_FPRTPR/",M,"_",combo,".TPR.FPR.using.original.score.txt")
      if(file.exists(res.file)){
        fread(res.file,header=T) %>% mutate(Method=M, ComboName=combo)
      }else{
        message(paste0("Error! woops, could not find result for  ", M, " ", combo))
      }
    }
  }
  dt.FPR.TPR.Abcam.HEK %>% distinct(Method,ComboName,Sample,Benchmark) %>% View()
  saveRDS(dt.FPR.TPR.Abcam.HEK, file = "dt.TPR.FPR.Abcam.HEK.combo.RDS")
}
dt.FPR.TPR.Abcam.HEK <- readRDS("dt.TPR.FPR.Abcam.HEK.combo.RDS")

dt.avg.FPR.TPR.Abcam.HEK <- dt.FPR.TPR.Abcam.HEK %>% dplyr::select(cutoff,Sample,nPeak,nPeakTP,nSite,contains("site"),Benchmark,Method,ComboName) %>%
  dplyr::rename(FPR=FPR_site, TPR=TPR_site) %>%
  group_by(Method,ComboName,cutoff,Benchmark) %>% mutate(FPR.avg=mean(FPR),TPR.avg=mean(TPR)) %>%
  as.data.table() %>% distinct(Method,ComboName,cutoff,Benchmark,FPR.avg,TPR.avg) %>% dplyr::rename(FPR=FPR.avg, TPR=TPR.avg) %>%
