        dt.pruned.alternative.FPR.TPR <- TPR.FPR.pruned(dt.TPR.FPR.fc = dt.avg.alternative.FPR.TPR.NEB.HeLa[Method==M & ComboName==combo & Benchmark==b,.(TPR,FPR,cutoff)]) %>%
          mutate(Method=M,ComboName=combo,Benchmark=b) %>% distinct()
        dt.pruned.alternative.FPR.TPR %>% mutate(AUC=TargetAUC(FPR = dt.pruned.alternative.FPR.TPR$FPR, TPR=dt.pruned.alternative.FPR.TPR$TPR,TargetRegion = 0.5)) %>%
          mutate(AUC=round(AUC,2),AUC.scaled=round(AUC/0.5,2), maxTPRmFPR=max(TPR-FPR), TPR20=max(TPR[FPR<=0.2]))
      }
    }
  }
  dt.pruned.alternative.FPR.TPR.AUC.NEB.HeLa.summary <- dt.pruned.alternative.FPR.TPR.AUC.NEB.HeLa %>% distinct(Method,ComboName,Benchmark,AUC,AUC.scaled,maxTPRmFPR,TPR20) %>% dplyr::arrange(desc(AUC.scaled),desc(TPR20)) %>%
    mutate(All.rank=1:n()) %>% group_by(Method) %>% mutate(Method.rank=1:n_distinct(ComboName)) %>% as.data.table() %>%
    left_join(x=.,y=dt.method.combo,by=c("Method","ComboName"))
  dt.pruned.alternative.FPR.TPR.AUC.NEB.HeLa.summary %>% head(n=3)
  dt.pruned.alternative.FPR.TPR.AUC.NEB.HeLa.summary %>% dplyr::filter(IsDefaultCombo)

  saveRDS(dt.pruned.alternative.FPR.TPR.AUC.NEB.HeLa, file="dt.pruned.alternative.FPR.TPR.AUC.NEB.HeLa.all.combo.RDS")
}
