#strategy3, Multiple correspondance analysis to perform dimension reduction for all 285 combo
#estimate the dimension of m6a site of all 285 combo
for(sam in unique(dt.m6a.FPR20.site$Sample)){
  dt.FPR20.site <- dt.m6a.FPR20.site %>% dplyr::filter(Sample==sam) %>%
    mutate(ComboID=paste(Method,ComboName,sep="|"), value="Y") %>% mutate(ComboID=str_replace(ComboID,pattern="ombo",replacement="")) %>%
    pivot_wider(id_cols = c("SiteID"),names_from = c("ComboID"),values_from = "value",values_fill = "N") %>% as.data.table()
  df.FPR20.site <- dt.FPR20.site[,-1] %>% as.data.frame()
  rownames(df.FPR20.site) <- dt.FPR20.site$SiteID
  #order the colunm by total number of m6a site and the row by total number of detect combo
  order.col <- colSums(df.FPR20.site=="Y") %>% sort(decreasing = T)
  df.FPR20.site <- df.FPR20.site[,names(order.col)]
  order.row <- rowSums(df.FPR20.site=="Y") %>% sort(decreasing = T)
  df.FPR20.site <- df.FPR20.site[names(order.row),]
  #rename the variable
  for(i in 1:ncol(df.FPR20.site)){
    df.FPR20.site[,i] <- factor(df.FPR20.site[,i], levels=c("Y","N"), labels=paste0(colnames(df.FPR20.site)[i],c("_y","_n")))
  }
  require("factoextra")
  res.mca <- MCA(df.FPR20.site, graph = FALSE,ncp=10)
  res.desc <- dimdesc(res.mca, axes = 1:10)
  saveRDS(res.mca, file=paste0("res.mca.",sam,".RDS"))
  saveRDS(res.desc, file=paste0("res.desc.",sam,".RDS"))
  # bestclusCA  <- clustrd::tuneclus(df.FPR20.site, nclusrange = 3:7, ndimrange = 2:6, method = "clusCA", criterion = "asw", nstart = 10, seed = 1234)
  # bestclusCA
  # saveRDS(bestclusCA,file=paste0("bestclusA.",sam,".RDS"))
}
