    dt.all.site.selected.combo <- dt.m6a.FPR20.site %>%
      mutate(ComboID=paste(Method,ComboName,sep="|")) %>% mutate(ComboID=str_replace(ComboID,pattern="ombo",replacement="")) %>%
      dplyr::filter(ComboID %in% unique(dt.selected.combo[Sample==sam & Dim %in% paste0("Dim",1:nDim),ComboID]))
    dt.all.site.selected.combo[,list(nSite=n_distinct(SiteID)), by=.(Sample)] %>% mutate(TPR=round(nSite/nrow(m6A.site.list[["GLORI_HEK293"]]),2), UseSample=sam, UseDim=nDim)
  }
}
