if(!file.exists("dt.pruned.FPR.TPR.AUC.Abcam.HEK.RDS")){
  dt.pruned.FPR.TPR.AUC.Abcam.HEK <- foreach(M = unique(dt.avg.FPR.TPR.Abcam.HEK$Method),.combine='rbind')%do%{
    foreach(combo = dt.avg.FPR.TPR.Abcam.HEK[Method==M,unique(ComboName)], .combine='rbind')%do%{
      registerDoParallel(cl=6)
      message(paste0("TPR FPR prune for ", M, " ",combo))
      dt.pruned.FPR.TPR.combo <- foreach(option = dt.avg.FPR.TPR.Abcam.HEK[Method==M & ComboName==combo, unique(Option)], .combine = 'rbind')%dopar%{
        foreach(b = unique(dt.avg.FPR.TPR.Abcam.HEK$Benchmark), .combine = 'rbind')%do%{
          dt.pruned.FPR.TPR <- TPR.FPR.pruned(dt.TPR.FPR.fc = dt.avg.FPR.TPR.Abcam.HEK[Method==M & ComboName==combo & Option==option & Benchmark==b,.(TPR,FPR,cutoff)]) %>%
            mutate(Method=M,ComboName=combo,optionID=option,Benchmark=b) %>% distinct()
          dt.pruned.FPR.TPR %>% mutate(AUC=TargetAUC(FPR = dt.pruned.FPR.TPR$FPR, TPR=dt.pruned.FPR.TPR$TPR,TargetRegion = 0.5)) %>%
            mutate(AUC=round(AUC,2),AUC.scaled=round(AUC/0.5,2), maxTPRmFPR=max(TPR-FPR), TPR20=max(TPR[FPR<=0.2]))
        }
      }
      stopImplicitCluster()
      dt.pruned.FPR.TPR.combo
    }
  }
  saveRDS(dt.pruned.FPR.TPR.AUC.Abcam.HEK, file="dt.pruned.FPR.TPR.AUC.Abcam.HEK.RDS")
}
