if(!file.exists("dt.pruned.genelevel.FPR.TPR.AUC.NEB.HEK.RDS")){
  dt.pruned.genelevel.FPR.TPR.AUC.NEB.HEK <- foreach(M = unique(dt.avg.genelevel.FPR.TPR.NEB.HEK$Method),.combine='rbind')%do%{
    foreach(combo = dt.avg.genelevel.FPR.TPR.NEB.HEK[Method==M,unique(ComboName)], .combine='rbind')%do%{
      registerDoParallel(cl=6)
      message(paste0("TPR FPR prune for ", M, " ",combo))
      dt.pruned.genelevel.FPR.TPR.combo <- foreach(option = dt.avg.genelevel.FPR.TPR.NEB.HEK[Method==M & ComboName==combo, unique(Option)], .combine = 'rbind')%dopar%{
        foreach(b = unique(dt.avg.genelevel.FPR.TPR.NEB.HEK$Benchmark), .combine = 'rbind')%do%{
          dt.pruned.genelevel.FPR.TPR <- TPR.FPR.pruned(dt.TPR.FPR.fc = dt.avg.genelevel.FPR.TPR.NEB.HEK[Method==M & ComboName==combo & Option==option & Benchmark==b,.(TPR,FPR,cutoff)]) %>%
            mutate(Method=M,ComboName=combo,optionID=option,Benchmark=b) %>% distinct()
          dt.pruned.genelevel.FPR.TPR %>% mutate(AUC=TargetAUC(FPR = dt.pruned.genelevel.FPR.TPR$FPR, TPR=dt.pruned.genelevel.FPR.TPR$TPR,TargetRegion = 0.5)) %>%
            mutate(AUC=round(AUC,2),AUC.scaled=round(AUC/0.5,2), maxTPRmFPR=max(TPR-FPR), TPR20=max(TPR[FPR<=0.2]))
        }
      }
      stopImplicitCluster()
      dt.pruned.genelevel.FPR.TPR.combo
    }
  }
  saveRDS(dt.pruned.genelevel.FPR.TPR.AUC.NEB.HEK, file="dt.pruned.genelevel.FPR.TPR.AUC.NEB.HEK.RDS")
}

dt.pruned.FPR.TPR.AUC.NEB.HEK <- readRDS("dt.pruned.FPR.TPR.AUC.NEB.HEK.RDS")
#determine the best option for 285 combo
dt.top.option.method.combo <- dt.pruned.FPR.TPR.AUC.NEB.HEK %>% distinct(Method,ComboName,optionID,Benchmark,AUC.scaled,TPR20,maxTPRmFPR) %>% dplyr::filter(str_detect(Benchmark,"GLORI_HEK293")) %>%
  group_by(Method,ComboName) %>% dplyr::arrange(desc(AUC.scaled)) %>% mutate(AUC.rank=1:n()) %>%
  dplyr::arrange(desc(TPR20)) %>% mutate(TPR.rank=1:n(), maxTPR20=max(TPR20)) %>% as.data.table() %>% distinct(Method,ComboName,optionID,AUC.scaled,TPR20,maxTPRmFPR,AUC.rank,TPR.rank,maxTPR20) %>%
  group_by(Method,ComboName) %>% dplyr::filter(TPR20>=(maxTPR20-0.05)) %>% slice_min(AUC.rank) %>% as.data.table() %>% dplyr::arrange(desc(AUC.scaled))
#load corresponding cutoff at FPR20
dt.cutoff.FPR20 <- dt.pruned.FPR.TPR.AUC.NEB.HEK %>% dplyr::filter(FPR==0.2 & str_detect(Benchmark,"GLORI_HEK293")) %>%
  dplyr::select(FPR,TPR,cutoff,Method,ComboName,optionID) %>% dplyr::arrange(Method,ComboName,optionID) %>%
  right_join(x=.,y=dt.top.option.method.combo) %>% dplyr::arrange(desc(AUC.scaled))
#load m6a intensity for 285 combo under best option
