#assess the TPR and FPR after merge of peaks from selected combo according to MCA results
dt.TPR.FPR.MCA.topn.combo <- foreach(SAM=unique(dt.m6a.FPR20.site$Sample), .combine='rbind')%do%{
  dt.TPR.FPR.MCA <- foreach(nDim=seq(2,10,2),.combine='rbind')%do%{
    selectedCombo <- unique(dt.selected.combo[Sample==SAM & Dim %in% paste0("Dim",1:nDim),ComboID]) %>%
      str_replace(pattern=fixed("|C"),replacement="|Combo")
    dt.topn.combo <- dt.cutoff.FPR20 %>% mutate(ComboID=paste0(Method,"|",ComboName)) %>% dplyr::filter(ComboID %in% selectedCombo)
    dt.topn.m6a <- dt.m6a.FPR20 %>% inner_join(x=.,y=dt.topn.combo,by=c("Method","ComboName","optionID"))
    dt.topn.m6a <- dt.topn.m6a %>% dplyr::filter(!(SumWidth>3000 & OverlappedNoGene>2))
    #dt.topn.m6a[SumWidth<=6000,.N,by=.(Sample,Method,ComboName,optionID)]
    #merge together
    dt.m6a.filtered.pos <- dt.topn.m6a %>% dplyr::filter(strand=="+") %>% dplyr::select(seqnames,start,end,name,score,strand,Sample) %>% distinct()
    if(nrow(dt.m6a.filtered.pos)>0){
      dt.m6a.filtered.pos.gr <- GenomicRanges::makeGRangesFromDataFrame(dt.m6a.filtered.pos,keep.extra.columns = T)
      dt.m6a.filtered.pos.merged <- foreach(sam = unique(dt.m6a.filtered.pos$Sample), .combine='rbind')%do%{
        GenomicRanges::reduce(dt.m6a.filtered.pos.gr[dt.m6a.filtered.pos.gr$Sample==sam,]) %>% as.data.table() %>%
          mutate(score=1000,name=paste(seqnames,start,end,strand,sep="_"),Sample=sam) %>%
          dplyr::select(seqnames,start,end,name,score,strand,Sample)
      }
    }else{
      dt.m6a.filtered.pos.merged <- data.table(seqnames=NULL,start=NULL,end=NULL,name=NULL,score=NULL,strand=NULL,Sample=NULL)
    }
    #filtered  and un overlapped m6a at neg strand
    dt.m6a.filtered.neg <- dt.topn.m6a %>% dplyr::filter(strand=="-") %>% dplyr::select(seqnames,start,end,name,score,strand,Sample) %>% distinct()
    if(nrow(dt.m6a.filtered.neg)>0){
      dt.m6a.filtered.neg.gr <- GenomicRanges::makeGRangesFromDataFrame(dt.m6a.filtered.neg,keep.extra.columns = T)
      dt.m6a.filtered.neg.merged <- foreach(sam = unique(dt.m6a.filtered.neg$Sample), .combine='rbind')%do%{
        GenomicRanges::reduce(dt.m6a.filtered.neg.gr[dt.m6a.filtered.neg.gr$Sample==sam,]) %>% as.data.table() %>%
          mutate(score=1000,name=paste(seqnames,start,end,strand,sep="_"),Sample=sam) %>%
          dplyr::select(seqnames,start,end,name,score,strand,Sample)
      }
    }else{
      dt.m6a.filtered.neg.merged <- data.table(seqnames=NULL,start=NULL,end=NULL,name=NULL,score=NULL,strand=NULL,Sample=NULL)
    }
    dt.m6a.filtered <- rbind(dt.m6a.filtered.pos.merged, dt.m6a.filtered.neg.merged)
    #calculate exonic sum width to filter extreme long peak (<=6kb)
    dt.m6a.filtered.sumwidth <- LongPeakRemoveIntron(dt.peak = dt.m6a.filtered,
                                                     dt.intron = fread("/data/m6A_calling_strategy/RIPPeakS_resource/dt.intron.hg38.bed"),
                                                     genome_file = "/data/m6A_calling_strategy/RIPPeakS_resource/chrNameLength_hg38.txt")
    dt.m6a.filtered <- dt.m6a.filtered %>% left_join(x=.,y=dt.m6a.filtered.sumwidth  %>% dplyr::distinct(Sample,name,SumWidth), by=c("Sample","name")) %>%
      dplyr::mutate(SumWidth=case_when(is.na(SumWidth) ~ 0, .default = SumWidth))
    #check the overlapped gene count of merged m6a
    gene.bed.file <- "/data/m6A_calling_strategy/RIPPeakS_resource/hg38_gencode.gene.bed"
    dt.m6a.filtered.overlapped.gene <- bt.intersect(a=dt.m6a.filtered, b=fread(gene.bed.file),s=T, f=0.5, F=0.8, c=T,e = T) %>% as.data.table()
    #dt.m6a.filtered.overlapped.gene[,.N,by=.(Sample=V7,nGene=V9)] %>% dplyr::arrange(Sample,nGene)
    #filter out merged peak with more than two genes and exonic width over 3kb
    dt.m6a.notkept <- dt.m6a.filtered.overlapped.gene[V9>2 & V8>3000,]
    #dt.m6a.notkept <- dt.m6a.filtered.overlapped.gene[V9>1,]
    dt.m6a.filtered <- dt.m6a.filtered %>% dplyr::filter(!name %in% dt.m6a.notkept$V4) #key filtering
    #obtain the intersect of GLORI_HEK293 m6a site
    dt.m6a.overlap <- bedtoolsr::bt.intersect(a=dt.m6a.filtered, b=m6A.site.list[["GLORI_HEK293"]][,1:6], s=T, wo=T) %>% as.data.table() %>% distinct()
    message(paste0("Finished TPR/FPR for merged top", nDim, " Dimension of MCA result using ", SAM))
    foreach(width.cut = c(Inf),.combine='rbind')%do%{
      dt.m6a.overlap %>% dplyr::filter(V8<=width.cut) %>%  group_by(Sample=V7) %>% mutate(nTP=n_distinct(V4), nSite=n_distinct(V12), TPR=n_distinct(V12)/nrow(m6A.site.list[["GLORI_HEK293"]])) %>%
        as.data.table() %>% distinct(Sample,nTP,nSite,TPR) %>% left_join(x=.,y=dt.m6a.filtered[SumWidth<=width.cut,list(nPeak=.N),by=.(Sample)],by=c("Sample")) %>% mutate(FPR=1-nTP/nPeak) %>%
        mutate(Strategy=paste0("MCA.top",nDim,"Dim.",SAM), InvolvedMethod=selectedCombo %>% strsplit(split="|",fixed=T) %>% sapply("[",1) %>% unique() %>% paste(collapse = ","),
               FPR=round(FPR,2), TPR=round(TPR,2)) %>% mutate(LongPeak=paste0("<=",round(width.cut/1000),"kb"))
    }
  }
  dt.TPR.FPR.MCA
}
dt.avg.TPR.FPR.MCA.topn.combo <- dt.TPR.FPR.MCA.topn.combo %>% group_by(Strategy) %>% mutate(avg.FPR=mean(FPR), avg.TPR=mean(TPR),avg.nSite=mean(nSite)) %>% as.data.table() %>%
  distinct(Strategy,InvolvedMethod,avg.FPR,avg.TPR,avg.nSite) %>% dplyr::arrange(desc(avg.TPR))
