        dt.m6a.overlaped.site <- bedtoolsr::bt.intersect(a=dt.m6a.filtered, b=m6A.site.list[["GLORI_HeLa"]][,1:6], s=T, wo=T) %>% as.data.table() %>% distinct() %>%
