dt.pruned.FPR.TPR.AUC.Millipore.mESC <- readRDS("/data/m6A_calling_strategy/Analysis/dt.pruned.FPR.TPR.AUC.Millipore.mESC.RDS")
#determine the best option for 285 combo
dt.top.option.method.combo <- dt.pruned.FPR.TPR.AUC.Millipore.mESC %>% distinct(Method,ComboName,optionID,Benchmark,AUC.scaled,TPR20,maxTPRmFPR) %>% dplyr::filter(str_detect(Benchmark,"GLORI_mESC")) %>%
  group_by(Method,ComboName) %>% dplyr::arrange(desc(AUC.scaled)) %>% mutate(AUC.rank=1:n()) %>%
  dplyr::arrange(desc(TPR20)) %>% mutate(TPR.rank=1:n(), maxTPR20=max(TPR20)) %>% as.data.table() %>% distinct(Method,ComboName,optionID,AUC.scaled,TPR20,maxTPRmFPR,AUC.rank,TPR.rank,maxTPR20) %>%
  group_by(Method,ComboName) %>% dplyr::filter(TPR20>=(maxTPR20-0.05)) %>% slice_min(AUC.rank) %>% as.data.table() %>% dplyr::arrange(desc(AUC.scaled))
#load corresponding cutoff at FPR20
dt.cutoff.FPR20 <- dt.pruned.FPR.TPR.AUC.Millipore.mESC %>% dplyr::filter(FPR==0.2 & str_detect(Benchmark,"GLORI_mESC")) %>%
  dplyr::select(FPR,TPR,cutoff,Method,ComboName,optionID) %>% dplyr::arrange(Method,ComboName,optionID) %>% dplyr::filter(!is.na(cutoff) & TPR>0) %>%
  inner_join(x=.,y=dt.top.option.method.combo) %>% dplyr::arrange(desc(AUC.scaled))
#load m6a intensity for 285 combo under best option
#load benchmark m6As
dt.HEK.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.HEK293.benchmark.m6As.RDS")
dt.mESC.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.mESC.benchmark.m6As.RDS")
dt.benchmark.m6As <- rbind(dt.HEK.benchmark.m6As,dt.mESC.benchmark.m6As)
m6A.site.list <- foreach(i=unique(dt.benchmark.m6As$Sample))%do%{dt.benchmark.m6As[Sample==i,1:6]}
names(m6A.site.list) <- unique(dt.benchmark.m6As$Sample)
if(!file.exists("dt.mESC.Millipore.all.combo.m6a.FPR20.RDS")){
  dt.m6a.FPR20 <- foreach(M=unique(dt.cutoff.FPR20$Method),.combine='rbind')%do%{
    foreach(combo = dt.cutoff.FPR20[Method==M,unique(ComboName)], .combine='rbind')%do%{
      message(paste0("Finished FPR20 peak for ", M, " ", which(dt.cutoff.FPR20[Method==M,unique(ComboName)] == combo), "th/", length(dt.cutoff.FPR20[Method==M,unique(ComboName)])))
      intensity.files <- list.files(paste0("/data/m6A_calling_strategy/RIPPeakS_Millipore/Intensity/",M,"_",combo),pattern = "allOption.tsv",full.names = T)
      names(intensity.files) <- list.files(paste0("/data/m6A_calling_strategy/RIPPeakS_Millipore/Intensity/",M,"_",combo),pattern = "allOption.tsv",full.names = F) %>%
        str_replace(pattern="Bedtools_intensity_",replacement = "") %>% str_replace(pattern="_allOption.tsv",replacement = "")
      intensity.files <- intensity.files[names(intensity.files) %>% grep(pattern="GSE184893",value=T)]
      dt.intensity <- foreach(s=names(intensity.files),.combine='rbind')%do%{fread(file = intensity.files[s]) %>% mutate(Sample=s)}#load intensity for all sample
      dt.intensity <- dt.intensity %>% dplyr::select(name,Sample,paste0(c("pos__","neg__"), dt.cutoff.FPR20[Method==M & ComboName==combo,optionID]))
      colnames(dt.intensity) <- c("name","Sample","pos","neg")
      #pull out m6a with intensity higher than cutoff at FPR20
      #filtered and un overlapped  m6a at pos strand
      dt.m6a.filtered.pos <- dt.intensity %>% dplyr::filter(pos >= dt.cutoff.FPR20[Method==M & ComboName==combo,cutoff])
      if(nrow(dt.m6a.filtered.pos)>0){
        dt.m6a.filtered.pos <- dt.m6a.filtered.pos %>% dplyr::mutate(name = name %>% strsplit(split=paste0(M,"_"),fixed=T) %>% sapply(tail,1)) %>%
          dplyr::mutate(seqnames=name %>% strsplit(split="_",fixed=T) %>% sapply("[",1),
                        start=name %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                        end=name %>% strsplit(split="_",fixed=T) %>% sapply("[",3),
                        strand="+") %>%
          dplyr::select(seqnames,start,end,name,score=pos,strand,Sample)
        dt.m6a.filtered.pos.gr <- GenomicRanges::makeGRangesFromDataFrame(dt.m6a.filtered.pos,keep.extra.columns = T)
        dt.m6a.filtered.pos.merged <- foreach(sam = unique(dt.m6a.filtered.pos$Sample), .combine='rbind')%do%{
          GenomicRanges::reduce(dt.m6a.filtered.pos.gr[dt.m6a.filtered.pos.gr$Sample==sam,]) %>% as.data.table() %>%
            mutate(score=1000,name=paste(seqnames,start,end,strand,sep="_"),Sample=sam) %>%
            dplyr::select(seqnames,start,end,name,score,strand,Sample)
        }
      }else{
        dt.m6a.filtered.pos.merged <- data.table(seqnames=NULL,start=NULL,end=NULL,name=NULL,score=NULL,strand=NULL,Sample=NULL)
      }
      #filtered  and un overlapped m6a at neg strand
      dt.m6a.filtered.neg <- dt.intensity %>% dplyr::filter(neg >= dt.cutoff.FPR20[Method==M & ComboName==combo,cutoff])
      if(nrow(dt.m6a.filtered.neg)>0){
        dt.m6a.filtered.neg <- dt.m6a.filtered.neg %>% dplyr::mutate(name = name %>% strsplit(split=paste0(M,"_"),fixed=T) %>% sapply(tail,1)) %>%
          dplyr::mutate(seqnames=name %>% strsplit(split="_",fixed=T) %>% sapply("[",1),
                        start=name %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                        end=name %>% strsplit(split="_",fixed=T) %>% sapply("[",3),
                        strand="-") %>%
          dplyr::select(seqnames,start,end,name,score=neg,strand,Sample)
        dt.m6a.filtered.neg.gr <- GenomicRanges::makeGRangesFromDataFrame(dt.m6a.filtered.neg,keep.extra.columns = T)
        dt.m6a.filtered.neg.merged <- foreach(sam = unique(dt.m6a.filtered.neg$Sample), .combine='rbind')%do%{
          GenomicRanges::reduce(dt.m6a.filtered.neg.gr[dt.m6a.filtered.neg.gr$Sample==sam,]) %>% as.data.table() %>%
            mutate(score=1000,name=paste(seqnames,start,end,strand,sep="_"),Sample=sam) %>%
            dplyr::select(seqnames,start,end,name,score,strand,Sample)
        }
      }else{
        dt.m6a.filtered.neg.merged <- data.table(seqnames=NULL,start=NULL,end=NULL,name=NULL,score=NULL,strand=NULL,Sample=NULL)
      }
      dt.m6a.filtered <- rbind(dt.m6a.filtered.pos.merged, dt.m6a.filtered.neg.merged)
      if(nrow(dt.m6a.filtered)>0){
        #calculate exonic sum width to filter extreme long peak (<=6kb)
        dt.m6a.filtered.sumwidth <- LongPeakRemoveIntron(dt.peak = dt.m6a.filtered,
                                                         dt.intron = fread("/data/m6A_calling_strategy/RIPPeakS_resource/dt.intron.mm39.bed"),
                                                         genome_file = "/data/m6A_calling_strategy/RIPPeakS_resource/chrNameLength_mm39.txt")
        dt.m6a.filtered <- dt.m6a.filtered %>% left_join(x=.,y=dt.m6a.filtered.sumwidth  %>% dplyr::distinct(Sample,name,SumWidth), by=c("Sample","name")) %>%
          dplyr::mutate(SumWidth=case_when(is.na(SumWidth) ~ 0, .default = SumWidth))
        #the overlap gene
        dt.m6a.filtered.overlapped.gene <- bt.intersect(a=dt.m6a.filtered, b=fread("/data/m6A_calling_strategy/RIPPeakS_resource/mm39_gencode.gene.bed"),
                                                        s=T, f=0.5, F=0.8, c=T,e = T) %>% as.data.table()
        dt.m6a.filtered <- dt.m6a.filtered %>% left_join(x=.,y=dt.m6a.filtered.overlapped.gene %>% dplyr::select(name=V4,Sample=V7,OverlappedNoGene=V9) %>%
                                                           dplyr::distinct(Sample,name,OverlappedNoGene), by=c("Sample","name"))
        dt.m6a.filtered %>% mutate(Method=M, ComboName=combo, optionID=dt.cutoff.FPR20[Method==M & ComboName==combo,optionID])
      }
    }
  }
  saveRDS(dt.m6a.FPR20, file="dt.mESC.Millipore.all.combo.m6a.FPR20.RDS")
}else{
  dt.m6a.FPR20 <- readRDS("dt.mESC.Millipore.all.combo.m6a.FPR20.RDS")
}
#dt.m6a.FPR20 <- readRDS("dt.mESC.Millipore.all.combo.and.option.m6a.FPR20.RDS") %>% dplyr::filter(str_detect(Sample,"GSE184893"))
