    foreach(combo = dt.cutoff.FPR20[Method==M,unique(ComboName)], .combine='rbind')%do%{
      message(paste0("Finished FPR20 overlapped sites for ", M, " ", which(dt.cutoff.FPR20[Method==M,unique(ComboName)] == combo), "th/", length(dt.cutoff.FPR20[Method==M,unique(ComboName)])))
      dt.m6a.filtered <- dt.m6a.FPR20 %>% dplyr::filter(Method==M & ComboName==combo & optionID==dt.cutoff.FPR20[Method==M & ComboName==combo,optionID])
      if(nrow(dt.m6a.filtered)>0){
        dt.m6a.filtered <- dt.m6a.filtered %>% dplyr::filter(!(SumWidth >3000 & OverlappedNoGene>2))
        #obtain the intersect of GLORI_mESC m6a site
        # dt.m6a.overlap <- bedtoolsr::bt.intersect(a=dt.m6a.filtered, b=m6A.site.list[["GLORI_mESC"]][,1:6], s=T, wo=T) %>% as.data.table() %>% distinct()
        # dt.m6a.overlap %>% group_by(Sample=V7) %>% mutate(nTP=n_distinct(V4), nSite=n_distinct(V16), TPR=n_distinct(V16)/nrow(m6A.site.list[["GLORI_mESC"]])) %>%
        #   as.data.table() %>% distinct(Sample,nTP,nSite,TPR) %>% left_join(x=.,y=dt.m6a.filtered[,list(nPeak=.N),by=.(Sample)],by=c("Sample")) %>% mutate(FPR=1-nTP/nPeak) %>%
        #   mutate(Method=M,ComboName=combo,optionID=dt.cutoff.FPR20[Method==M & ComboName==combo,optionID], FPR=round(FPR,2), TPR=round(TPR,2))
        dt.m6a.overlaped.site <- bedtoolsr::bt.intersect(a=dt.m6a.filtered, b=m6A.site.list[["GLORI_mESC"]][,1:6], s=T, wo=T) %>% as.data.table() %>% distinct() %>%
          dplyr::select(Sample=V7,SiteID=V16) %>% distinct()
        dt.m6a.overlaped.site %>% mutate(Method=M, ComboName=combo, optionID=dt.cutoff.FPR20[Method==M & ComboName==combo,optionID])
      }
    }
  }
  saveRDS(dt.m6a.FPR20.site, file="dt.mESC.Millipore.all.combo.m6a.FPR20.sites.RDS")
}else{
  dt.m6a.FPR20.site <- readRDS("dt.mESC.Millipore.all.combo.m6a.FPR20.sites.RDS")
}
