# 6:  MCA.top4Dim.HEK_NEB_mRNA1                    TRESS,MACS2,MeRIPtools,exomePeak   0.205   0.725  134162.0
# 7:  MCA.top8Dim.HEK_NEB_mRNA1 TRESS,MACS2,MeRIPtools,exomePeak,exomePeak2,MeTPeak   0.220   0.735  135133.5
# 8: MCA.top10Dim.HEK_NEB_mRNA1 TRESS,MeRIPtools,MeTPeak,MACS2,exomePeak,exomePeak2   0.220   0.735  135147.5
# 9:  MCA.top2Dim.HEK_NEB_mRNA2                          exomePeak,MACS2,MeRIPtools   0.175   0.640  117881.0
# 10:  MCA.top2Dim.HEK_NEB_mRNA1                              TRESS,MACS2,MeRIPtools   0.190   0.615  113094.5
selected.strategy <- dt.avg.TPR.FPR.MCA.topn.combo$Strategy[1]
MCA.res.files <- list.files(pattern = "^(res.desc).+(NEB).+(.RDS)$")
names(MCA.res.files) <- MCA.res.files %>% str_replace(pattern="res.desc.",replacement = "") %>% str_replace(pattern=".RDS",replacement = "")
dt.selected.combo.MCA <- foreach(sam = names(MCA.res.files),.combine='rbind')%do%{
  res.desc <- readRDS(MCA.res.files[sam])
  dt.cor.dim <- foreach(i = 1:10, .combine='rbind')%do%{
    res.desc[[i]]$category %>% as.data.table(keep.rownames = "ComboID") %>% dplyr::arrange(desc(abs(Estimate))) %>% dplyr::filter(str_detect(ComboID,"_y")) %>%
      mutate(Dim=paste0("Dim",i)) %>% mutate(Estimate=round(Estimate,2))
  }
  #dt.cor.dim %>% pivot_wider(id_cols = "ComboID", values_from = "Estimate",names_from = "Dim",values_fill = 0) %>% as.data.table() %>% View()
  dt.cor.dim %>% group_by(Dim,Direction=Estimate>0) %>% dplyr::arrange(desc(abs(Estimate))) %>% slice_head(n=1) %>% as.data.table() %>%
    mutate(ComboID=ComboID %>% strsplit(split="=",fixed=T) %>% sapply("[",1), Sample=sam)
}
selected.combo <- dt.selected.combo.MCA %>% dplyr::filter(Sample==selected.strategy %>% strsplit(split="Dim.",fixed=T) %>% sapply(tail,1)) %>%
  dplyr::filter(Dim %in% paste0("Dim",1:(as.integer(selected.strategy %>% strsplit(split="top",fixed=T) %>% sapply(tail,1) %>% strsplit(split="Dim",fixed=T) %>% sapply(head,1))))) %>%
  mutate(ComboID=str_replace(ComboID,pattern=fixed("|C"),replacement="|Combo"))
dt.selected.method.option <- selected.combo %>% dplyr::select(ComboID,Dim,Estimate) %>% left_join(x=.,y=dt.top.option.method.combo %>% mutate(ComboID=paste0(Method,"|",ComboName)))
#load benchmark m6As
dt.HEK293.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.HEK293.benchmark.m6As.RDS")
dt.mESC.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.mESC.benchmark.m6As.RDS")
dt.benchmark.m6As <- rbind(dt.HEK293.benchmark.m6As,dt.mESC.benchmark.m6As)
m6A.site.list <- foreach(i=unique(dt.benchmark.m6As$Sample))%do%{dt.benchmark.m6As[Sample==i,c(1:6,9)]}
names(m6A.site.list) <- unique(dt.benchmark.m6As$Sample)
if(!file.exists("dt.HEK.NEB.TPR.FPR.M6APeakS.RDS")){
dt.TPR.FPR.selected.method.option <- foreach(fpr=unique(dt.pruned.FPR.TPR.AUC.NEB.HEK$FPR),.combine='rbind')%do%{
  dt.cutoff.FPR <- dt.pruned.FPR.TPR.AUC.NEB.HEK %>% dplyr::filter(FPR==fpr & str_detect(Benchmark,"GLORI_HEK293")) %>%
    dplyr::select(FPR,TPR,cutoff,Method,ComboName,optionID) %>%
    dplyr::arrange(Method,ComboName,optionID) %>% dplyr::filter(TPR>0 & !is.na(cutoff)) %>%
    inner_join(x=.,y=dt.selected.method.option %>% distinct(ComboID,Method,ComboName,optionID))
  if(nrow(dt.cutoff.FPR)>0){
    #obtain m6a at FPR cutoff
    dt.m6a.FPR <- foreach(M=unique(dt.cutoff.FPR$Method),.combine='rbind')%do%{
      foreach(combo = dt.cutoff.FPR[Method==M,unique(ComboName)], .combine='rbind')%do%{
        message(paste0("Obtain peak at FPR<=",fpr," for ", M, " ", combo, " ", dt.cutoff.FPR[Method==M & ComboName==combo,optionID]))
        intensity.files <- list.files(paste0("/data/m6A_calling_strategy/RIPPeakS_NEB/Intensity/",M,"_",combo),pattern = "allOption.tsv",full.names = T)
        names(intensity.files) <- list.files(paste0("/data/m6A_calling_strategy/RIPPeakS_NEB/Intensity/",M,"_",combo),pattern = "allOption.tsv",full.names = F) %>%
          str_replace(pattern="Bedtools_intensity_",replacement = "") %>% str_replace(pattern="_allOption.tsv",replacement = "")
        intensity.files <- intensity.files[names(intensity.files)]
        dt.intensity <- foreach(s=names(intensity.files),.combine='rbind')%do%{fread(file = intensity.files[s]) %>% mutate(Sample=s)}#load intensity for all sample
        dt.intensity <- dt.intensity %>% dplyr::select(name,Sample,paste0(c("pos__","neg__"), dt.cutoff.FPR[Method==M & ComboName==combo,optionID]))
        colnames(dt.intensity) <- c("name","Sample","pos","neg")
        #pull out m6a with intensity higher than cutoff at FPR20
        #filtered and un overlapped  m6a at pos strand
        dt.m6a.filtered.pos <- dt.intensity %>% dplyr::filter(pos >= dt.cutoff.FPR[Method==M & ComboName==combo,cutoff])
        if(nrow(dt.m6a.filtered.pos)>0){
          dt.m6a.filtered.pos <- dt.m6a.filtered.pos %>% dplyr::mutate(name = name %>% strsplit(split=paste0(M,"_"),fixed=T) %>% sapply(tail,1)) %>%
            dplyr::mutate(seqnames=name %>% strsplit(split="_",fixed=T) %>% sapply("[",1),
                          start=name %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                          end=name %>% strsplit(split="_",fixed=T) %>% sapply("[",3),
                          strand="+") %>%
            dplyr::select(seqnames,start,end,name,score=pos,strand,Sample)
          dt.m6a.filtered.pos.gr <- GenomicRanges::makeGRangesFromDataFrame(dt.m6a.filtered.pos,keep.extra.columns = T)
          dt.m6a.filtered.pos.merged <- foreach(sam = unique(dt.m6a.filtered.pos$Sample), .combine='rbind')%do%{
            GenomicRanges::reduce(dt.m6a.filtered.pos.gr[dt.m6a.filtered.pos.gr$Sample==sam,]) %>% as.data.table() %>%
              mutate(score=1000,name=paste(seqnames,start,end,strand,sep="_"),Sample=sam) %>%
              dplyr::select(seqnames,start,end,name,score,strand,Sample)
          }
        }else{
          dt.m6a.filtered.pos.merged <- data.table(seqnames=NULL,start=NULL,end=NULL,name=NULL,score=NULL,strand=NULL,Sample=NULL)
        }
        #filtered  and un overlapped m6a at neg strand
        dt.m6a.filtered.neg <- dt.intensity %>% dplyr::filter(neg >= dt.cutoff.FPR[Method==M & ComboName==combo,cutoff])
        if(nrow(dt.m6a.filtered.neg)>0){
          dt.m6a.filtered.neg <- dt.m6a.filtered.neg %>% dplyr::mutate(name = name %>% strsplit(split=paste0(M,"_"),fixed=T) %>% sapply(tail,1)) %>%
            dplyr::mutate(seqnames=name %>% strsplit(split="_",fixed=T) %>% sapply("[",1),
                          start=name %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                          end=name %>% strsplit(split="_",fixed=T) %>% sapply("[",3),
                          strand="-") %>%
            dplyr::select(seqnames,start,end,name,score=neg,strand,Sample)
          dt.m6a.filtered.neg.gr <- GenomicRanges::makeGRangesFromDataFrame(dt.m6a.filtered.neg,keep.extra.columns = T)
          dt.m6a.filtered.neg.merged <- foreach(sam = unique(dt.m6a.filtered.neg$Sample), .combine='rbind')%do%{
            GenomicRanges::reduce(dt.m6a.filtered.neg.gr[dt.m6a.filtered.neg.gr$Sample==sam,]) %>% as.data.table() %>%
              mutate(score=1000,name=paste(seqnames,start,end,strand,sep="_"),Sample=sam) %>%
              dplyr::select(seqnames,start,end,name,score,strand,Sample)
          }
        }else{
          dt.m6a.filtered.neg.merged <- data.table(seqnames=NULL,start=NULL,end=NULL,name=NULL,score=NULL,strand=NULL,Sample=NULL)
        }
        dt.m6a.filtered <- rbind(dt.m6a.filtered.pos.merged, dt.m6a.filtered.neg.merged)
        #calculate exonic sum width to filter extreme long peak (<=6kb)
        dt.m6a.filtered.sumwidth <- LongPeakRemoveIntron(dt.peak = dt.m6a.filtered,
                                                         dt.intron = fread("/data/m6A_calling_strategy/RIPPeakS_resource/dt.intron.hg38.bed"),
                                                         genome_file = "/data/m6A_calling_strategy/RIPPeakS_resource/chrNameLength_hg38.txt")
        dt.m6a.filtered <- dt.m6a.filtered %>% left_join(x=.,y=dt.m6a.filtered.sumwidth  %>% dplyr::distinct(Sample,name,SumWidth), by=c("Sample","name")) %>%
          dplyr::mutate(SumWidth=case_when(is.na(SumWidth) ~ 0, .default = SumWidth))
        #the overlap gene
        dt.m6a.filtered.overlapped.gene <- bt.intersect(a=dt.m6a.filtered, b=fread("/data/m6A_calling_strategy/RIPPeakS_resource/hg38_gencode.gene.bed"),
                                                        s=T, f=0.5, F=0.8, c=T,e = T) %>% as.data.table()
        dt.m6a.filtered <- dt.m6a.filtered %>% left_join(x=.,y=dt.m6a.filtered.overlapped.gene %>% dplyr::select(name=V4,Sample=V7,OverlappedNoGene=V9) %>%
                                                           dplyr::distinct(Sample,name,OverlappedNoGene), by=c("Sample","name"))
        dt.m6a.filtered %>% mutate(Method=M, ComboName=combo, optionID=dt.cutoff.FPR[Method==M & ComboName==combo,optionID])
      }
    }
    message(paste0("Merge peak at FPR<=",fpr))
    #merge m6a
    dt.unmerged.m6a <- dt.m6a.FPR %>% dplyr::filter(!(SumWidth>3000 & OverlappedNoGene>2))
    #dt.topn.m6a[SumWidth<=6000,.N,by=.(Sample,Method,ComboName,optionID)]
    #merge together
    dt.m6a.filtered.pos <- dt.unmerged.m6a %>% dplyr::filter(strand=="+") %>% dplyr::select(seqnames,start,end,name,score,strand,Sample) %>% distinct()
    if(nrow(dt.m6a.filtered.pos)>0){
      dt.m6a.filtered.pos.gr <- GenomicRanges::makeGRangesFromDataFrame(dt.m6a.filtered.pos,keep.extra.columns = T)
      dt.m6a.filtered.pos.merged <- foreach(sam = unique(dt.m6a.filtered.pos$Sample), .combine='rbind')%do%{
        GenomicRanges::reduce(dt.m6a.filtered.pos.gr[dt.m6a.filtered.pos.gr$Sample==sam,]) %>% as.data.table() %>%
          mutate(score=1000,name=paste(seqnames,start,end,strand,sep="_"),Sample=sam) %>%
          dplyr::select(seqnames,start,end,name,score,strand,Sample)
      }
    }else{
      dt.m6a.filtered.pos.merged <- data.table(seqnames=NULL,start=NULL,end=NULL,name=NULL,score=NULL,strand=NULL,Sample=NULL)
    }
    #filtered  and un overlapped m6a at neg strand
    dt.m6a.filtered.neg <- dt.unmerged.m6a %>% dplyr::filter(strand=="-") %>% dplyr::select(seqnames,start,end,name,score,strand,Sample) %>% distinct()
    if(nrow(dt.m6a.filtered.neg)>0){
      dt.m6a.filtered.neg.gr <- GenomicRanges::makeGRangesFromDataFrame(dt.m6a.filtered.neg,keep.extra.columns = T)
      dt.m6a.filtered.neg.merged <- foreach(sam = unique(dt.m6a.filtered.neg$Sample), .combine='rbind')%do%{
        GenomicRanges::reduce(dt.m6a.filtered.neg.gr[dt.m6a.filtered.neg.gr$Sample==sam,]) %>% as.data.table() %>%
          mutate(score=1000,name=paste(seqnames,start,end,strand,sep="_"),Sample=sam) %>%
          dplyr::select(seqnames,start,end,name,score,strand,Sample)
      }
    }else{
      dt.m6a.filtered.neg.merged <- data.table(seqnames=NULL,start=NULL,end=NULL,name=NULL,score=NULL,strand=NULL,Sample=NULL)
    }
    dt.m6a.filtered <- rbind(dt.m6a.filtered.pos.merged, dt.m6a.filtered.neg.merged)
    #calculate exonic sum width to filter extreme long peak (<=6kb)
    dt.m6a.filtered.sumwidth <- LongPeakRemoveIntron(dt.peak = dt.m6a.filtered,
                                                     dt.intron = fread("/data/m6A_calling_strategy/RIPPeakS_resource/dt.intron.hg38.bed"),
                                                     genome_file = "/data/m6A_calling_strategy/RIPPeakS_resource/chrNameLength_hg38.txt")
    dt.m6a.filtered <- dt.m6a.filtered %>% left_join(x=.,y=dt.m6a.filtered.sumwidth  %>% dplyr::distinct(Sample,name,SumWidth), by=c("Sample","name")) %>%
      dplyr::mutate(SumWidth=case_when(is.na(SumWidth) ~ 0, .default = SumWidth))
    #check the overlapped gene count of merged m6a
    gene.bed.file <- "/data/m6A_calling_strategy/RIPPeakS_resource/hg38_gencode.gene.bed"
    dt.m6a.filtered.overlapped.gene <- bt.intersect(a=dt.m6a.filtered, b=fread(gene.bed.file),s=T, f=0.5, F=0.8, c=T,e = T) %>% as.data.table()
    #dt.m6a.filtered.overlapped.gene[,.N,by=.(Sample=V7,nGene=V9)] %>% dplyr::arrange(Sample,nGene)
    #filter out merged peak with more than two genes and exonic width over 3kb
    dt.m6a.notkept <- dt.m6a.filtered.overlapped.gene[V9>2 & V8>3000,]
    #dt.m6a.notkept <- dt.m6a.filtered.overlapped.gene[V9>1,]
    dt.m6a.filtered <- dt.m6a.filtered %>% dplyr::filter(!name %in% dt.m6a.notkept$V4) %>% dplyr::filter(str_detect(seqnames,"chr")) #key filtering
    #obtain the intersect of GLORI_HEK293 m6a site
    dt.m6a.overlap <- bedtoolsr::bt.intersect(a=dt.m6a.filtered, b=m6A.site.list[["GLORI_HEK293"]][,1:6], s=T, wo=T) %>% as.data.table() %>% distinct()
    dt.benchmark.gene <- m6A.site.list[["GLORI_HEK293"]] %>% tidyr::separate_longer_delim(OverlappedGenes,delim = "|") %>% as.data.table()
    benchmark.gene <- unique(dt.benchmark.gene[OverlappedGenes!="",OverlappedGenes])
    dt.m6a.overlapgene <- bt.intersect(a=dt.m6a.filtered, b=fread(gene.bed.file),s=T, f=0.5, F=0.8, wo=T,e = T) %>% as.data.table()
    #calculate TPR and FPR
    message(paste0("Finished TPR/FPR for merged m6a at FPR<=",fpr))
    dt.TPR.FPR <- foreach(width.cut = c(Inf),.combine='rbind')%do%{
      dt.m6a.overlap %>% dplyr::filter(V8<=width.cut) %>%  group_by(Sample=V7) %>% mutate(nTP=n_distinct(V4), nSite=n_distinct(V12), TPR=n_distinct(V12)/nrow(m6A.site.list[["GLORI_HEK293"]])) %>%
        as.data.table() %>% distinct(Sample,nTP,nSite,TPR) %>% left_join(x=.,y=dt.m6a.filtered[SumWidth<=width.cut,list(nPeak=.N),by=.(Sample)],by=c("Sample")) %>% mutate(FPR=1-nTP/nPeak) %>%
        mutate(Strategy="MePeakS", InvolvedMethod=dt.selected.method.option$Method %>% unique() %>% paste(collapse = ","),
               FPR=round(FPR,2), TPR=round(TPR,2)) %>% mutate(LongPeak=paste0("<=",round(width.cut/1000),"kb"))
    } %>% mutate(MergedFPR=fpr)
    message("The average TPR of merged m6a at FPR<=",fpr, " is ", mean(dt.TPR.FPR$TPR))
    dt.genelevel.TPR.FPR <- foreach(width.cut = c(Inf),.combine='rbind')%do%{
      dt.m6a.overlapgene %>% dplyr::filter(V8<=width.cut) %>%  group_by(Sample=V7) %>% mutate(nTP=n_distinct(V12[V12 %in% benchmark.gene]), nGene=n_distinct(V12)) %>%
        mutate(FPR=round(1-nTP/nGene,2), TPR=round(nTP/length(benchmark.gene),2)) %>%
        as.data.table() %>% distinct(Sample,nTP,nGene,TPR,FPR) %>%
        mutate(Strategy="MePeakS", InvolvedMethod=dt.selected.method.option$Method %>% unique() %>% paste(collapse = ","),
               FPR=round(FPR,2), TPR=round(TPR,2)) %>% mutate(LongPeak=paste0("<=",round(width.cut/1000),"kb"))
    } %>% mutate(MergedFPR=fpr)
    message("The average TPR of merged m6a at FPR<=",fpr, " is ", mean(dt.TPR.FPR$TPR))
    dt.TPR.FPR %>% left_join(x=.,y=dt.genelevel.TPR.FPR %>% dplyr::select(Sample,nTP_gene=nTP,nGene,TPR_gene=TPR,FPR_gene=FPR),by=c("Sample"))
  }
}
saveRDS(dt.TPR.FPR.selected.method.option, file="dt.HEK.NEB.TPR.FPR.M6APeakS.RDS")
}
#determine the optimal cutoff
source("/data/m6A_calling_strategy/Script/Wrapper_function_for_m6A_calling_using_MACS2SMePeak.R")
dt.HEK.NEB.TPR.FPR.M6APeakS <- readRDS("dt.HEK.NEB.TPR.FPR.M6APeakS.RDS")
