  dt.selected.method.option %>% distinct(Method,ComboName,optionID) %>% mutate(MergedFPR=dt.optimal.cutoff[Mode=="Strict",cutoff]) %>% mutate(MergedFPR=round(MergedFPR,2)) %>%
