               by=c("MergedFPR"="FPR","Method","ComboName","optionID")) %>% dplyr::filter(!is.na(cutoff) & TPR>0) %>%
    mutate(M6APeakS.mode="Strict", Mode.FPR=dt.optimal.cutoff[Mode=="Strict",FPR], Mode.TPR=dt.optimal.cutoff[Mode=="Strict",TPR]),
  dt.selected.method.option %>% distinct(Method,ComboName,optionID) %>% mutate(MergedFPR=dt.optimal.cutoff[Mode=="Moderate",cutoff]) %>% mutate(MergedFPR=round(MergedFPR,2)) %>%
    inner_join(x=.,y=dt.pruned.FPR.TPR.AUC.Abcam.HEK %>% mutate(FPR=round(FPR,2)) %>% dplyr::filter(str_detect(Benchmark,"GLORI_HEK")) %>% dplyr::select(Method,ComboName,optionID,FPR,TPR,cutoff) %>% distinct(),
               by=c("MergedFPR"="FPR","Method","ComboName","optionID")) %>% dplyr::filter(!is.na(cutoff) & TPR>0) %>%
    mutate(M6APeakS.mode="Moderate", Mode.FPR=dt.optimal.cutoff[Mode=="Moderate",FPR], Mode.TPR=dt.optimal.cutoff[Mode=="Moderate",TPR]),
  dt.selected.method.option %>% distinct(Method,ComboName,optionID) %>% mutate(MergedFPR=dt.optimal.cutoff[Mode=="Sensitive",cutoff]) %>% mutate(MergedFPR=round(MergedFPR,2)) %>%
    inner_join(x=.,y=dt.pruned.FPR.TPR.AUC.Abcam.HEK %>% mutate(FPR=round(FPR,2)) %>% dplyr::filter(str_detect(Benchmark,"GLORI_HEK")) %>% dplyr::select(Method,ComboName,optionID,FPR,TPR,cutoff) %>% distinct(),
               by=c("MergedFPR"="FPR","Method","ComboName","optionID")) %>% dplyr::filter(!is.na(cutoff) & TPR>0) %>%
    mutate(M6APeakS.mode="Sensitive", Mode.FPR=dt.optimal.cutoff[Mode=="Sensitive",FPR], Mode.TPR=dt.optimal.cutoff[Mode=="Sensitive",TPR])
) %>% dplyr::arrange(M6APeakS.mode,Method,ComboName) %>% mutate(Antibody="Abcam",Benchmark="GLORI_HEK")
