########### prepare cutoff at all FPR for five M6APeakS mode ############
dt.cutoff.at.all.FPR.M6APeakS <- foreach(MODE=c("NEB","SYSY","Abcam","Millipore","NEB_HeLa"),.combine='rbind')%do%{
  dt.cutoff <- readRDS(paste0("dt.selected.combo.cutoff.M6APeakS_", MODE, ".at.all.FPR.RDS")) %>% mutate(FPR=round(FPR,2),TPR=round(TPR,2)) %>%
    mutate(M6APeakModel=MODE)
  if(MODE=="Millipore"){FPR_max  <- 0.4}else{FPR_max <- 0.3}
  dt.selected.cutoff <- list(dt.cutoff %>% mutate(TPRmFPR=TPR-FPR, maxTPRmFPR=max(TPR-FPR)) %>%  dplyr::filter(TPRmFPR == maxTPRmFPR & FPR<= FPR_max) %>%
                        dplyr::arrange(desc(TPR)) %>% distinct(MergedFPR,FPR,TPR,TPRmFPR,maxTPRmFPR) %>% slice_head(n=1) %>% mutate(Mode="Moderate"),
                        dt.cutoff %>% mutate(TPRmFPR=TPR-FPR, maxTPRmFPR=max(TPR-FPR)) %>%  dplyr::filter(TPRmFPR >= maxTPRmFPR-0.05 & FPR<= FPR_max) %>%
                          dplyr::arrange(desc(TPR),FPR) %>% distinct(MergedFPR,FPR,TPR,TPRmFPR,maxTPRmFPR) %>% slice_head(n=1) %>% mutate(Mode="Sensitive"),
                        dt.cutoff %>% mutate(TPRmFPR=TPR-FPR, maxTPRmFPR=max(TPR-FPR)) %>%  dplyr::filter(TPRmFPR >= maxTPRmFPR-0.05 & FPR<= FPR_max) %>%
                          dplyr::arrange(FPR,desc(TPR)) %>% distinct(MergedFPR,FPR,TPR,TPRmFPR,maxTPRmFPR) %>% slice_head(n=1) %>% mutate(Mode="Strict")) %>%
                       Reduce(x=.,rbind)
  dt.cutoff %>% mutate(TPRmFPR=TPR-FPR, maxTPRmFPR=max(TPR-FPR)) %>%  left_join(x=., y=dt.selected.cutoff)
}
dt.cutoff.at.all.FPR.M6APeakS %>% dplyr::filter(!is.na(Mode)) %>% distinct(M6APeakModel,Mode,MergedFPR,FPR,TPR,TPRmFPR,maxTPRmFPR)
