#2. the cor and pvalue of top10 dimension most correlated method combo option at both direction
#3. the determine of selected method combo with best performance
#4. M6APeakS site-level AUC is higher than each method's best combo option (GLORI_HEK293)
#load pruned TPR/FPR
dt.method.combo <- readRDS("dt.method.combo.filtered.RDS")
attr(dt.method.combo,"groups") <- NULL
source("/data/m6A_calling_strategy/Script/Wrapper_function_for_m6A_calling_using_MACS2SMePeak.R")
#load pruned TPR FPR
dt.pruned.FPR.TPR.AUC.NEB.HEK <- readRDS("dt.pruned.FPR.TPR.AUC.NEB.HEK.RDS")
#determine the best option for 285 combo
dt.top.option.method.combo <- dt.pruned.FPR.TPR.AUC.NEB.HEK %>% distinct(Method,ComboName,optionID,Benchmark,AUC.scaled,TPR20,maxTPRmFPR) %>% dplyr::filter(str_detect(Benchmark,"GLORI_HEK293")) %>%
  group_by(Method,ComboName) %>% dplyr::arrange(desc(AUC.scaled)) %>% mutate(AUC.rank=1:n()) %>%
  dplyr::arrange(desc(TPR20)) %>% mutate(TPR.rank=1:n(), maxTPR20=max(TPR20)) %>% as.data.table() %>% distinct(Method,ComboName,optionID,AUC.scaled,TPR20,maxTPRmFPR,AUC.rank,TPR.rank,maxTPR20) %>%
  group_by(Method,ComboName) %>% dplyr::filter(TPR20>=(maxTPR20-0.05)) %>% slice_min(AUC.rank) %>% as.data.table() %>% dplyr::arrange(desc(AUC.scaled))
dt.method.best <- dt.top.option.method.combo %>% group_by(Method) %>% dplyr::arrange(desc(AUC.scaled)) %>% mutate(AUC.rank=1:n()) %>%
  dplyr::arrange(desc(TPR20)) %>% mutate(TPR.rank=1:n(), maxTPR20=max(TPR20)) %>%
  dplyr::filter(TPR20>=(maxTPR20-0.05)) %>% slice_min(AUC.rank) %>% as.data.table() %>% dplyr::arrange(desc(AUC.scaled))
