######### validate the performance of RIPPeakS ###############
#load RIPPeakS peak of HEK293 NEB mRNA and IVT samples
Samples <- list.files(path="/data/m6A_calling_strategy/RIPPeakS/",pattern="Peak_HEK_NEB") %>% str_replace(pattern="Peak_",replacement = "")
dt.RIPPeakS.HEK293.NEB <- foreach(s=Samples,.combine='rbind')%do%{
  dt.peak.sensitive <- fread(paste0("/data/m6A_calling_strategy/RIPPeakS/Peak_",s,"/SensitiveMode_peak.bed")) %>% mutate(Mode="Sensitive")
  dt.peak.strict <- fread(paste0("/data/m6A_calling_strategy/RIPPeakS/Peak_",s,"/StrictMode_peak.bed")) %>% mutate(Mode="Strict")
  rbind(dt.peak.sensitive,dt.peak.strict)
}
#load benchmark m6As
dt.HEK293.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.HEK293.benchmark.m6As.RDS")
dt.mESC.benchmark.m6As <- readRDS(file="/data/m6A_calling_strategy/Benchmark_m6As/dt.mESC.benchmark.m6As.RDS")
dt.benchmark.m6As <- rbind(dt.HEK293.benchmark.m6As,dt.mESC.benchmark.m6As)
m6A.site.list <- foreach(i=unique(dt.benchmark.m6As$Sample))%do%{dt.benchmark.m6As[Sample==i,1:6]}
names(m6A.site.list) <- unique(dt.benchmark.m6As$Sample)
#benchmark
dt.TPR.FPR.RIPPeakS.HEK293.NEB <- foreach(s=Samples,.combine='rbind')%do%{
  foreach(mode=c("Sensitive","Strict"),.combine='rbind')%do%{
    foreach(b = names(m6A.site.list) %>% grep(pattern="HEK",value=T),.combine='rbind')%do%{
      dt.m6a <- dt.RIPPeakS.HEK293.NEB %>% dplyr::filter(Sample==s & Mode==mode)
      #calculate exonic width
      dt.m6a.intron.width <- LongPeakRemoveIntron(dt.peak=dt.m6a,
                           genome_file = "/data/m6A_calling_strategy/RIPPeakS_resource/chrNameLength_hg38.txt",
                           dt.intron=fread("/data/m6A_calling_strategy/RIPPeakS_resource/dt.intron.hg38.bed"))
      dt.m6a.filtered <- dt.m6a %>% dplyr::filter(name %in% dt.m6a.intron.width[SumWidth<=6000,unique(name)])
      dt.merged.peak.benchmark.overlap <- bedtoolsr::bt.intersect(a=dt.m6a.filtered, b=m6A.site.list[[b]][,1:6], s=T, wo=T) %>% as.data.table() %>% distinct()
      dt.merged.peakcount <- dt.m6a.filtered[,.(nPeak=n_distinct(name,score,strand)),by=.(Sample)]
      dt.merged.TPR.FPR <- dt.merged.peak.benchmark.overlap[,.(TP=n_distinct(V4,V5,V6), TP.sites=n_distinct(V11,V12,V13)),by=.(Sample=V7)] %>%
        left_join(x=.,y=dt.merged.peakcount,by=c("Sample")) %>% mutate(FPR=1-TP/nPeak, TPR=TP.sites/nrow(m6A.site.list[[b]]))
      dt.merged.TPR.FPR %>% mutate(Benchmark=b, Sample=s, Mode=mode)
    }
  }
}
