#calculate the IVT rates of NEB/SYSY/Abcam using default models
#SYSY antibody
#calculate IVT:peak that overlapped with IVT peak with bedtools intersect (a=mRNA peak, b=IVT peak, f=0.5 or cumulate overlap portion higher than 50%)
peak.files <- list.files("/data/m6A_calling_strategy/M6APeakS_SYSY/",pattern="M6APeakS_peak",full.names = T)
names(peak.files) <- list.files("/data/m6A_calling_strategy/M6APeakS_SYSY/",pattern="M6APeakS_peak",full.names = F) %>%
  strsplit(split="_M6APeakS_peak") %>% sapply(head,1)
dt.SYSY.M6APeakS.peak <- foreach(f = names(peak.files), .combine='rbind')%do%{
  fread(peak.files[f],header=T)
}
dt.SYSY.M6APeakS.peak[,.N,by=Sample]
#            Sample     N
# 1:  HEK_SYSY_IVT1  6326
# 2:  HEK_SYSY_IVT2  6465
# 3: HEK_SYSY_mRNA1 11026
# 4: HEK_SYSY_mRNA2 11355
dt.IVTrate.M6APeakS.SYSY <- foreach(sam = names(peak.files) %>% grep(pattern="IVT",invert = T,value=T), .combine='rbind')%do%{
  foreach(ivt = names(peak.files) %>% grep(pattern="IVT",invert = F,value=T), .combine='rbind')%do%{
    foreach(cutoff= c(0.5,0.8), .combine='rbind')%do%{
      dt.intersect <- bedtoolsr::bt.intersect(a=dt.SYSY.M6APeakS.peak[Sample==sam,], b=dt.SYSY.M6APeakS.peak[Sample==ivt,], s=T, f=cutoff,wo=T) %>% as.data.table()
      #data.table(Sample=sam, IVTSample=ivt, OverlapCutoff = cutoff, IVTrate=round(length(unique(dt.intersect$V4))/nrow(dt.SYSY.M6APeakS.peak[Sample==sam,1:6]),2))
      dt.IVToverlapped.m6a <- dt.intersect[,1:8] %>% distinct()
      colnames(dt.IVToverlapped.m6a) <- colnames(dt.SYSY.M6APeakS.peak[Sample==sam,])
      dt.nonIVToverlapped.m6a <- dt.SYSY.M6APeakS.peak[Sample==sam,] %>% dplyr::filter(!name %in% dt.IVToverlapped.m6a$name)
      #calculate the FPR/TPR of IVT+ and IVT- m6A
      dt.m6a.filtered <- dt.SYSY.M6APeakS.peak[Sample==sam,] %>% mutate(IVToverlapped=name %in% dt.IVToverlapped.m6a$name)
      #obtain the intersect of GLORI_mESC m6a site
      benchmark.bed <- "/data/m6A_calling_strategy/RIPPeakS_resource/dt.benchmark.GLORI_HEK293.m6As.bed"
      org.genebed <- "/data/m6A_calling_strategy/RIPPeakS_resource/hg38_gencode.gene.bed"
      dt.m6a.overlap <- bedtoolsr::bt.intersect(a=dt.m6a.filtered, b=fread(benchmark.bed)[,1:6], s=T, wo=T) %>% as.data.table() %>% distinct()
      dt.benchmark.sites <- fread(benchmark.bed)[,c(1:6,9)]
      dt.benchmark.gene <- fread(benchmark.bed)[,c(1:6,9)] %>% dplyr::rename(OverlappedGenes=V9) %>%
        tidyr::separate_longer_delim(OverlappedGenes,delim = "|") %>% as.data.table()
      benchmark.gene <- unique(dt.benchmark.gene[OverlappedGenes!="",OverlappedGenes])
      dt.m6a.overlapgene <- bt.intersect(a=dt.m6a.filtered, b=fread(org.genebed),s=T, f=0.5, F=0.8, wo=T,e = T) %>% as.data.table()
      #calculate TPR and FPR
      dt.TPR.FPR <- foreach(width.cut = c(Inf),.combine='rbind')%do%{
        foreach(ivtoverlap = c(TRUE, FALSE, "all"), .combine='rbind')%do%{
        if(ivtoverlap == "all"){
          dt.m6a.overlap %>% dplyr::filter(V8<=width.cut) %>%  group_by(Sample=V7) %>% mutate(nTP=n_distinct(V4), nSite=n_distinct(V12), TPR=n_distinct(V12)/nrow(dt.benchmark.sites)) %>%
            as.data.table() %>% distinct(Sample,nTP,nSite,TPR) %>% left_join(x=.,y=dt.m6a.filtered[SumWidth<=width.cut,list(nPeak=.N),by=.(Sample)],by=c("Sample")) %>% mutate(FPR=1-nTP/nPeak) %>%
            mutate(IVToverlapped=ivtoverlap,FPR=round(FPR,2), TPR=round(TPR,2)) %>% mutate(LongPeak=paste0("<=",round(width.cut/1000),"kb"))
          }else{
            dt.m6a.overlap %>% dplyr::filter(V8<=width.cut & V9==ivtoverlap) %>%  group_by(Sample=V7) %>% mutate(nTP=n_distinct(V4), nSite=n_distinct(V12), TPR=n_distinct(V12)/nrow(dt.benchmark.sites)) %>%
              as.data.table() %>% distinct(Sample,nTP,nSite,TPR) %>% left_join(x=.,y=dt.m6a.filtered[SumWidth<=width.cut & IVToverlapped==ivtoverlap,list(nPeak=.N),by=.(Sample)],by=c("Sample")) %>% mutate(FPR=1-nTP/nPeak) %>%
              mutate(IVToverlapped=ivtoverlap,FPR=round(FPR,2), TPR=round(TPR,2)) %>% mutate(LongPeak=paste0("<=",round(width.cut/1000),"kb"))
          }

        }
      } %>% mutate(nSite_per_nPeak=round(nSite/nPeak,2), nSite_per_nTP=round(nSite/nTP,2))
      dt.genelevel.TPR.FPR <- foreach(width.cut = c(Inf),.combine='rbind')%do%{
        foreach(ivtoverlap = c(TRUE, FALSE, "all"), .combine='rbind')%do%{
          if(ivtoverlap=="all"){
            dt.m6a.overlapgene %>% dplyr::filter(V8<=width.cut) %>%  group_by(Sample=V7) %>% mutate(nTP=n_distinct(V13[V13 %in% benchmark.gene]), nGene=n_distinct(V13)) %>%
              mutate(FPR=round(1-nTP/nGene,2), TPR=round(nTP/length(benchmark.gene),2)) %>%
              as.data.table() %>% distinct(Sample,nTP,nGene,TPR,FPR) %>%
              mutate(IVToverlapped=ivtoverlap,FPR=round(FPR,2), TPR=round(TPR,2)) %>% mutate(LongPeak=paste0("<=",round(width.cut/1000),"kb"))
          }else{
            dt.m6a.overlapgene %>% dplyr::filter(V8<=width.cut & V9==ivtoverlap) %>%  group_by(Sample=V7) %>% mutate(nTP=n_distinct(V13[V13 %in% benchmark.gene]), nGene=n_distinct(V13)) %>%
              mutate(FPR=round(1-nTP/nGene,2), TPR=round(nTP/length(benchmark.gene),2)) %>%
              as.data.table() %>% distinct(Sample,nTP,nGene,TPR,FPR) %>%
              mutate(IVToverlapped=ivtoverlap,FPR=round(FPR,2), TPR=round(TPR,2)) %>% mutate(LongPeak=paste0("<=",round(width.cut/1000),"kb"))
          }
        }
      }
      dt.TPR.FPR %>% left_join(x=.,y=dt.genelevel.TPR.FPR %>% dplyr::select(Sample,IVToverlapped,nTP_gene=nTP,nGene,TPR_gene=TPR,FPR_gene=FPR),by=c("Sample","IVToverlapped")) %>%
        mutate(IVTsample=ivt) %>% mutate(OverlapCutoff=cutoff) %>% dplyr::select(Sample,IVTsample,OverlapCutoff,everything())
    }
  }
}
