#the IVT rate and TPR/FPR after using the m6A-calibrate package
require(m6ACalibrateR)
#model type: Abcam, NEB, SYSY, ensemble(average)
#FPR_threshold:0-1, smaller value indicate stricter filtering, default 0.5
#filter mode : directFilter, strictFilter, flankExclusion
org.txdb <- makeTxDbFromGFF("/home/huangp/genome_db/gencode.v44.annotation.gtf")

dt.calibrateR.M6APeakS.SYSY <- foreach(sam=unique(dt.IVTrate.M6APeakS.SYSY$Sample) %>% grep(pattern="IVT",invert = T,value=T), .combine='rbind')%do%{
  foreach(cutoff=seq(0.5,1,by=0.25), .combine='rbind')%do%{
    foreach(mode=c("directFilter", "strictFilter", "flankExclusion")[1:2], .combine='rbind')%do%{
      t1 <- Sys.time()
      message(paste0("Satrt m6a calibrate for ",  sam," at FPR_threshold:",cutoff, " model_type:SYSY filter_mode:",  mode))
      gr.before <- makeGRangesFromDataFrame(dt.SYSY.M6APeakS.peak[Sample==sam,],keep.extra.columns = T)
      gr.after <- m6ACalibrateR::m6ACalibrate(x=gr.before,
                                              #gff = "/home/huangp/genome_db/gencode.v44.annotation.gtf",
                                              txdb=org.txdb,
                                              genome = "hg38",
                                              model_type = "SYSY",
                                              FP_threshold = cutoff,
                                              filter_mode = mode)
      diff.time <- Sys.time()-t1
      message(paste0("Finished m6a calibrate for ", sam, " at FPR_threshold:",cutoff, " model_type:SYSY filter_mode:",  mode, " used ", round(as.numeric(diff.time),2), attr(diff.time,"unit")))
      message("npeak before:", length(gr.before), " v.s npeak after:",length(gr.after))
      dt.gr.after <- as.data.table(gr.after) %>% mutate(Sample=sam, FPR_threshold=cutoff, CalibrateMode=mode)
      dt.gr.after
    }
  }
}
saveRDS(dt.calibrateR.M6APeakS.SYSY, file="dt.calibrateR.M6APeakS.SYSY.RDS")
