setwd("/data2/CRC_m6A/Analysis/")
source("/data/m6A_calling_strategy/Script/Wrapper_function_for_m6A_calling_using_MACS2SMePeak.R")
#load reported m6A in original GEO:GSE247632
bed.files <- list.files("/data2/CRC_m6A/GSE247632_peak/",pattern="(bed)$",full.names = T)
names(bed.files) <- list.files("/data2/CRC_m6A/GSE247632_peak/",pattern="(bed)$",full.names = F) %>%
  strsplit(split="_",fixed=T) %>% sapply(tail,1) %>% strsplit(split="IPVS",fixed=T) %>% sapply(head,1)
names(bed.files) <- names(bed.files) %>% str_replace(pattern="C",replacement = "CRC") %>% str_replace(pattern="N",replacement = "NT")
dt.gene.annot <- gffToGRanges("/data/m6A_calling_strategy/RIPPeakS_resource/gencode.v44.annotation.gtf") %>% as.data.table()
dt.gene.annot <- dt.gene.annot %>% dplyr::select(gene_id,gene_name,gene_type) %>% distinct()
dt.m6a.GSE247632 <- foreach(s = names(bed.files),.combine='rbind')%do%{
  dt.m6a <- fread(bed.files[s]) %>% dplyr::select(seqnames="#chr",start=chromStart, end=chromEnd, score=fold_enrchment, strand) %>%
    mutate(Sample=s,name=paste(seqnames,start,end,strand,sep="_")) %>% dplyr::select(seqnames,start,end,name,score,strand,Sample) %>% distinct()
  #merged overlapped peaks together
  dt.m6a.reduced <- GenomicRanges::reduce(GenomicRanges::makeGRangesFromDataFrame(df=dt.m6a,keep.extra.columns = T),drop.empty.ranges = T) %>% as.data.table() %>%
    mutate(name=paste(seqnames,start,end,strand,sep="_"),score=1000) %>% dplyr::select(seqnames,start,end,name,score,strand)
  dt.overlap <- bedtoolsr::bt.intersect(a=dt.m6a.reduced,b=dt.m6a,s=T,wo=T) %>% as.data.table() %>% dplyr::select(name=V4, name.subset=V10, score.subset=V11) %>% distinct()
  dt.m6a.reduced <- dt.overlap %>% group_by(name) %>% mutate(score=mean(score.subset)) %>% as.data.table() %>% dplyr::select(name,score) %>% distinct() %>%
                    inner_join(x=.,y=dt.m6a.reduced %>% dplyr::select(-score), by=("name")) %>% dplyr::select(seqnames,start,end,name,score,strand)
  #exonic sumwidth
  dt.m6a.reduced.sumwidth <- LongPeakRemoveIntron(dt.peak = dt.m6a.reduced,
                                                   dt.intron = fread("/data/m6A_calling_strategy/RIPPeakS_resource/dt.intron.hg38.bed"),
                                                   genome_file = "/data/m6A_calling_strategy/RIPPeakS_resource/chrNameLength_hg38.txt")
  dt.m6a.reduced <- dt.m6a.reduced %>% left_join(x=.,y=dt.m6a.reduced.sumwidth  %>% dplyr::distinct(name,SumWidth), by=c("name")) %>%
    dplyr::mutate(SumWidth=case_when(is.na(SumWidth) ~ 0, .default = SumWidth))
  #overlap gene
  dt.m6a.overlapgene <- bt.intersect(a=dt.m6a.reduced[,1:6], b=fread("/data/m6A_calling_strategy/RIPPeakS_resource/hg38_gencode.gene.bed"),s=T, f=0.5, F=0.8, wo=T,e = T) %>% as.data.table()
  dt.m6a.overlapgene <- dt.m6a.overlapgene %>% dplyr::select(peak.name=V4, gene_id=V10) %>% distinct() %>% inner_join(x=.,y=dt.gene.annot,by=c("gene_id")) %>%
                        group_by(peak.name) %>% mutate(nOverlappedGenes=n_distinct(gene_id),OverlappedGenes=paste(gene_name,collapse = ",")) %>% as.data.table()
  dt.m6a.reduced <- dt.m6a.reduced %>% left_join(x=.,y=dt.m6a.overlapgene %>% distinct(peak.name,nOverlappedGenes,OverlappedGenes),by=c("name"="peak.name")) %>% mutate(Sample=s)
  print(dt.m6a.reduced %>% dplyr::filter((SumWidth>3000 & nOverlappedGenes>2)))
  dt.m6a.reduced
}
