dt.MeTPeak.novel.m6a <- foreach(s=unique(dt.MeTPeak.GSE.reported$Sample),.combine='rbind')%do%{
  dt.reported <- dt.MeTPeak.GSE.reported %>% dplyr::filter(Sample==s)
  dt.MeTPeak <- dt.MeTPeak.GSE.method %>%  dplyr::filter(Sample==s)
  dt.novel.MeTPeak <- bt.intersect( a=dt.MeTPeak,b=dt.reported, s=T, f=0.01,wa=T,v=T) %>% as.data.table()
  dt.novel.reported <- bt.intersect( a=dt.reported, b=dt.MeTPeak, s=T, f=0.01,wa=T,v=T) %>% as.data.table()
  data.table(Sample=s, nPeak.MeTPeak=nrow(dt.MeTPeak),nNovel.MeTPeak=n_distinct(dt.novel.MeTPeak$V4), nPeak.reported=nrow(dt.reported), nNovel.reported=n_distinct(dt.novel.reported$V4))
}
