dt.method.combo <- dt.method.combo %>% dplyr::filter(IsDefaultCombo==TRUE) %>% dplyr::filter(!(Method=="MeRIPtools" & ComboName=="Combo10"))
print(dt.method.combo)
if(!file.exists("/data2/CRC_m6A/Analysis/dt.CRC.MethodDefault.m6A.RDS")){
  dt.MethodDefault.m6A <- foreach(M=unique(dt.method.combo$Method), .combine='rbind')%do%{
    dt.m6a <- LoadPeakMethod(Method = M, Method.peak.dir = paste0("/data2/CRC_m6A/MethodDefault/", M, "_", dt.method.combo[Method==M,ComboName]))
    dt.m6a <- dt.m6a %>% mutate(Sample=Sample %>% strsplit(split="/",fixed=T) %>% sapply(tail,1))
    #infer the strandness of the detected MACS2 peak according to overlapped genes
    if(M=="MACS2"){
      dt.gene.bed <- fread("/data/m6A_calling_strategy/RIPPeakS_resource/hg38_gencode.gene.bed")
      dt.m6a.overlapped.gene <- bt.intersect(a=rbind(dt.m6a[,1:6] %>% mutate(strand="+") %>% mutate(name=paste(seqnames,start,end,sep="_")) %>% distinct(),
                                                     dt.m6a[,1:6] %>% mutate(strand="-") %>% mutate(name=paste(seqnames,start,end,sep="_")) %>% distinct()),
                                             b=dt.gene.bed, s=T, f=0.3,wo=T) %>% as.data.table()
      foreach(chr=unique(dt.m6a.overlapped.gene$V1) %>% grep(pattern="chr",value=T), .combine='rbind')%do%{
        message(paste0("infer strandness for ",which(unique(dt.m6a.overlapped.gene$V1)==chr), "th/",length(unique(dt.m6a.overlapped.gene$V1))))
        dt.m6a.strandness <- dt.m6a.overlapped.gene %>% dplyr::filter(V1==chr) %>% dplyr::select(name=V4,strand=V6,OverlapLength=V13)  %>% distinct() %>%
          group_by(name,strand) %>% slice_max(OverlapLength,n=1) %>% as.data.table()
        dt.m6a.chr <- dt.m6a %>% dplyr::filter(seqnames==chr) %>% mutate(name=paste(seqnames,start,end,sep="_")) %>% dplyr::select(name,score,Sample,Method) %>% distinct() %>%
          left_join(x=.,dt.m6a.strandness %>% dplyr::select(name,strand), by=c("name")) %>% dplyr::arrange(name,strand)
        dt.nongene.overlapped <- dt.m6a.chr %>% dplyr::filter(is.na(strand))
        dt.gene.overlapped <- dt.m6a.chr %>% dplyr::filter(!is.na(strand)) %>% dplyr::arrange(name,strand)
        dt.final.m6a.chr <- list(dt.gene.overlapped, dt.nongene.overlapped %>% mutate(strand="+"), dt.nongene.overlapped %>% mutate(strand="-")) %>% Reduce(x=.,rbind)
        dt.final.m6a.chr %>% mutate(seqnames=name %>% strsplit(split="_",fixed=T) %>% sapply("[",1), start=name %>% strsplit(split="_",fixed=T) %>% sapply("[",2),
                                    end=name %>% strsplit(split="_",fixed=T) %>% sapply("[",3), name=paste0(name,"_",strand)) %>%
          dplyr::select(seqnames,start,end,name,score,strand,Sample,Method)
      }
    }
    dt.m6a
  }
  saveRDS(dt.MethodDefault.m6A, file="/data2/CRC_m6A/Analysis/dt.CRC.MethodDefault.m6A.RDS")
}
