#enriched motif of m6As of two origin
dt.cmd.homer <- foreach(strategy=c("Raw", "Center500", "Center200", "Exonic"),.combine='c')%do%{
  if(strategy=="Raw"){
    m6a_peaks_M6APeakS <- dt.m6a.combined %>% dplyr::filter(Sample %in% dt.m6a.combined[Origin!="M6APeakS",unique(Sample)] & Origin=="M6APeakS") %>%
      distinct(seqnames,start,end,name,strand) %>% mutate(score=1000) %>% dplyr::select(seqnames,start,end,name,score,strand)
    dt.bed <- m6a_peaks_M6APeakS
  }else if(strategy=="Center500"){
    m6a_peaks_M6APeakS <- dt.m6a.combined %>% dplyr::filter(Sample %in% dt.m6a.combined[Origin!="M6APeakS",unique(Sample)] & Origin=="M6APeakS") %>%
      distinct(seqnames,start,end,name,strand) %>% mutate(score=1000) %>% dplyr::select(seqnames,start,end,name,score,strand)
    dt.bed <- m6a_peaks_M6APeakS %>% makeGRangesFromDataFrame() %>% resize(width = 500, fix = "center") %>% as.data.table() %>%
      mutate(score=1000,name=paste(seqnames,start,end,strand,sep="_")) %>% dplyr::select(seqnames,start,end,name,score,strand) %>% distinct()
  }else if(strategy=="Center200"){
    m6a_peaks_M6APeakS <- dt.m6a.combined %>% dplyr::filter(Sample %in% dt.m6a.combined[Origin!="M6APeakS",unique(Sample)] & Origin=="M6APeakS") %>%
      distinct(seqnames,start,end,name,strand) %>% mutate(score=1000) %>% dplyr::select(seqnames,start,end,name,score,strand)
    dt.bed <- m6a_peaks_M6APeakS %>% makeGRangesFromDataFrame() %>% resize(width = 200, fix = "center") %>% as.data.table() %>%
      mutate(score=1000,name=paste(seqnames,start,end,strand,sep="_")) %>% dplyr::select(seqnames,start,end,name,score,strand) %>% distinct()
  }else if(strategy == "Exonic"){
    m6a_peaks_M6APeakS <- dt.m6a.combined %>% dplyr::filter(Sample %in% dt.m6a.combined[Origin!="M6APeakS",unique(Sample)] & Origin=="M6APeakS") %>%
      distinct(seqnames,start,end,name,strand) %>% mutate(score=1000) %>% dplyr::select(seqnames,start,end,name,score,strand)
    dt.bed <- bedtoolsr::bt.subtract(a=m6a_peaks_M6APeakS,b=fread("/data/m6A_calling_strategy/RIPPeakS_resource/dt.intron.hg38.bed"),s=T) %>% as.data.table()
    colnames(dt.bed) <- c("seqnames","start","end","name","score","strand")
    dt.bed <- dt.bed %>% dplyr::filter(end-start>=50)
  }
  #prepare outdir
  dir <- paste0("/data2/CRC_m6A/Analysis/homer_",strategy)
  if(!dir.exists(dir)){dir.create(dir)}
  bed.file <- paste0("/data2/CRC_m6A/Analysis/m6a_peaks_M6APeakS_", strategy,".bed")
  fwrite(dt.bed,file=bed.file, sep="\t",row.names = F,col.names = F)
  #prepare cmd
  cmd <- paste0("~/anaconda3/envs/salmon/bin/findMotifsGenome.pl ", bed.file ," hg38 ", dir," -rna -len 6 -size 100 &")
  cmd
}
