dt.strict.novel.m6A.M6APeakS.deredundant <-  foreach(study = unique(dt.strict.novel.m6A.M6APeakS$StudyID), .combine='rbind')%do%{
  foreach(method=unique(dt.strict.novel.m6A.M6APeakS$ComparedMethod), .combine='rbind')%do%{
    AllSamples <- unique(dt.strict.novel.m6A.M6APeakS[StudyID==study,Sample])
    AllStrictNovelPeaks <- unique(dt.strict.novel.m6A.M6APeakS[StudyID==study & ComparedMethod==method,name])
    message(paste0("Obtain deredundant peak for ", length(AllStrictNovelPeaks), " strict novel peaks when compared with ",method, " in ", study))
    dt.m6a.deredundant <- dt.novel.m6A.M6APeakS %>% dplyr::filter(name %in% AllStrictNovelPeaks) %>%
                          dplyr::filter(Sample==sample(AllSamples,1)) %>% dplyr::select(seqnames:strand) %>% distinct()#initiate
    for(i in 1:length(AllSamples)){
      #print(dt.m6a.deredundant)
      dt.m6a.toadd <- dt.novel.m6A.M6APeakS %>% dplyr::filter(Sample ==  AllSamples[i] & name %in% AllStrictNovelPeaks) %>%
        dplyr::select(seqnames:strand) %>% distinct()
      dt.m6a.added <- bt.intersect(a=dt.m6a.toadd[,1:6],b=dt.m6a.deredundant[,1:6],s=T,f=0.9,v=T,r=T) %>% as.data.table()
      if(nrow(dt.m6a.added)>0){
        colnames(dt.m6a.added) <- colnames(dt.m6a.toadd)
        dt.m6a.deredundant <- rbind(dt.m6a.deredundant, dt.m6a.added)
      }
    }
    dt.m6a.deredundant %>% mutate(StudyID=study, ComparedMethod=method)
  }
}
