#save selected high confident strict m6a
dt.strict.novel.m6A.M6APeakS.visualization <- dt.strict.novel.m6A.M6APeakS.deredundant[HarborRatio>=0.5 & HarborSample>=2,]
dt.deptools.depth.average.strict.novel.m6a <- foreach(study=unique(dt.strict.novel.m6A.M6APeakS.deredundant$StudyID),.combine = 'rbind')%do%{
    foreach(method=unique(dt.strict.novel.m6A.M6APeakS.deredundant$ComparedMethod),.combine = 'rbind')%do%{
    fwrite(dt.strict.novel.m6A.M6APeakS.visualization[StudyID==study & ComparedMethod==method & strand=="+",1:6], file=paste0("dt.strict.novel.m6A.M6APeakS.",study,".",method,".visualization.on.pos.strand.bed"),sep="\t",row.names=F,col.names = F)
    fwrite(dt.strict.novel.m6A.M6APeakS.visualization[StudyID==study & ComparedMethod==method & strand=="-",1:6], file=paste0("dt.strict.novel.m6A.M6APeakS.",study,".",method,".visualization.on.neg.strand.bed"),sep="\t",row.names=F,col.names = F)
    #deptools computeMatrix
    #computeMatrix scale-regions -S <biwig file(s)> -R <bed file> -out
    AllSamples <- dt.m6a.combined[StudyID==study,unique(Sample)]
    AllSamples <- paste0(rep(AllSamples,each=2), rep(c("_Input","_RIP"),length(AllSamples)))
    t1 <- Sys.time()
    registerDoParallel(cl=4)
    dt.deptools.depth.novel.study.method <- foreach(s = AllSamples, .combine='rbind')%dopar%{
      message(paste0("Calculated normalized depth for ",s, " for novel m6A vs ", method, " in ", study))
      foreach(strand = c("pos","neg"), .combine='rbind')%do%{
        #computeMatrix scale-regions
        compuateMatrix.cmd <- paste0("~/bin/computeMatrix  scale-regions -p 16 -S /data2/CRC_m6A/BigWig/",s,".",strand,
                                     ".bw -R /data2/CRC_m6A/Analysis/dt.strict.novel.m6A.M6APeakS.", study, ".", method, ".visualization.on.",
                                     strand,".strand.bed --samplesLabel ",s," -o /data2/CRC_m6A/Analysis/",s,".",strand,".matrix.gz")
        system(command = compuateMatrix.cmd, wait = T)
        #unzip matrix.gz
        system(command = paste0("gunzip /data2/CRC_m6A/Analysis/",s,".",strand,".matrix.gz"),wait = T)
        #load normalized depth
        dt.depth <- fread(paste0("/data2/CRC_m6A/Analysis/",s,".",strand,".matrix"),skip=1) %>% dplyr::select(name=V4,paste0("V",7:106))
        colnames(dt.depth) <- c("name",paste0("bin",1:100))
        #remove intermediate files
        system(command = paste0("rm -f /data2/CRC_m6A/Analysis/",s,".",strand,".matrix"))
        dt.depth %>% mutate(Sample=s,Strand=strand) %>% dplyr::select(Sample,Strand,name,contains("bin"))
      }
    }
    Sys.time()-t1
    stopImplicitCluster()
    dt.deptools.depth.average <- dt.deptools.depth.novel.study.method %>% mutate(Library=case_when(str_detect(Sample,"Input") ~ "Input",.default = "RIP")) %>%
      dplyr::select(Library,contains("bin")) %>% group_by(Library) %>%  summarise_all(.funs = mean) %>% as.data.table() %>%
      pivot_longer(cols = paste0("bin",1:100),values_to = "NormDepth",names_to = "Bin") %>% as.data.table()
    dt.deptools.depth.average %>% mutate(StudyID=study, ComparedMethod=method)
  }
}
