dt.strict.novel.m6A.M6APeakS.visualization <- dt.strict.novel.m6A.M6APeakS.deredundant[HarborRatio>=0.5 & HarborSample>=2,]
dt.strict.novel.m6agene <- foreach(study=unique(dt.strict.novel.m6A.M6APeakS.visualization$StudyID), .combine='rbind')%do%{
  dt.res.study <- foreach(method=unique(dt.strict.novel.m6A.M6APeakS.visualization$ComparedMethod), .combine='rbind')%do%{
    message(paste0("Determine the complete novel m6agene for ", method, " in ", study))
    dt.m6a.novel <- dt.strict.novel.m6A.M6APeakS.visualization %>% dplyr::filter(StudyID==study & ComparedMethod==method) %>% dplyr::select(seqnames,start,end,name,score,strand,HarborRatio)
    #determine the harbor in independent cohort
    ValidationStudy <-  grep(unique(dt.strict.novel.m6A.M6APeakS.visualization$StudyID),pattern=study,invert = T,value=T)
    dt.m6a.novel.harbor <- foreach(vst = ValidationStudy, .combine='rbind')%do%{
      ValidationSamples <- dt.m6a.combined[StudyID==vst,unique(Sample)]
      dt.validation.sample.harbor <- foreach(sam = ValidationSamples, .combine = 'rbind')%do%{
        dt.overlap <- bt.intersect(a=dt.m6a.novel, b=dt.m6a.combined %>% dplyr::filter(Sample==sam & Origin=="M6APeakS"), s=T, f=0.9, wo=T) %>% as.data.table()
        dt.m6a.novel %>% mutate(Sample=sam, Harbor=name %in% dt.overlap$V4)
      }
      dt.validation.sample.harbor %>% group_by(name) %>% mutate(ValidationHarborRatio=n_distinct(Sample[Harbor])/length(ValidationSamples)) %>% as.data.table() %>%
        distinct(seqnames,start,end,name,score,strand,HarborRatio,ValidationHarborRatio)
    }
    # dt.m6a.novel.harbor %>% summarise(q=paste0("q",seq(0,1,0.1)),qvalue=quantile(HarborRatio,seq(0,1,0.1)), qvalue.validation=quantile(ValidationHarborRatio,seq(0,1,0.1)))
    #determine the m6a+ gene is novel m6a+ gene in corresponding study x method
    dt.m6agene.method <- dt.m6a.combined %>% dplyr::filter(Origin==method & StudyID==study) %>% distinct(OverlappedGenes,Sample) %>%
      separate_longer_delim(OverlappedGenes,delim = ",") %>% as.data.table() %>% distinct(Sample,OverlappedGenes) %>%
      group_by(OverlappedGenes) %>% mutate(nSample=n_distinct(Sample)) %>% as.data.table() %>% distinct(OverlappedGenes,nSample) %>% mutate(Method=method,StudyID=study)
    dt.m6agene.novel <- dt.m6a.combined %>% distinct(name,OverlappedGenes) %>% left_join(x=dt.m6a.novel.harbor,y=.) %>% separate_longer_delim(OverlappedGenes,delim = ",") %>%
      as.data.table() %>% left_join(x=.,y=dt.m6agene.method)
    dt.m6agene.novel %>% dplyr::arrange(desc(HarborRatio),desc(ValidationHarborRatio),!is.na(nSample)) %>%
      #dplyr::filter(ValidationHarborRatio>=0.2 & is.na(nSample)) %>%
      mutate(StudyID=study, ComparedMethod=method)
  }
  dt.res.study
}
