# register(SerialParam())#turn off parallel
#function to perform multiple ontology
Genelist <- dt.strict.novel.m6agene[HarborRatio>=0.5 & ValidationHarborRatio>=0.1 & is.na(nSample) & StudyID=="GSE179042" & ComparedMethod=="MeTPeak",unique(OverlappedGenes)]
dt.Genelist <- bitr(Genelist,fromType = c("SYMBOL"), toType = c("ENTREZID"),OrgDb = org.Hs.eg.db)
Genelist[!Genelist %in% dt.Genelist$SYMBOL]
#self made overrepresentation fuction
OR_enrichment <- function(InputGenes=dt.Genelist$ENTREZID,Type=c("GO_BP","GO_MF","KEGG","RA")[1]){
  if(Type == "GO_BP"){
    enrich_res.dt <- enrichGO(gene=InputGenes,OrgDb = org.Hs.eg.db, ont="BP",pvalueCutoff = 0.05,readable = T)@result %>% as.data.table() %>% dplyr::filter(Count>=3 & pvalue<=0.05)
    if(nrow(enrich_res.dt)>0){enrich_res.dt <- enrich_res.dt %>% dplyr::select(ID,Description,GeneRatio,BgRatio,pvalue,p.adjust,geneName=geneID,Count) %>%
      mutate(Ontology=Type) %>% dplyr::arrange(p.adjust)}else{ enrich_res.dt <- NULL}
  }else if(Type=="GO_MF"){
    enrich_res.dt <- enrichGO(gene=InputGenes,OrgDb = org.Hs.eg.db, ont="MF",pvalueCutoff = 0.05,readable = T)@result %>% as.data.table() %>% dplyr::filter(Count>=3 & pvalue<=0.05)
    if(nrow(enrich_res.dt)>0){enrich_res.dt <- enrich_res.dt %>% dplyr::select(ID,Description,GeneRatio,BgRatio,pvalue,p.adjust,geneName=geneID,Count) %>%
      mutate(Ontology=Type) %>% dplyr::arrange(p.adjust)}else{ enrich_res.dt <- NULL}
  }else if(Type == "KEGG"){
    enrich_res.dt <- setReadable(enrichKEGG(gene =InputGenes, use_internal_data = T,pvalueCutoff = 0.05,organism = "hsa"),OrgDb = org.Hs.eg.db, keyType = "ENTREZID")@result %>% as.data.table() %>% dplyr::filter(Count>=3 & pvalue<=0.05)
    all_path = as.data.frame(KEGG.db::KEGGPATHID2NAME)
    enrich_res.dt$Description = all_path$path_name[match(enrich_res.dt$ID, all_path$path_id)]
    if(nrow(enrich_res.dt)>0){enrich_res.dt <- enrich_res.dt %>% dplyr::select(ID,Description,GeneRatio,BgRatio,pvalue,p.adjust,geneName=geneID,Count) %>%
      mutate(Ontology=Type) %>% dplyr::arrange(p.adjust)}else{ enrich_res.dt <- NULL}
  }else if(Type == "RA"){
    enrich_res.dt <- ReactomePA::enrichPathway(InputGenes, pvalueCutoff = 0.05,organism = "human",readable = T)@result %>% as.data.table() %>% dplyr::filter(Count>=3 & pvalue<=0.05)
    if(nrow(enrich_res.dt)>0){enrich_res.dt <- enrich_res.dt %>% dplyr::select(ID,Description,GeneRatio,BgRatio,pvalue,p.adjust,geneName=geneID,Count) %>% mutate(Ontology=Type) %>% dplyr::arrange(p.adjust)}else{ enrich_res.dt <- NULL}
  }
  return(enrich_res.dt)
}

enrichment_res.strict.novel.m6agene <- foreach(study=unique(dt.strict.novel.m6agene$StudyID),.combine='rbind')%do%{
  foreach(method=unique(dt.strict.novel.m6agene$ComparedMethod), .combine='rbind')%do%{
    foreach(cutoff=c(0.1,0.2,0.5), .combine='rbind')%do%{
      Genelist <- dt.strict.novel.m6agene[HarborRatio>=0.5 & ValidationHarborRatio>=cutoff & is.na(nSample) & StudyID==study & ComparedMethod==method,unique(OverlappedGenes)]
      dt.Genelist <- bitr(Genelist,fromType = c("SYMBOL"), toType = c("ENTREZID"),OrgDb = org.Hs.eg.db)
      print(paste0(nrow(dt.Genelist), "/", length(Genelist), " at cutoff>=", cutoff, " based on ", method, " in ", study," for enrichment analyses"))
      dt.enrich.res <- foreach(type=c("GO_BP","GO_MF","KEGG","RA"), .combine='rbind')%do%{
        OR_enrichment(InputGenes=dt.Genelist$ENTREZID,Type=type)
      }
      dt.enrich.res %>% mutate(StudyID=study, ComparedMethod=method, ValidationRatioCutoff=cutoff)
    }
  }
}
