#deredundant of enriched term
dt.input <- enrichment_res.strict.novel.m6agene %>% dplyr::filter(p.adjust<=0.1) %>% dplyr::filter(ComparedMethod=="exomePeak2" & ValidationRatioCutoff==0.2 & StudyID=="GSE179042") %>% dplyr::arrange(p.adjust)
TermDeredundant <- function(InputEnrichRes = dt.input, Overlapcutoff=0.8,nthread=10){
   if(nrow(InputEnrichRes)<=10){nthread<-1}
    #build list for all terms
   require(foreach)
    TermGeneList <- foreach(i=1:nrow(InputEnrichRes))%do%{
      str_split( InputEnrichRes$geneName[i],pattern = "/") %>% unlist()
    }
    names(TermGeneList) <- InputEnrichRes$ID
    #calculate the overlap cutoff
    require(doParallel)
    registerDoParallel(cl=nthread)
    dt.overlap.ratio <- foreach(j = 1:(nrow(InputEnrichRes)-1),.combine='rbind')%dopar%{
      foreach(k=(j+1):nrow(InputEnrichRes), .combine='rbind')%do%{
        nSize1 <- length(TermGeneList[[j]])
        nSize2 <- length(TermGeneList[[k]])
        nOverlap <- length(intersect(TermGeneList[[j]],TermGeneList[[k]]))
        data.table(Term1=names(TermGeneList)[j],nSize1, Term2=names(TermGeneList)[k], nSize2, nOverlap)
      }
    }
    stopImplicitCluster()
    dt.filter <- dt.overlap.ratio %>% dplyr::filter(nOverlap/nSize2>=Overlapcutoff)
    return(InputEnrichRes %>% dplyr::filter(!ID %in% dt.filter$Term2))
}
deredundant_enrichment_res.strict.novel.m6agene <- foreach(study=unique(enrichment_res.strict.novel.m6agene$StudyID), .combine = 'rbind')%do%{
  foreach(method=unique(enrichment_res.strict.novel.m6agene$ComparedMethod),.combine = 'rbind')%do%{
    dt.input <- enrichment_res.strict.novel.m6agene %>% dplyr::filter(p.adjust<=0.1 & pvalue<=0.05) %>%
      dplyr::filter(ComparedMethod==method & StudyID==study & ValidationRatioCutoff==0.2) %>% dplyr::arrange(p.adjust)
    dt.output <- TermDeredundant(InputEnrichRes = dt.input,Overlapcutoff = 0.8,nthread = 10)
    message(paste0("Obtain ",nrow(dt.output), "/", nrow(dt.input)," deredundant enriched terms for ", study, " compared with ", method))
    dt.output
  }
}
