mixedToFloat <- function(x){
  foreach(i=1:length(x), .combine = 'c')%do%{
    x1 <- strsplit(x[i],split = "/",fixed=T) %>% sapply("[",1) %>% as.integer()
    x2 <- strsplit(x[i],split = "/",fixed=T) %>% sapply("[",2) %>% as.integer()
    x1/x2*100
  }
}
