#deptools bigwigAverage
#bigwigAverage -b sample1.bw sample2.bw -o outfile.bw
dt.CRC.sample  <- fread("/data2/CRC_m6A/rawdata/CRC_m6A_Sample_info.csv") %>%
  mutate(DonorName=SampleName %>% str_replace(pattern="_Input",replacement = "") %>% str_replace(pattern = "_RIP",replacement = "")) %>%
  dplyr::filter(StudyID %in% c("GSE179042","GSE247632"))
run.bigwig.average <- foreach(study=unique(dt.cancer.gene.novel.m6agene$StudyID),.combine = 'c')%do%{
  foreach(condition=c("T","NT"), .combine = 'c')%do%{
    if(condition=="T"){donors <- dt.CRC.sample[StudyID==study,unique(DonorName)] %>% grep(pattern="NT",invert = T,value = T)}else{
      donors <- dt.CRC.sample[StudyID==study,unique(DonorName)] %>% grep(pattern="NT",invert = F,value = T)}
    foreach(library=c("Input","RIP"), .combine = 'c')%do%{
       foreach(strand = c("pos", "neg"), .combine='c')%do%{
        all_bw <- paste0(donors,"_",library, ".", strand, ".bw") %>% paste(collapse = " ")
        cmd <- paste0("cd /data2/CRC_m6A/BigWig && ~/bin/bigwigAverage -p 64 -b ", all_bw, " -o ", study,"_",condition,"_",library, ".", strand,".bw")
        system(cmd,wait = T)
       }
    }
  }
}
#run bigwigCompare
#bigwigCompare -b1 sample1.bw -b2 sample2.bw -o log2.bw#b1 is usually the file for the treatment
#--operation#Possible choices: log2, ratio, subtract, add, mean, reciprocal_ratio, first, second
run.bigwig.average <- foreach(study=unique(dt.cancer.gene.novel.m6agene$StudyID),.combine = 'c')%do%{
  foreach(condition=c("T","NT"), .combine = 'c')%do%{
      foreach(strand = c("pos", "neg"), .combine='c')%do%{
        all_bw <- paste0(study,"_",condition,"_",c("RIP","Input"), ".", strand, ".bw")
        cmd <- paste0("cd /data2/CRC_m6A/BigWig && ~/bin/bigwigCompare -p 64 -b1 ", all_bw[1], " -b2 ", all_bw[2]," --pseudocount 1 --operation ratio"," -o ", study,"_",condition,"_RIPvsInputRatio", ".", strand,".bw")
        print(cmd)
        system(cmd,wait = T)
    }
  }
}

#merge peaks from M6APeakS, exomePeak2, MeTPeak,and MeRIPtools for each study (method x study x condition  x strand)
dt.m6a.combined <- readRDS("dt.CRC.m6a.combined.RDS")
dt.mergepeak <- foreach(study=unique(dt.cancer.gene.novel.m6agene$StudyID), .combine = 'rbind')%do%{
  foreach(method=c("M6APeakS","exomePeak2", "MeTPeak","MeRIPtools"), .combine = 'rbind')%do%{
    foreach(condition=c("NT","T"),.combine = 'rbind')%do%{
      if(condition=="NT"){samples <- dt.m6a.combined[StudyID==study,unique(Sample)] %>% grep(pattern="NT",value=T,invert = F)
      }else{samples <- dt.m6a.combined[StudyID==study,unique(Sample)] %>% grep(pattern="NT",value=T,invert = T)}
      dt.m6a.merged <- dt.m6a.combined %>% dplyr::filter(Sample %in% samples & Origin==method) %>% dplyr::select(seqnames:strand,Sample)
      dt.m6a.merged <- dt.m6a.merged %>% dplyr::select(seqnames:strand) %>% distinct() %>% makeGRangesFromDataFrame() %>% IRanges::reduce() %>% as.data.table() %>%
        dplyr::mutate(name=paste(seqnames,start,end,sep="_"),score=1000) %>% dplyr::select(seqnames,start,end,name,score,strand)
      dt.m6a.merged %>% mutate(StudyID=study, Method=method,Condition=condition)
    }
  }
}

