dt.m6a.intensity <- foreach(s = unique(dt.m6a.combined$Sample), .combine='rbind')%do%{
  message(paste0("load ", which(unique(dt.m6a.combined$Sample)==s)))
  fread(paste0("/data2/CRC_m6A/Analysis/tmp/", s, "__Combined_m6a_bedtools_intensity.tsv")) %>%
    mutate(Sample=s, strand=strsplit(name,split="_") %>% sapply(tail,1)) %>%
    mutate(score=case_when(strand == "+" ~ pos, strand=="-" ~ neg)) %>% dplyr::select(name,Sample,score) %>% distinct()
}
dt.m6a.intensity.deredundant <- dt.m6a.deredundant %>% dplyr::select(-score) %>% inner_join(x=.,y=dt.m6a.intensity,by=c("name")) %>%
  dplyr::filter(Sample %in% dt.m6a.combined[StudyID %in% c("GSE247632","GSE179042"),unique(Sample)]) %>% dplyr::arrange(seqnames,start,end,strand,Sample)
length(unique(dt.m6a.intensity.deredundant$name))#114,611 peaks
length(unique(dt.m6a.intensity.deredundant$Sample))
#differential methylated in CRC of two cohort
dt.DMP.CRC <- foreach(study=c("GSE247632","GSE179042"), .combine='rbind')%do%{
  dt.m6a.intensity.study <- dt.m6a.intensity.deredundant %>% dplyr::filter(Sample %in% dt.m6a.combined[StudyID==study,unique(Sample)])
  dt.m6a.intensity.study <- dt.m6a.intensity.study %>% mutate(Donor=str_replace(Sample,pattern="NT",replacement="") %>% str_replace(pattern="T",replacement = ""),
                                                              Condition=case_when(str_detect(Sample,"NT") ~ "Adjacent", .default = "Tumor") %>% factor(levels=c("Tumor","Adjacent"))) %>%
                            dplyr::arrange(name,Condition,Donor)
  registerDoParallel(cl=20)
  t1 <- Sys.time()
  dt.DMP <- foreach(p = unique(dt.m6a.intensity.study$name), .combine = 'rbind')%dopar%{
    if(length(unique(dt.m6a.intensity.study[name==p,score]))>1){
      ttest.unpaired <- t.test(x=dt.m6a.intensity.study[name==p & Condition=="Tumor",score],y=dt.m6a.intensity.study[name==p & Condition=="Adjacent",score], paired = F)
      ttest.paired <- t.test(x=dt.m6a.intensity.study[name==p & Condition=="Tumor",score],y=dt.m6a.intensity.study[name==p & Condition=="Adjacent",score], paired = T)
      data.table(Study=study, name=p, ttest.p.paired=signif(ttest.paired$p.value,2), ttest.p=signif(ttest.unpaired$p.value,2),
                 score.tumor=ttest.unpaired$estimate[1], score.adjacent=ttest.unpaired$estimate[2],score.pairdiff=ttest.paired$estimate)
    }else{
      data.table(Study=study, name=p, ttest.p.paired=1, ttest.p=1,
                 score.tumor=mean(dt.m6a.intensity.study[name==p & Condition=="Tumor",score]),
                 score.adjacent=mean(dt.m6a.intensity.study[name==p & Condition=="Adjacent",score]),score.pairdiff=0)
    }
  }
  Sys.time()-t1
  stopImplicitCluster()
  message(paste0("Finished DMP for ", study))
  dt.DMP
}
