#calculate the count of DMP and DMG at different cutoff
dt.count.DMP.DMG <- foreach(pcutoff=c(0.05,0.01),.combine = 'rbind')%do%{
  foreach(diffcutoff=c(0.5,1,2), .combine='rbind')%do%{
    dt.sig.DMP.CRC <- dt.DMP.CRC %>% dplyr::filter(ttest.p.paired<=pcutoff & abs(score.pairdiff)>=diffcutoff) %>%
      dplyr::arrange(Study,ttest.p.paired,desc(abs(score.pairdiff))) %>%
      left_join(x=.,y=dt.m6a.combined %>% distinct(name,OverlappedGenes),by="name") %>% tidyr::separate_longer_delim(OverlappedGenes,delim = ",") %>%
      as.data.table()
    #DMP and DMG in each study
    dt.count.DMP.DMG <- dt.sig.DMP.CRC %>% mutate(Direction=factor(score.pairdiff>0,levels=c(TRUE,FALSE),labels=c("Hyper","Hypo"))) %>%  group_by(Study,Direction) %>%
    mutate(nDMP=n_distinct(name), nDMG=n_distinct(OverlappedGenes)) %>% as.data.table()  %>%  distinct(Study,Direction,nDMP,nDMG) %>%
      pivot_wider(id_cols = "Direction", names_from = "Study",values_from = c("nDMP","nDMG")) %>% as.data.table()
    #shared DMP and DMG
    dt.count.shared.DMP.DMG <- dt.sig.DMP.CRC %>% mutate(Direction=factor(score.pairdiff>0,levels=c(TRUE,FALSE),labels=c("Hyper","Hypo"))) %>%  group_by(Direction,name) %>%
      dplyr::filter(n_distinct(Study)>1) %>% as.data.table() %>% group_by(Direction) %>% mutate(nDMP.shared=n_distinct(name),nDMG.shared=n_distinct(OverlappedGenes)) %>%
      as.data.table() %>% distinct(Direction,nDMP.shared,nDMG.shared)
    dt.count.DMP.DMG %>% left_join(x=.,y=dt.count.shared.DMP.DMG,by="Direction") %>% mutate(pcutoff=pcutoff,diffcutoff=diffcutoff)
  }
}
