#significant DEG in GSE179042 and GSE247632
library(Rsubread)
require(DESeq2)
dt.DEG.two.study <- foreach(study=c("GSE179042","GSE247632"), .combine='rbind')%do%{
  if(!file.exists(paste0("dt.DEG.", study, ".CRC.RDS"))){
    if(!file.exists(paste0(study,".Gene_CountMatrix.RDS"))){
      InputSamples <- paste0(dt.m6a.combined[StudyID==study,unique(Sample)],"_Input")
      PE_bam_files <- list.files(path="/data2/CRC_m6A/7_RIPPeakS/BAM/R1_bam/", pattern='(Input).+(sortedByCoord.UN).+(R1.bam)$', full.names = T)
      names(PE_bam_files) <- list.files(path="/data2/CRC_m6A/7_RIPPeakS/BAM/R1_bam/", pattern='(Input).+(sortedByCoord.UN).+(R1.bam)$', full.names = F) %>%
        strsplit(split=".sorted",fixed=T) %>% sapply("[",1)
      PE_bam_files <- PE_bam_files[InputSamples]
      Sample_Gene_CountMatrix_PE <- Rsubread::featureCounts(files = PE_bam_files,
                                                            nthreads = 60,
                                                            annot.ext = "/data/m6A_calling_strategy/RIPPeakS_resource/gencode.v44.annotation.gtf",
                                                            isGTFAnnotationFile = TRUE, GTF.featureType = "exon", GTF.attrType = "gene_id",
                                                            fracOverlap = 0, countMultiMappingReads = FALSE, fraction = FALSE, splitOnly = FALSE,
                                                            nonSplitOnly = FALSE, isPairedEnd = T, countReadPairs = FALSE, strandSpecific = c(0,1,2)[3])
      Gene_CountMatrix <- Sample_Gene_CountMatrix_PE$counts
      colnames(Gene_CountMatrix) <- colnames(Gene_CountMatrix) %>% strsplit(split="_",fixed=T) %>% sapply("[",1)
      saveRDS(Gene_CountMatrix,file=paste0(study,".Gene_CountMatrix.RDS"))
    }
    Gene_CountMatrix <- readRDS(paste0(study,".Gene_CountMatrix.RDS"))
    # dt.gene.count <- as.data.table(Gene_CountMatrix,keep.rownames = "GeneID") %>% pivot_longer(cols = colnames(.)[-1],values_to = "Count",names_to = "SampleID") %>%
    #   mutate(SampleID=strsplit(SampleID,split=".",fixed=T) %>% sapply("[",1)) %>% as.data.table() %>% group_by(SampleID) %>% mutate(FC.MappedCount=sum(Count)) %>% as.data.table()
    # attr(dt.gene.count,"groups") <- NULL
    #run DESeq2
    #build design matrix
    dt.all.pheno <- data.table(Sample=colnames(Gene_CountMatrix)) %>% mutate(Group=case_when(str_detect(Sample,"NT") ~ "Adjacent", .default = "Tumor"),
                                                                             Donor=str_replace(Sample,pattern="NT",replacement="") %>% str_replace(pattern="T",replacement = ""))

    annot <- genomation::gffToGRanges("/data/m6A_calling_strategy/RIPPeakS_resource/gencode.v44.annotation.gtf") %>% as.data.table() %>%
      dplyr::filter(type=="gene") %>% dplyr::select(gene_id,gene_name)
    dt.pheno <- dt.all.pheno %>%  mutate(condition=factor(Group, levels=c("Tumor","Adjacent")))
    tbl <- Gene_CountMatrix[,dt.pheno$Sample]
    # pre-filter low count genes
    # keep genes with at least N counts > 2, where N = size of smallest group
    keep <- rowSums( tbl >= 2 ) >= min(table(dt.pheno$condition))*0.5
    tbl <- tbl[keep, ]
    ds <- DESeqDataSetFromMatrix(countData=tbl, colData=dt.pheno, design= ~condition)
    ds <- DESeq(ds, test="Wald", sfType="poscount")
    # extract results for top genes table
    res <- results (ds, contrast=c("condition", levels(dt.pheno$condition)[1], levels(dt.pheno$condition)[2]), alpha=0.05, pAdjustMethod ="fdr") %>% as.data.table(keep.rownames="GeneID")
    tT <- res %>% dplyr::arrange(padj) %>% inner_join(x=.,y=annot %>% dplyr::select(gene_id,gene_name),by=c("GeneID"="gene_id")) %>%
      dplyr::select(GeneID,Symbol=gene_name,LFC=log2FoldChange,pvalue,padj)
    print(tT %>% dplyr::filter(abs(LFC)>=1 & padj<=0.05) %>% mutate(StudyID=study))
    saveRDS(tT, file=paste0("dt.DEG.", study, ".CRC.RDS"))
  }
  readRDS(paste0("dt.DEG.", study, ".CRC.RDS")) %>% mutate(StudyID=study)
}

