dt.DMEG.CRC <- foreach(study = unique(dt.DMP.CRC$Study), .combine='rbind')%do%{
  pcutoff <- ifelse(study=="GSE247632", 0.05, 0.05)
  dt.sig.DMP.CRC <- dt.DMP.CRC %>% dplyr::filter(Study==study & ttest.p.paired<=pcutoff & abs(score.pairdiff)>=1) %>%
    dplyr::arrange(Study,ttest.p.paired,desc(abs(score.pairdiff))) %>% tidyr::separate_longer_delim(OverlappedGenes,delim = ",") %>%
    as.data.table()
  print(dt.sig.DMP.CRC %>% inner_join(x=.,y=dt.DEG.two.study %>% dplyr::filter(StudyID==study & abs(LFC)>=1 & padj<=0.05 & !is.na(padj)),by=c("OverlappedGenes"="Symbol","Study"="StudyID")))
  dt.sig.DMP.CRC %>% inner_join(x=.,y=dt.DEG.two.study %>% dplyr::filter(StudyID==study & abs(LFC)>=1 & padj<=0.05 & !is.na(padj)),by=c("OverlappedGenes"="Symbol","Study"="StudyID")) %>%
    mutate(diffmethy.p=signif(ttest.p.paired,2), score.tumor=round(score.tumor,2), score.adjacent=round(score.adjacent,2), score.pairdiff=round(score.pairdiff,2),
           diffexpr.LFC=round(LFC,2), diffexpr.padj=signif(padj,2)) %>% dplyr::select(Study,name,diffmethy.p,contains("score"), Symbol=OverlappedGenes, GeneID, contains("diffexpr"))
}
