enrichment_res.DMEG <- foreach(study=unique(dt.DMEG.CRC$Study),.combine='rbind')%do%{
  foreach(Direction=c("Hyper","Hypo"),.combine='rbind')%do%{
      Genelist <- dt.DMEG.CRC[Study==study & DiffMethy==Direction & DiffExpr==ifelse(Direction=="Hyper","Up","Down"),unique(Symbol)]
      dt.Genelist <- bitr(Genelist,fromType = c("SYMBOL"), toType = c("ENTREZID"),OrgDb = org.Hs.eg.db)
      print(paste0(nrow(dt.Genelist), "/", length(Genelist)," ", Direction, " DMEG  in ", study," for enrichment analyses"))
      dt.enrich.res <- foreach(type=c("GO_BP","GO_MF","KEGG","RA"), .combine='rbind')%do%{
        OR_enrichment(InputGenes=dt.Genelist$ENTREZID,Type=type)
      }
      dt.enrich.res %>% mutate(StudyID=study, DiffMethy=Direction, DiffExpr=ifelse(Direction=="Hyper","Up","Down"))
  }
}
