dt.ratio.DMP.DMG.DMEG <- foreach(study = unique(dt.sig.DMP.CRC$Study), .combine='rbind')%do%{
  foreach(method = c("exomePeak2","MeTPeak","MeRIPtools","All"), .combine = 'rbind')%do%{
    if(method=="All"){
      dt.sig.DMP.CRC.subset <- dt.sig.DMP.CRC %>% dplyr::filter(Study==study) %>% mutate(DiffMethy=factor(score.pairdiff>0,levels=c(TRUE,FALSE),labels=c("Hyper","Hypo"))) %>% dplyr::select(name,DiffMethy,OverlappedGenes,contains(study))
      colnames(dt.sig.DMP.CRC.subset)[4:6] <- paste0("IsStrictNovel",1:3)
      dt.DMEG.CRC.subset <- dt.DMEG.CRC %>% dplyr::filter(Study==study) %>% dplyr::select(name,DiffMethy,DiffExpr,Symbol) %>% distinct()
      data.table(nDMP=n_distinct(dt.sig.DMP.CRC.subset[,name]), nDMG=n_distinct(dt.sig.DMP.CRC.subset[!is.na(OverlappedGenes),OverlappedGenes]),
                 nDMEG.Hyper=n_distinct(dt.DMEG.CRC.subset[DiffMethy=="Hyper" & DiffExpr=="Up",Symbol]),nDMEG.Hypo=n_distinct(dt.DMEG.CRC.subset[DiffMethy=="Hypo" & DiffExpr=="Down",Symbol]),
                 nDMP.strictnovel=n_distinct(dt.sig.DMP.CRC.subset[IsStrictNovel1==TRUE & IsStrictNovel2==TRUE & IsStrictNovel3==TRUE,name]),
                 nDMG.strictnovel=n_distinct(dt.sig.DMP.CRC.subset[IsStrictNovel1==TRUE & IsStrictNovel2==TRUE & IsStrictNovel3==TRUE & !is.na(OverlappedGenes), OverlappedGenes]),
                 nDMEG.Hyper.strictnovel=n_distinct(dt.sig.DMP.CRC.subset[IsStrictNovel1==TRUE & IsStrictNovel2==TRUE & IsStrictNovel3==TRUE & DiffMethy == "Hyper" & !is.na(OverlappedGenes) & OverlappedGenes %in% dt.DMEG.CRC.subset[DiffMethy=="Hyper" & DiffExpr=="Up",unique(Symbol)], OverlappedGenes]),
                 nDMEG.Hypo.strictnovel=n_distinct(dt.sig.DMP.CRC.subset[IsStrictNovel1==TRUE & IsStrictNovel2==TRUE & IsStrictNovel3==TRUE & DiffMethy == "Hypo" & !is.na(OverlappedGenes) & OverlappedGenes %in% dt.DMEG.CRC.subset[DiffMethy=="Hypo" & DiffExpr=="Down",unique(Symbol)], OverlappedGenes])
      ) %>% mutate(Study=study,ComparedMethod=method)
    }else{
      dt.sig.DMP.CRC.subset <- dt.sig.DMP.CRC %>% dplyr::filter(Study==study) %>% mutate(DiffMethy=factor(score.pairdiff>0,levels=c(TRUE,FALSE),labels=c("Hyper","Hypo"))) %>% dplyr::select(name,DiffMethy,OverlappedGenes,paste(study,method,sep="."))
      colnames(dt.sig.DMP.CRC.subset)[4] <- "IsStrictNovel"
      dt.DMEG.CRC.subset <- dt.DMEG.CRC %>% dplyr::filter(Study==study) %>% dplyr::select(name,DiffMethy,DiffExpr,Symbol) %>% distinct()
      data.table(nDMP=n_distinct(dt.sig.DMP.CRC.subset[,name]), nDMG=n_distinct(dt.sig.DMP.CRC.subset[!is.na(OverlappedGenes),OverlappedGenes]),
                 nDMEG.Hyper=n_distinct(dt.DMEG.CRC.subset[DiffMethy=="Hyper" & DiffExpr=="Up",Symbol]),nDMEG.Hypo=n_distinct(dt.DMEG.CRC.subset[DiffMethy=="Hypo" & DiffExpr=="Down",Symbol]),
                 nDMP.strictnovel=n_distinct(dt.sig.DMP.CRC.subset[IsStrictNovel==TRUE,name]), nDMG.strictnovel=n_distinct(dt.sig.DMP.CRC.subset[IsStrictNovel==TRUE & !is.na(OverlappedGenes), OverlappedGenes]),
                 nDMEG.Hyper.strictnovel=n_distinct(dt.sig.DMP.CRC.subset[IsStrictNovel==TRUE & DiffMethy == "Hyper" & !is.na(OverlappedGenes) & OverlappedGenes %in% dt.DMEG.CRC.subset[DiffMethy=="Hyper" & DiffExpr=="Up",unique(Symbol)], OverlappedGenes]),
                 nDMEG.Hypo.strictnovel=n_distinct(dt.sig.DMP.CRC.subset[IsStrictNovel==TRUE & DiffMethy == "Hypo" & !is.na(OverlappedGenes) & OverlappedGenes %in% dt.DMEG.CRC.subset[DiffMethy=="Hypo" & DiffExpr=="Down",unique(Symbol)], OverlappedGenes])) %>%
        mutate(Study=study,ComparedMethod=method)
    }
  }
}
