#Identification of M14KD DEG in human CRC cell line HCT116
library(Rsubread)
require(DESeq2)
if(!file.exists(paste0("dt.DEG.M14KD.GSE186791.CRC.HCT116.RDS"))){
  if(!file.exists(paste0("M14KD.GSE186791.CRC.HCT116.Gene_CountMatrix.RDS"))){
    RNAseqSamples <- fread("/data2/CRC_m6A/rawdata/GSE186791_CRC_HCT116_siMETTL14_RNAseq_sample_info.csv")
    PE_bam_files <- list.files(path="/data2/CRC_m6A/7_RIPPeakS/BAM/R1_bam/", pattern='(.sortedByCoord.UN.R1.bam)$', full.names = T)
    names(PE_bam_files) <- list.files(path="/data2/CRC_m6A/7_RIPPeakS/BAM/R1_bam/", pattern='(sortedByCoord.UN).+(R1.bam)$', full.names = F) %>%
      strsplit(split=".sorted",fixed=T) %>% sapply("[",1)
    PE_bam_files <- PE_bam_files[RNAseqSamples$SampleName]
    Sample_Gene_CountMatrix_PE <- Rsubread::featureCounts(files = PE_bam_files,
                                                          nthreads = 60,
                                                          annot.ext = "/data/m6A_calling_strategy/RIPPeakS_resource/gencode.v44.annotation.gtf",
                                                          isGTFAnnotationFile = TRUE, GTF.featureType = "exon", GTF.attrType = "gene_id",
                                                          fracOverlap = 0, countMultiMappingReads = FALSE, fraction = FALSE, splitOnly = FALSE,
                                                          nonSplitOnly = FALSE, isPairedEnd = T, countReadPairs = FALSE, strandSpecific = c(0,1,2)[3])
    Gene_CountMatrix <- Sample_Gene_CountMatrix_PE$counts
    colnames(Gene_CountMatrix) <- colnames(Gene_CountMatrix) %>% strsplit(split=".",fixed=T) %>% sapply("[",1)
    saveRDS(Gene_CountMatrix,file=paste0("M14KD.GSE186791.CRC.HCT116.Gene_CountMatrix.RDS"))
  }
  Gene_CountMatrix <- readRDS(paste0("M14KD.GSE186791.CRC.HCT116.Gene_CountMatrix.RDS"))
  #run DESeq2
  #build design matrix
  dt.all.pheno <- data.table(Sample=colnames(Gene_CountMatrix)) %>% mutate(Group=case_when(str_detect(Sample,"NC") ~ "shControl", .default = "shMETTL14"))
  annot <- genomation::gffToGRanges("/data/m6A_calling_strategy/RIPPeakS_resource/gencode.v44.annotation.gtf") %>% as.data.table() %>%
    dplyr::filter(type=="gene") %>% dplyr::select(gene_id,gene_name)
  dt.pheno <- dt.all.pheno %>%  mutate(condition=factor(Group, levels=c("shMETTL14","shControl")))
  tbl <- Gene_CountMatrix[,dt.pheno$Sample]
  # pre-filter low count genes
  # keep genes with at least N counts > 2, where N = size of smallest group
  keep <- rowSums( tbl >= 2 ) >= min(table(dt.pheno$condition))*0.5
  tbl <- tbl[keep, ]
  ds <- DESeqDataSetFromMatrix(countData=tbl, colData=dt.pheno, design= ~condition)
  ds <- DESeq(ds, test="Wald", sfType="poscount")
  # extract results for top genes table
  res <- results (ds, contrast=c("condition", levels(dt.pheno$condition)[1], levels(dt.pheno$condition)[2]), alpha=0.05, pAdjustMethod ="fdr") %>% as.data.table(keep.rownames="GeneID")
  tT <- res %>% dplyr::arrange(padj) %>% inner_join(x=.,y=annot %>% dplyr::select(gene_id,gene_name),by=c("GeneID"="gene_id")) %>%
    dplyr::select(GeneID,Symbol=gene_name,LFC=log2FoldChange,pvalue,padj)
  tT %>% dplyr::filter(Symbol=="METTL14")
  #                GeneID  Symbol        LFC              pvalue              padj
  # 1: ENSG00000145388.15 METTL14 -0.4854512 0.00000000009221314 0.000000007265401
  print(tT %>% dplyr::filter(abs(LFC)>=0.5 & padj<=0.05) %>% mutate(StudyID="M14KD.GSE186791"))
  saveRDS(tT %>% mutate(StudyID="M14KD.GSE186791"), file=paste0("dt.DEG.M14KD.GSE186791.CRC.HCT116.RDS"))
}
dt.DEG.M14KD.GSE186791 <- readRDS(paste0("dt.DEG.M14KD.GSE186791.CRC.HCT116.RDS"))

