#function to mapped mouse gene to human gene
library(org.Hs.eg.db)
library(org.Mm.eg.db)
library(Orthology.eg.db)
mapIt <- function(mouseids, horg, morg, orth){
  mouseg <- mapIds(morg, mouseids, "ENTREZID", "SYMBOL")
  mapped <- select(orth, mouseg, "Homo_sapiens","Mus_musculus")
  names(mapped) <- c("Mus_egid","Homo_egid")
  husymb <- select(horg, as.character(mapped[,2]), "SYMBOL","ENTREZID")
  return(data.frame(Mus_symbol = mouseids,
                    mapped,
                    Homo_symbol = husymb[,2]))
}
dt.genemap <- mapIt(unique(dt.DEG.M3KO.GSE142589$Symbol), org.Hs.eg.db, org.Mm.eg.db, Orthology.eg.db) %>% as.data.table(keep.rownames="inputid")
dt.DEG.M3KO.GSE142589 <- dt.DEG.M3KO.GSE142589 %>% left_join(x=.,y=dt.genemap %>% dplyr::select(inputid,Homo_symbol),by=c("Symbol"="inputid"))
