dt.DMEG.CRC.validation <- foreach(Direction=c("Hyper","Hypo"),.combine='rbind')%do%{
  foreach(study=unique(dt.DMEG.CRC$Study), .combine='rbind')%do%{
    dt.DMEG.subset <- dt.DMEG.CRC %>% dplyr::select(Study,Symbol,diffexpr.LFC,diffmethy.score,DiffMethy,DiffExpr) %>% distinct() %>%
      dplyr::filter(DiffMethy==Direction & Study==study)
    foreach(validation = c("M14KD.GSE186791","M3KO.GSE142589", "M14KO.GSE142589"), .combine='rbind')%do%{
      if(validation=="M14KD.GSE186791"){
        dt.DMEG.subset.validated <- dt.DMEG.subset %>% left_join(x=.,y=dt.DEG.M14KD.GSE186791 %>% dplyr::filter(padj<=0.05 & LFC<= -0.5) %>% dplyr::select(Symbol,LFC,padj),by=c("Symbol"="Symbol"))
      }else if(validation=="M3KO.GSE142589"){
        dt.DMEG.subset.validated <- dt.DMEG.subset %>% left_join(x=.,y=dt.DEG.M3KO.GSE142589 %>% dplyr::filter(padj<=0.05 & LFC<= -0.5) %>% dplyr::select(Homo_symbol,LFC,padj),by=c("Symbol"="Homo_symbol"))
      }else{
        dt.DMEG.subset.validated <- dt.DMEG.subset %>% left_join(x=.,y=dt.DEG.M14KO.GSE142589 %>% dplyr::filter(padj<=0.05 & LFC<= -0.5) %>% dplyr::select(Homo_symbol,LFC,padj),by=c("Symbol"="Homo_symbol"))
      }
      #data.table(StudyID=study, Direction=Direction,nDMEG=n_distinct(dt.DMEG.subset$Symbol),nValidated=n_distinct(dt.DMEG.subset.validated[!is.na(LFC),]), Validation=paste("Down.",validation))
      dt.DMEG.subset.validated %>% dplyr::filter(!is.na(LFC)) %>% mutate(Validation=paste("Down.",validation))
    }
  }
}
#       StudyID Direction nDMEG nValidated            Validation
