Strandness.files <- list.files(path="/data2/CRC_m6A/6_alignment_star/",pattern="(infer.tsv)$",full.names = T)
names(Strandness.files) <- list.files(path="/data2/CRC_m6A/6_alignment_star/",pattern="(strandness.infer.tsv)$",full.names = F) %>%
  strsplit(split="_STAR",fixed=T) %>% sapply("[",1)
Strandness.files <- Strandness.files[match(dt.SRA.samples$SampleName,names(Strandness.files))]
dt.infer.strandness.res <- foreach(i=1:length(Strandness.files),.combine='rbind')%do%{
  dt.res <- fread(Strandness.files[i])
  if(sum(stringr::str_detect(dt.res$V6,pattern=fixed("2++,2--")))>0){
    Library <- "PE"
    if(dt.res[stringr::str_detect(V6,fixed("2++,2--")),V7]>=0.5){
      Strandness <- "R2"
      score <- dt.res[stringr::str_detect(V6,fixed("2++,2--")),V7]}else{
        if(dt.res[stringr::str_detect(V6,fixed("1++,1--")),V7]>=0.5){
          Strandness <- "R1"
          score <- dt.res[stringr::str_detect(V6,fixed("1++,1--")),V7]}else{
            Strandness <- "unstranded"
            score <- NULL
          }
      }
    data.table(Sample=names(Strandness.files)[i], Library=Library, Strandness=Strandness, Strandness.score=score)
  }else{
    Library <- "SE"
    if(dt.res[stringr::str_detect(V6,fixed("++,--")),V7]>=0.5){
      Strandness <- "same"
      score <- dt.res[stringr::str_detect(V6,fixed("++,--")),V7]}else{
        if(dt.res[stringr::str_detect(V6,fixed("+-,-+")),V7]>=0.5){
          Strandness <- "opposite"
          score <- dt.res[stringr::str_detect(V6,fixed("+-,-+")),V7]
        }else{
          Strandness <- "unstranded"
          score <- NULL
        }
      }
    data.table(Sample=names(Strandness.files)[i], Library=Library, Strandness=Strandness, Strandness.score=score)
  }
}
dt.infer.strandness.res %>% dplyr::arrange(Library,desc(Strandness.score))#PE, R2

#mapping statistics
#load star mapping statistics
final.log.files <- list.files("/data2/CRC_m6A/6_alignment_star/",pattern="(Log.final.out)",full.names = T)
names(final.log.files) <- list.files("/data2/CRC_m6A/6_alignment_star/",pattern="(Log.final.out)",full.names = F) %>%
  strsplit(split="_STAR",fixed=T) %>% sapply("[",1)
final.log.files <- final.log.files[match(dt.SRA.samples$SampleName,names(final.log.files))]
dt.mapping.res <- foreach(i=1:length(final.log.files),.combine='rbind')%do%{
  dt.res <- fread(final.log.files[i],sep="|",sep2="\t",fill = T,header = F)
  dt.res$V1 <- dt.res$V1 %>% str_replace(pattern = "\t",replacement = "")
  dt.res$V2 <- dt.res$V2 %>% str_replace(pattern = "\t",replacement = "")
  data.table(Sample=names(final.log.files)[i], UniqueMappedRate = dt.res[V1=="Uniquely mapped reads %",V2],
             UniqueMappedRead=dt.res[V1=="Uniquely mapped reads number",V2]) %>%
    mutate(UniqueMappedRate=str_replace(UniqueMappedRate,pattern="%",replacement="") %>% as.numeric(),
           UniqueMappedRead=round(as.integer(UniqueMappedRead)/1000000,2))
}
#merged together
dt.strandness.mapping <- dt.infer.strandness.res %>% left_join(x=.,y=dt.mapping.res) %>% dplyr::arrange(desc(UniqueMappedRate))#keep all samples
fwrite(dt.strandness.mapping, file="/data2/CRC_m6A/Analysis/Mapping_statistic_GSE130012_HCT116_M3KO_RNAseq.csv")

