                                                          fracOverlap = 0, countMultiMappingReads = FALSE, fraction = FALSE, splitOnly = FALSE,
                                                          nonSplitOnly = FALSE, isPairedEnd = T, countReadPairs = FALSE, strandSpecific = c(0,1,2)[3])
