#identification of DMG in GSE167075 Caco2 M3KD MeRIPseq
#Identification of DMGs with at least one bin with abs(RIP/Input fold)>=1
#deptools bigwigAverage
#bigwigAverage -b sample1.bw sample2.bw -o outfile.bw
dt.MeRIP.samples <-  fread("/data2/CRC_m6A/Analysis/Mapping_statistic_GSE167075_CRC_Cov2_COVIDinfected_M3KD_RNAseq_MeRIPseq.csv",header = T) %>% dplyr::filter(!str_detect(Sample,"mRNA")) %>%
  mutate(SampleName=Sample)
run.bigwig.average <- foreach(condition=c("shCTL","shM3"), .combine = 'c')%do%{
  foreach(library=c("Input","RIP"), .combine = 'c')%do%{
    foreach(strand = c("pos", "neg"), .combine='c')%do%{
    #all_bw <- paste0(donors,"_",library, ".", strand, ".bw") %>% paste(collapse = " ")
    all_bw <- paste0("/data2/CRC_m6A/BigWig/",dt.MeRIP.samples[str_detect(SampleName,condition) & str_detect(SampleName,library),unique(SampleName)],".", strand,".bw") %>% paste(collapse = " ")
    cmd <- paste0("cd /data2/CRC_m6A/BigWig && ~/bin/bigwigAverage -p 64 -b ", all_bw, " -o /data2/CRC_m6A/BigWig/GSE167075_Caco2",condition,"_",library, ".",strand, ".bw")
    if(str_count(all_bw,pattern = ".bw")==1){
      cmd <- paste0("cp ",all_bw, " /data2/CRC_m6A/BigWig/GSE167075_Caco2",condition,"_",library, ".",strand, ".bw ")
    }
    print(cmd)
    system(cmd,wait = T)
    }
  }
}
#run bigwigCompare
#bigwigCompare -b1 sample1.bw -b2 sample2.bw -o log2.bw#b1 is usually the file for the treatment
#--operation#Possible choices: log2, ratio, subtract, add, mean, reciprocal_ratio, first, second
run.bigwig.Compare <- foreach(condition=c("shCTL","shM3"), .combine = 'c')%do%{
  foreach(strand = c("pos", "neg"), .combine='c')%do%{
  all_bw <- paste0("/data2/CRC_m6A/BigWig/GSE167075_Caco2",condition,"_",c("RIP","Input"),".",strand, ".bw")
  cmd <- paste0("cd /data2/CRC_m6A/BigWig && ~/bin/bigwigCompare -p 64 -b1 ", all_bw[1], " -b2 ", all_bw[2]," --pseudocount 1 --operation ratio"," -o /data2/CRC_m6A/BigWig/GSE167075_Caco2", condition,"_RIPvsInputRatio.",strand,".bw")
  print(cmd)
  system(cmd,wait = T)
  }
}
require(plotgardener)
dt.gene <- genomation::gffToGRanges("~/genome_db/gencode.v44.annotation.gtf") %>% as.data.table() %>% dplyr::filter(type=="gene") %>% dplyr::select(seqnames,start,end,strand,gene_id,gene_name)
# dt.gene.mapid <- mapIt(unique(dt.gene$gene_name), org.Hs.eg.db, org.Mm.eg.db, Orthology.eg.db) %>% as.data.table(keep.rownames="inputid") %>% dplyr::filter(!is.na(Homo_symbol))
# dt.gene <- dt.gene %>% inner_join(x=.,y=dt.gene.mapid,by=c("gene_name"="inputid"))
dt.Ratio.DMEG <-  foreach(study = unique(dt.DMEG.CRC$Study),.combine='rbind')%do%{
  foreach(direction=unique(dt.DMEG.CRC$DiffMethy), .combine='rbind')%do%{
    t1 <- Sys.time()
    dt.DMEG.subset <- dt.DMEG.CRC %>% dplyr::select(Study,Symbol,name,DiffMethy,DiffExpr) %>% distinct() %>%
      dplyr::filter(DiffMethy==direction & Study==study)
    registerDoParallel(cl=10)
    dt.ratio.DMEG.subset <- foreach(g = unique(dt.DMEG.subset$Symbol),.combine = 'rbind')%dopar%{
      message(paste0(which(unique(dt.DMEG.subset$Symbol)==g), "/", length(unique(dt.DMEG.subset$Symbol)), " ",direction," DMEG in ",study, " "))
      dt.selected.gene <- dt.gene %>% dplyr::filter(gene_name==g)
      print(dt.selected.gene)
      if(nrow(dt.selected.gene)==1){
        gr.region <- makeGRangesFromDataFrame(dt.selected.gene)
        region.tiled <- tile(gr.region,width = 100)[[1]] %>% as.data.table() %>% mutate(name=paste(seqnames,start,end,sep="_"),score=1000) %>% dplyr::select(seqnames,start,end,name,score,strand)
        dt.ratio.gene <- foreach(condition=c("shCTL","shM3"), .combine='rbind')%do%{
          region <- pgParams(chrom = as.character(dt.selected.gene$seqnames),chromstart = dt.selected.gene$start, chromend = dt.selected.gene$end,assembly = "hg38")
          ratio <- plotgardener::readBigwig(file = paste0("/data2/CRC_m6A/BigWig/GSE167075_Caco2",condition,"_RIPvsInputRatio.",ifelse(dt.selected.gene$strand=="+","pos","neg"),".bw"),params=region) %>% as.data.table() %>%
            mutate(name=paste(seqnames,start,end,sep="")) %>% dplyr::select(seqnames,start,end,name,score,strand)
          if(nrow(ratio)>0){
            dt.overlap <- findOverlaps(makeGRangesFromDataFrame(region.tiled), makeGRangesFromDataFrame(ratio)) %>% as.data.table()
            cbind(region.tiled[dt.overlap$queryHits,] %>% dplyr::select(-score),ratio[dt.overlap$subjectHits,] %>% dplyr::select(name.ratio=name,score)) %>%
              group_by(name) %>% mutate(score=mean(as.numeric(score),na.rm=T)) %>% as.data.table() %>% distinct(name,score) %>% mutate(condition=condition)
            #bt.intersect(a=region.tiled, b=ratio, wo=T) %>% as.data.table() %>% group_by(name=V4) %>% mutate(score=mean(as.numeric(V11),na.rm=T)) %>% as.data.table() %>% distinct(name,score) %>% mutate(condition=condition)
          }else{
            data.table(name=NA,score=NA,condition=condition)
          }
        } %>% dplyr::arrange(name,condition) %>% mutate(Symbol=g)
        print(dt.ratio.gene %>% pivot_wider(id_cols = c("name","Symbol"),values_from = "score",names_from = "condition") %>% mutate(Diff.M3KD=round(shM3-shCTL,2)) %>%
                dplyr::filter(Diff.M3KD <= -1) %>% as.data.table())
        dt.ratio.gene  %>% pivot_wider(id_cols = c("name","Symbol"),values_from = "score",names_from = "condition") %>% mutate(Diff.M3KD=round(shM3-shCTL,2)) %>% as.data.table()
      }
    } %>% mutate(Study=study, DiffMethy=direction)
    stopImplicitCluster()
    Sys.time()-t1
    dt.ratio.DMEG.subset
  }
}
saveRDS(dt.Ratio.DMEG, file="dt.Ratio.DMEG.GSE167075_Caco2_M3KD_MeRIPseq.RDS")
dt.DM.DMEG <- dt.Ratio.DMEG %>%  dplyr::filter(Diff.M3KD <= -1)
dt.DM.DMEG %>% distinct(Symbol,Study,DiffMethy) %>% dplyr::arrange(DiffMethy,Symbol)
dt.DM.DMEG %>% distinct(Symbol,Study,DiffMethy) %>% dplyr::arrange(DiffMethy,Symbol) %>%
  inner_join(x=.,y=dt.DMEG.CRC.validation %>% distinct(Symbol,Study,DiffMethy,DiffExpr,nDMEG.Study,nValidation)) %>% View()

