#load all METTL3/METTL14/FTO/ALKBH5 KD KO associated DEG from validation GEO
m6APertubation.DEG.files <- list.files(path = ".",pattern="^(dt.DEG).+(RDS)$")
m6APertubation.DEG.files <- m6APertubation.DEG.files[c(grep(m6APertubation.DEG.files,pattern="KO"), grep(m6APertubation.DEG.files,pattern="KD")) %>% unique()]
dt.DEG.m6APertubation <- foreach(f = m6APertubation.DEG.files, .combine = 'rbind')%do%{
  dt.DEG <- readRDS(file = f) %>% dplyr::filter(abs(LFC)>=0.5 & pvalue<0.05 & !is.na(padj))
  if(str_detect(f,pattern = "CT26")){#transform mouse symbol to human symbol
    dt.DEG.mapid <- mapIt(unique(dt.DEG$Symbol), org.Hs.eg.db, org.Mm.eg.db, Orthology.eg.db) %>% as.data.table(keep.rownames="inputid") %>% dplyr::filter(!is.na(Homo_symbol))
    dt.DEG <- dt.DEG %>% inner_join(x=.,y=dt.DEG.mapid,by=c("Symbol"="inputid"))
    dt.DEG <- dt.DEG %>% dplyr::filter(!is.na(Homo_symbol)) %>% dplyr::mutate(Symbol=Homo_symbol)
  }
  print(paste0(nrow(dt.DEG), " LFC>=0.5 & pvalue<0.05 DEG in ", str_replace(f,pattern="dt.DEG.",replacement = "") %>% str_replace(pattern=".RDS",replacement = "")))
  dt.DEG %>% dplyr::select(Symbol,LFC,pvalue,padj) %>% mutate(Study=str_replace(f,pattern="dt.DEG.",replacement = "") %>% str_replace(pattern=".RDS",replacement = ""))
}
#load all METTL3/METTL14/FTO/ALKBH5 KD KO associated DMG from validation GEO
m6APertubation.DMEG.DM.ratio.files  <- list.files(path=".",pattern="^(dt.Ratio.DMEG).+(MeRIPseq.RDS)$")
dt.DMG.m6APertubation <- {
  #Caco2 M3KD
  dt.DMG.Caco2.M3KD <- readRDS(m6APertubation.DMEG.DM.ratio.files[grep(m6APertubation.DMEG.DM.ratio.files,pattern="Caco2")]) %>% dplyr::filter(Diff.M3KD <= -0.5 & shCTL >= 1.5) %>%
    group_by(Symbol) %>% mutate(DiffMethyPerturbation=min(Diff.M3KD)) %>% as.data.table() %>% dplyr::distinct(Study,DiffMethy,Symbol,DiffMethyPerturbation) %>%
    mutate(Perturbation="Caco2.M3KD")
  #CT26 M3KO
  dt.DMG.CT26.M3KO <- readRDS(m6APertubation.DMEG.DM.ratio.files[grep(m6APertubation.DMEG.DM.ratio.files,pattern="CT26")]) %>% dplyr::filter(Diff.M3KO <= -0.5 & control >= 1.5) %>%
    group_by(Symbol) %>% mutate(DiffMethyPerturbation=min(Diff.M3KO)) %>% as.data.table() %>% dplyr::distinct(Study,DiffMethy,Symbol,DiffMethyPerturbation) %>%
    mutate(Perturbation="CT26.M3KO")
  #CT26 M14KO
  dt.DMG.CT26.M14KO <- readRDS(m6APertubation.DMEG.DM.ratio.files[grep(m6APertubation.DMEG.DM.ratio.files,pattern="CT26")]) %>% dplyr::filter(Diff.M14KO <= -0.5 & control >= 1.5) %>%
    group_by(Symbol) %>% mutate(DiffMethyPerturbation=min(Diff.M14KO)) %>% as.data.table() %>% dplyr::distinct(Study,DiffMethy,Symbol,DiffMethyPerturbation) %>%
    mutate(Perturbation="CT26.M14KO")
  #CRC1 FTOKD
  dt.DMG.CRC1.FTOKD <- readRDS(m6APertubation.DMEG.DM.ratio.files[grep(m6APertubation.DMEG.DM.ratio.files,pattern="FTO")]) %>% dplyr::filter(Diff.FTOKD >= 0.5 & shFTO >= 1.5) %>%
    group_by(Symbol) %>% mutate(DiffMethyPerturbation=max(Diff.FTOKD)) %>% as.data.table() %>% dplyr::distinct(Study,DiffMethy,Symbol,DiffMethyPerturbation) %>%
    mutate(Perturbation="CRC1.FTOKD")
  list(dt.DMG.Caco2.M3KD,dt.DMG.CT26.M3KO,dt.DMG.CT26.M14KO,dt.DMG.CRC1.FTOKD) %>% Reduce(x=.,rbind)
}


#incorporate the m6APerturbation DEG and DMG validation with DMEG
dt.DMEG.CRC <- readRDS("/data2/CRC_m6A/Analysis/dt.DMEG.CRC.RDS")
dt.DMEG.CRC.m6APerturbation.validation <- foreach(study=unique(dt.DMEG.CRC$Study), .combine='rbind')%do%{
  foreach(direction=unique(dt.DMEG.CRC$DiffMethy), .combine = 'rbind')%do%{
    #pull out all DMEG
    dt.DMEG.CRC.subset <- dt.DMEG.CRC %>% dplyr::filter(Study==study & DiffMethy==direction) %>% dplyr::select(Symbol,name,DiffMethy,DiffExpr,contains(study)) %>% distinct() %>%
      dplyr::arrange(Symbol) %>% dplyr::select(-name) %>% distinct()
    colnames(dt.DMEG.CRC.subset) <- colnames(dt.DMEG.CRC.subset) %>% str_replace(pattern = study, replacement = "StrictNovel")
   #add DEG validation
    dt.DEG.m6APertubation.sig <- rbind(dt.DEG.m6APertubation %>% dplyr::filter( ((str_detect(Study,"ALKBH5") | str_detect(Study,"FTO")) & LFC>0)),#hypermethy and up
                                       dt.DEG.m6APertubation %>% dplyr::filter(!str_detect(Study,"ALKBH5") & !str_detect(Study,"FTO") & LFC<0)) #hypomethy and down
    dt.DEG.m6APertubation.sig <- dt.DEG.m6APertubation.sig %>% dplyr::filter(!str_detect(Study,"GSE165115") & !str_detect(Study,"GSE186791"))#these DEG is quite limited
    dt.DEG.m6APertubation.sig <- dt.DEG.m6APertubation.sig %>% mutate(logP = -log10(pvalue), LFC.abs = abs(LFC))
    dt.DEG.m6APertubation.DMEG <- dt.DEG.m6APertubation.sig %>% dplyr::filter(Symbol %in% dt.DMEG.CRC.subset$Symbol) %>%
      group_by(Symbol) %>% mutate(nPerturbRNAseq=n_distinct(Study), PerturbRNAseq.study=paste(Study,collapse = "|"), PerturbRNAseq.logP=mean(logP), PerturbRNAseq.LFC.abs=mean(LFC.abs)) %>%
      as.data.table() %>% distinct(Symbol,nPerturbRNAseq,PerturbRNAseq.logP,PerturbRNAseq.LFC.abs,PerturbRNAseq.study)
    dt.DMEG.CRC.subset <- dt.DMEG.CRC.subset %>% left_join(x=.,y=dt.DEG.m6APertubation.DMEG,by="Symbol") %>%
      dplyr::arrange(DiffMethy, DiffExpr, Symbol, StrictNovel.exomePeak2, StrictNovel.MeTPeak,StrictNovel.MeRIPtools)
    #add DMG validation
    dt.DMG.m6APertubation.DMEG <- dt.DMG.m6APertubation %>% dplyr::filter(Perturbation != "CRC1.FTOKD") %>% dplyr::filter(Symbol %in% dt.DMEG.CRC.subset$Symbol) %>% group_by(Symbol) %>%
      mutate(nPerturbMeRIPseq=n_distinct(Perturbation), PerturbMeRIPseq.study=paste(unique(Perturbation),collapse = "|"), DiffMethyPerturb=mean(abs(DiffMethyPerturbation))) %>%
      as.data.table() %>% distinct(Symbol,nPerturbMeRIPseq,DiffMethyPerturb,PerturbMeRIPseq.study)
    dt.DMEG.CRC.subset <- dt.DMEG.CRC.subset %>% left_join(x=.,y=dt.DMG.m6APertubation.DMEG,by=c("Symbol")) %>%
      dplyr::arrange(DiffMethy, DiffExpr, Symbol, StrictNovel.exomePeak2,StrictNovel.MeTPeak,StrictNovel.MeRIPtools)
    dt.DMEG.CRC.subset <- dt.DMEG.CRC.subset %>% mutate(nPerturbRNAseq=case_when(is.na(nPerturbRNAseq) ~ 0, .default = nPerturbRNAseq),
                                                        nPerturbMeRIPseq=case_when(is.na(nPerturbMeRIPseq) ~ 0, .default = nPerturbMeRIPseq))
    dt.DMEG.CRC.subset <- dt.DMEG.CRC.subset %>% dplyr::arrange(desc(nPerturbMeRIPseq),desc(nPerturbRNAseq)) %>% mutate(Study=study,DiffMethy=direction) %>% dplyr::select(Study,DiffMethy,everything())
    #dt.DMEG.CRC.subset %>% dplyr::filter(StrictNovel.exomePeak2 & StrictNovel.MeTPeak & StrictNovel.MeRIPtools) %>% dplyr::arrange(desc(nPerturbMeRIPseq),desc(nPerturbRNAseq)) %>% View()
    print(dt.DMEG.CRC.subset %>% dplyr::filter(StrictNovel.exomePeak2 & StrictNovel.MeTPeak & StrictNovel.MeRIPtools) %>%  dplyr::filter(nPerturbRNAseq>=2 & nPerturbMeRIPseq>=2) %>%
            dplyr::select(-PerturbRNAseq.study,-PerturbMeRIPseq.study))
    dt.DMEG.CRC.subset
  }
}
dt.DMEG.CRC.m6APerturbation.validation %>% group_by(Study,DiffMethy,Symbol) %>% dplyr::filter(sum(StrictNovel.MeRIPtools==FALSE)==0 | sum(StrictNovel.MeTPeak==FALSE)==0 | sum(StrictNovel.exomePeak2==FALSE)==0) %>%
  as.data.table() %>% dplyr::arrange(DiffMethy,desc(nPerturbMeRIPseq), desc(nPerturbRNAseq),Symbol) %>% dplyr::filter(nPerturbMeRIPseq>0 & nPerturbRNAseq > 0) %>% View()
