#Venn plot display the count of strict novel DMEG in two study
StrictNovel.DMEG.list <- vector(mode="list",length=8)
names(StrictNovel.DMEG.list) <- paste0(rep(unique(dt.strict.novel.DMEG.CRC$Study), each=4), ".", rep(c("MeRIPtools","MeTPeak","exomePeak2","AllDMEG"),2))
for(study in unique(dt.strict.novel.DMEG.CRC$Study)){
  for(method in c("MeRIPtools","MeTPeak","exomePeak2","AllDMEG")){
    if(method!="AllDMEG"){
      dt.strict.novel.DMEG.CRC.subset <- dt.strict.novel.DMEG.CRC %>% dplyr::select(Study,Symbol,paste0("Novelby",method))
      colnames(dt.strict.novel.DMEG.CRC.subset)[3] <- "NovelbyMethod"
      StrictNovel.DMEG.list[[paste0(study,".",method)]] <- unique(dt.strict.novel.DMEG.CRC.subset[Study==study & NovelbyMethod==TRUE,Symbol])
    }else{
      StrictNovel.DMEG.list[[paste0(study,".",method)]] <- dt.DMEG.CRC[Study==study,unique(Symbol)]
    }

  }
}

