dt.m6a.overlap.withgene <- annot_peak(peak.bed=dt.intensity %>% dplyr::distinct(seqnames,start,end,strand) %>%
                                        mutate(name=paste(seqnames,start,end,strand,sep="_"),score=1000) %>% dplyr::select(seqnames,start,end,name,score,strand),#six column bed files
                       strand = FALSE,#must be false for MACS2 peaks
                       fract = 0.5,#50% of peaks overlapped with gene
                       feature_order=c("utr3","utr5","cds","exon","promoter","intron","intergenic"),
                       gtf="/data/m6A_calling_strategy/RIPPeakS_resource/gencode.vM33.annotation.gtf",
                       annot_type=c("gene","feature","both")[3])
