dt.m6a.overlap.withgene <- dt.m6a.overlap.withgene %>% left_join(x=.,y=dt.gene.bed %>% dplyr::select(GeneID=V4,Gene.strand=V6),by=c("OverlappedGeneIDs"="GeneID"))

dt.intensity.new <- dt.intensity %>% dplyr::left_join(x=.,y=dt.m6a.overlap.withgene %>% dplyr::select(seqnames,start,end,OverlappedGeneIDs, Gene.strand) %>% distinct(),by=c("seqnames","start","end")) %>%
  dplyr::mutate(Gene.strand=case_when(is.na(Gene.strand) ~ "*", .default = Gene.strand))
#the count of m6a overlapped with one strand, both strand, and intergenic region
dt.highratio.unstranded.m6a <- dt.intensity.new %>% group_by(Sample,name) %>% mutate(nStrand=n_distinct(Gene.strand[Gene.strand!="*"])) %>% group_by(Sample) %>%
  mutate(nPeak.total = n_distinct(name), nPeak.intergenic = n_distinct(name[nStrand==0]),
         nPeak.onestrand=n_distinct(name[nStrand==1]), nPeak.bothstrand=n_distinct(name[nStrand==2])) %>% as.data.table() %>%
  dplyr::select(Sample,contains("nPeak")) %>% distinct() %>% dplyr::arrange(Sample)
dt.highratio.unstranded.m6a
#             Sample nPeak.total nPeak.intergenic nPeak.onestrand nPeak.bothstrand
# 1:      2cell_rep1        9164             2754            5640              770
# 2:      2cell_rep2        9557             2412            6292              853
# 3:      8cell_rep1        8806              764            7106              936
# 4:      8cell_rep2        9466              710            7746             1010
# 5: Blastocyst_rep1        9135              356            7818              961
# 6: Blastocyst_rep2        7948              582            6550              816
# 7:   GVoocyte_rep1       10959             2272            7740              947
# 8:   GVoocyte_rep2       11967             2338            8538             1091
# 9:  MIIoocyte_rep1       10788             1945            7842             1001
# 10:  MIIoocyte_rep2        8971             1888            6379              704
# 11:     Zygote_rep1        6920             1783            4590              547
# 12:     Zygote_rep2       10138             2207            7029              902
dt.highratio.unstranded.m6a <- dt.highratio.unstranded.m6a %>%
  pivot_longer(cols = c("nPeak.intergenic", "nPeak.onestrand", "nPeak.bothstrand"),names_to = c("Group"), names_prefix = "nPeak.",values_to = "nPeak") %>%
  mutate(ratio = round(nPeak/nPeak.total, 3)) %>% as.data.table() %>%
  mutate(condition=strsplit(Sample,split="_rep",fixed=T) %>% sapply("[",1)) %>%
  mutate(condition=factor(condition,levels=c("GVoocyte","MIIoocyte","Zygote","2cell","8cell","Blastocyst"),labels=c("GV","MII","Zyg","2C","8C","BC"))) %>%
  dplyr::arrange(condition,Sample,Group) %>% mutate(Sample=factor(Sample,levels=unique(Sample)))
scale_factor <- 1 / max(dt.highratio.unstranded.m6a$nPeak.total)
dt.highratio.unstranded.m6a$nPeaktotal_scaled <- dt.highratio.unstranded.m6a$nPeak.total * scale_factor

p.highratio.unstranded.m6a <- dt.highratio.unstranded.m6a %>%
  mutate(Group=factor(Group, levels=c("onestrand","bothstrand","intergenic"),labels=c("one strand","both strand","intergenic"))) %>%
  ggplot(data=., aes(x=Sample))+
  geom_bar(mapping = aes(fill=Group,y=ratio,color=condition), stat = "identity", position = position_stack(), width=0.7,linewidth=0.8)+
  geom_line(aes(y=nPeaktotal_scaled, group=1), color="#b515d3",size=1)+
