dt.GSE192440.genic.shared.m6a <- foreach(con = unique(dt.GSE192440.genic.m6a$condition), .combine = 'rbind')%do%{
  x1 <- bt.intersect(a=dt.GSE192440.genic.m6a[condition==con & str_detect(Sample,"rep1"),] %>% dplyr::select(seqnames:strand),
                     b=dt.GSE192440.genic.m6a[condition==con & str_detect(Sample,"rep2"),] %>% dplyr::select(seqnames:strand),
                     s=T, e=T,f = 0.8, F=0.8) %>% as.data.table()
  x2 <- bt.intersect(a=dt.GSE192440.genic.m6a[condition==con & str_detect(Sample,"rep2"),] %>% dplyr::select(seqnames:strand),
                     b=dt.GSE192440.genic.m6a[condition==con & str_detect(Sample,"rep1"),] %>% dplyr::select(seqnames:strand),
                     s=T, e=T,f = 0.8, F=0.8) %>% as.data.table()
  inner_join(x=x1 %>% dplyr::select(seqnames=V1, start=V2, end=V3, score1=V5,strand=V6),y=x2 %>% dplyr::select(seqnames=V1, start=V2, end=V3, score2=V5,strand=V6)) %>%
    mutate(condition=con,score=(score1+score2)/2,name=paste(seqnames,start,end,strand,sep="_")) %>% dplyr::select(seqnames,start,end,name,score,strand,condition,everything())
}
