########### load HeLa m6As from alternative method combos ############
#load HeLa m6as
dt.method.parameter.combo.filtered <- readRDS("dt.method.combo.filtered.RDS")
t1<-Sys.time()
dt.Method.HeLa.m6A <- foreach(m = c("MACS2","exomePeak","exomePeak2","MeTPeak","MeRIPtools","TRESS"), .combine = 'rbind')%do%{
  if(m=="MACS2"){
    dt.combo.method <- dt.method.parameter.combo.filtered %>% dplyr::filter(Method==m)
    dt.method.m6a <- foreach(c = unique(dt.combo.method$ComboName), .combine='rbind')%do%{
      message(paste0("start load ", c, " of ", m))
      Samples <- list.files(path=paste0("/data/m6A_calling_strategy/MACS2/",c), pattern="peaks.xls",full.names = F) %>%
        str_replace(pattern="_peaks.xls",replacement = "")
      m6As <- list.files(path=paste0("/data/m6A_calling_strategy/MACS2/",c), pattern="peaks.xls",full.names = T)
      names(m6As) <- Samples
      m6As <- m6As[names(m6As) %>% grep(pattern="IVT",invert = T,value=T) %>% grep(pattern="HeLa",value=T)]
      foreach(i = 1:length(m6As),.combine='rbind')%do%{
        fread(file = m6As[i]) %>% dplyr::select(seqnames=chr,start,end,name,score=fold_enrichment) %>% mutate(strand="*") %>%
          mutate(name=paste(names(m6As)[i],"MACS2", seqnames, start, end, strand,sep="_")) %>%
          dplyr::select(seqnames,start,end,name,score,strand) %>% mutate(Sample=names(m6As)[i],ComboName=c)
      }
    } %>% mutate(Method=m)
  }else if(m=="exomePeak"){
    dt.combo.method <- dt.method.parameter.combo.filtered %>% dplyr::filter(Method==m)
    dt.method.m6a <- foreach(c = unique(dt.combo.method$ComboName), .combine='rbind')%do%{
      message(paste0("start load ", c, " of ", m))
      Samples <- list.files(path=paste0("/data/m6A_calling_strategy/exomePeak_new/",c), pattern="peak.xls",full.names = T,recursive = T) %>%
        strsplit(split="/") %>% sapply(tail,2,simplify = F) %>% sapply(head,1)
      m6As <- list.files(path=paste0("/data/m6A_calling_strategy/exomePeak_new/",c), pattern="peak.xls",full.names = T,recursive = T)
      names(m6As) <- Samples
      m6As <- m6As[names(m6As) %>% grep(pattern="IVT",invert = T,value=T) %>% grep(pattern="HeLa",value=T)]
      foreach(i = 1:length(m6As),.combine='rbind')%do%{
        fread(file = m6As[i],header = T) %>% dplyr::mutate(seqnames=chr, start=chromStart, end=chromEnd, score=fold_enrchment) %>%
          mutate(name=paste(names(m6As)[i],"exomePeak", seqnames, start, end, strand,sep="_")) %>%
          dplyr::select(seqnames,start,end,name,score,strand) %>% mutate(Sample=names(m6As)[i],ComboName=c)
      }
    } %>% mutate(Method=m)
  }else if(m=="exomePeak2"){
    dt.combo.method <- dt.method.parameter.combo.filtered %>% dplyr::filter(Method==m)
    dt.method.m6a <- foreach(c = unique(dt.combo.method$ComboName), .combine='rbind')%do%{
      message(paste0("start load ", c, " of ", m))
      Samples <- list.files(path=paste0("/data/m6A_calling_strategy/exomePeak2_new/",c), pattern="peaks.csv",full.names = T,recursive = T) %>%
        strsplit(split="/") %>% sapply(tail,2,simplify = F) %>% sapply(head,1) %>% strsplit(split="__",fixed=T) %>% sapply("[",1)
      m6As <- list.files(path=paste0("/data/m6A_calling_strategy/exomePeak2_new/",c), pattern="peaks.csv",full.names = T,recursive = T)
      names(m6As) <- Samples
      m6As <- m6As[names(m6As) %>% grep(pattern="IVT",invert = T,value=T) %>% grep(pattern="HeLa",value=T)]
      foreach(i = 1:length(m6As),.combine='rbind')%do%{
        fread(file = m6As[i],header = T) %>% dplyr::mutate(seqnames=chr, start=chromStart, end=chromEnd, score=(RPM.IP+0.5)/(RPM.input+0.5)) %>%#add pseudocount 0.1
          dplyr::filter(RPM.IP>RPM.input) %>%
          mutate(name=paste(names(m6As)[i],"exomePeak2", seqnames, start, end, strand,sep="_")) %>%
          dplyr::select(seqnames,start,end,name,score,strand) %>% mutate(Sample=names(m6As)[i],ComboName=c)
      }
    } %>% mutate(Method=m)
  }else if(m=="MeTPeak"){
    dt.combo.method <- dt.method.parameter.combo.filtered %>% dplyr::filter(Method==m)
    dt.method.m6a <- foreach(c = unique(dt.combo.method$ComboName), .combine='rbind')%do%{
      message(paste0("start load ", c, " of ", m))
      Samples <- list.files(path=paste0("/data/m6A_calling_strategy/MeTPeak_new/",c), pattern="peak.xls",full.names = T,recursive = T) %>%
        strsplit(split="/") %>% sapply(tail,2,simplify = F) %>% sapply(head,1)
      m6As <- list.files(path=paste0("/data/m6A_calling_strategy/MeTPeak_new/",c), pattern="peak.xls",full.names = T,recursive = T)
      names(m6As) <- Samples
      m6As <- m6As[names(m6As) %>% grep(pattern="IVT",invert = T,value=T) %>% grep(pattern="HeLa",value=T)]
      foreach(i = 1:length(m6As),.combine='rbind')%do%{
        fread(file = m6As[i],header = T) %>% dplyr::mutate(seqnames=chr, start=chromStart, end=chromEnd, score=fold_enrchment) %>%
          mutate(name=paste(names(m6As)[i],"MeTPeak", seqnames, start, end, strand,sep="_")) %>%
          dplyr::select(seqnames,start,end,name,score,strand) %>% mutate(Sample=names(m6As)[i],ComboName=c)
      }
    } %>% mutate(Method=m)
  }else if(m=="TRESS"){
    dt.combo.method <- dt.method.parameter.combo.filtered %>% dplyr::filter(Method==m)
    dt.method.m6a <- foreach(c = unique(dt.combo.method$ComboName), .combine='rbind')%do%{
      message(paste0("start load ", c, " of ", m))
      Samples <- list.files(path=paste0("/data/m6A_calling_strategy/TRESS_new/",c), pattern="peaks.xls",full.names = T,recursive = T) %>%
        strsplit(split="/") %>% sapply(tail,1) %>% str_replace(pattern="_peaks.xls",replacement="")
      m6As <- list.files(path=paste0("/data/m6A_calling_strategy/TRESS_new/",c), pattern="peaks.xls",full.names = T,recursive = T)
      names(m6As) <- Samples
      m6As <- m6As[names(m6As) %>% grep(pattern="IVT",invert = T,value=T) %>% grep(pattern="HeLa",value=T)]
      foreach(i = 1:length(m6As),.combine='rbind')%do%{
        fread(file = m6As[i],header = T) %>% dplyr::mutate(seqnames=chr, score=2^(as.numeric(lg.fc))) %>%
          mutate(name=paste(names(m6As)[i],"TRESS", seqnames, start, end, strand,sep="_")) %>%
          dplyr::select(seqnames,start,end,name,score,strand) %>% mutate(Sample=names(m6As)[i],ComboName=c)
      }
    } %>% mutate(Method=m)
  }else if(m=="MeRIPtools"){
    dt.combo.method <- dt.method.parameter.combo.filtered %>% dplyr::filter(Method==m)
    dt.method.m6a <- foreach(c = unique(dt.combo.method$ComboName), .combine='rbind')%do%{
      message(paste0("start load ", c, " of ", m))
      Samples <- list.files(path=paste0("/data/m6A_calling_strategy/MeRIPtools/",c), pattern="peak.tsv",full.names = T,recursive = T) %>%
        strsplit(split="/") %>% sapply(tail,1) %>% str_replace(pattern="_peak.tsv",replacement="")
      m6As <- list.files(path=paste0("/data/m6A_calling_strategy/MeRIPtools/",c), pattern="peak.tsv",full.names = T,recursive = T)
      names(m6As) <- Samples
      m6As <- m6As[names(m6As) %>% grep(pattern="IVT",invert = T,value=T) %>% grep(pattern="HeLa",value=T)]
      foreach(i = 1:length(m6As),.combine='rbind')%do%{
        fread(file = m6As[i],header = T) %>% dplyr::mutate(seqnames=chr) %>%
          mutate(name=paste(names(m6As)[i],"MeRIPtools", seqnames, start, end, strand,sep="_")) %>%
          dplyr::select(seqnames,start,end,name,score,strand) %>% mutate(Sample=names(m6As)[i],ComboName=c)
      }
    } %>% mutate(Method=m)
  }
  saveRDS(dt.method.m6a,file=paste0("/data/m6A_calling_strategy/",m, "/dt.",m, ".HeLa.m6a.RDS"))
  dt.method.m6a
}
Sys.time()-t1

